package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import com.sampleapp.data.repository.AssetRepository;
import com.sampleapp.ui.AppServices;
import javafx.application.Platform;
import javafx.beans.property.SimpleLongProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.geometry.Insets;
import javafx.scene.control.*;
import javafx.scene.layout.*;

import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

/**
 * Assets workspace with tabs for Asset Tree and Details.
 * Populates from AssetRepository data and resolves type names via ItemTypeCache.
 */
public class AssetsWorkspace extends Workspace {

    private final AppServices appServices;

    private TreeView<String> treeView;
    private TableView<AssetRepository.AssetRow> assetTable;
    private Label totalLabel;

    // Detail tab labels
    private Label detailItem, detailTypeId, detailLocation, detailQuantity,
            detailVolume, detailValue, detailCategory, detailGroup;

    // Mapping from location name to location ID for tree selection
    private final Map<String, Long> locationMap = new LinkedHashMap<>();

    public AssetsWorkspace(AppState appState, AppServices appServices) {
        super(appState);
        this.appServices = appServices;

        tabPane.getTabs().addAll(
                createAssetTreeTab(),
                createDetailsTab()
        );

        appServices.onSyncCompleted(syncType -> {
            if ("assets".equalsIgnoreCase(syncType) || "full".equalsIgnoreCase(syncType)) {
                refreshData(appState.getSelectedCharacterId());
            }
        });
    }

    @SuppressWarnings("unchecked")
    private Tab createAssetTreeTab() {
        var tab = new Tab("Asset Tree");

        var splitPane = new SplitPane();

        // Left: location tree
        treeView = new TreeView<>();
        treeView.setRoot(new TreeItem<>("All Locations"));
        treeView.getRoot().setExpanded(true);

        // When a location is selected, filter the table
        treeView.getSelectionModel().selectedItemProperty().addListener((obs, oldVal, newVal) -> {
            if (newVal != null && locationMap.containsKey(newVal.getValue())) {
                long locationId = locationMap.get(newVal.getValue());
                filterByLocation(locationId);
            }
        });

        // Right: items at selected location
        assetTable = new TableView<>();

        var nameCol = new TableColumn<AssetRepository.AssetRow, String>("Item");
        nameCol.setPrefWidth(250);
        nameCol.setCellValueFactory(cd -> {
            String name = appServices.getItemTypeCache().getName(cd.getValue().typeId())
                    .orElse("Type " + cd.getValue().typeId());
            return new SimpleStringProperty(name);
        });

        var qtyCol = new TableColumn<AssetRepository.AssetRow, Number>("Quantity");
        qtyCol.setPrefWidth(80);
        qtyCol.setCellValueFactory(cd -> new SimpleLongProperty(cd.getValue().quantity()));

        var volumeCol = new TableColumn<AssetRepository.AssetRow, String>("Volume");
        volumeCol.setPrefWidth(100);
        volumeCol.setCellValueFactory(cd -> new SimpleStringProperty("--"));

        var valueCol = new TableColumn<AssetRepository.AssetRow, String>("Est. Value");
        valueCol.setPrefWidth(120);
        valueCol.setCellValueFactory(cd -> new SimpleStringProperty("--"));

        var groupCol = new TableColumn<AssetRepository.AssetRow, String>("Group");
        groupCol.setPrefWidth(150);
        groupCol.setCellValueFactory(cd -> new SimpleStringProperty(cd.getValue().locationFlag()));

        assetTable.getColumns().addAll(nameCol, qtyCol, volumeCol, valueCol, groupCol);
        assetTable.setPlaceholder(new Label("Select a location"));

        // When an asset is selected, update details tab
        assetTable.getSelectionModel().selectedItemProperty().addListener((obs, oldVal, newVal) -> {
            if (newVal != null) {
                updateDetails(newVal);
            }
        });

        splitPane.getItems().addAll(treeView, assetTable);
        splitPane.setDividerPositions(0.35);

        // Search bar above
        var searchBox = new HBox(10);
        searchBox.setPadding(new Insets(5));
        var searchField = new TextField();
        searchField.setPromptText("Search assets...");
        searchField.setPrefWidth(300);
        var searchButton = new Button("Search");
        totalLabel = new Label("Total value: --");
        totalLabel.setStyle("-fx-text-fill: #AAAAAA;");
        var spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);
        searchBox.getChildren().addAll(searchField, searchButton, spacer, totalLabel);

        // Wire search
        searchButton.setOnAction(e -> {
            String query = searchField.getText().toLowerCase().trim();
            if (query.isEmpty()) {
                assetTable.setItems(FXCollections.observableArrayList(allAssets));
            } else {
                var filtered = allAssets.stream()
                        .filter(a -> appServices.getItemTypeCache().getName(a.typeId())
                                .orElse("").toLowerCase().contains(query))
                        .toList();
                assetTable.setItems(FXCollections.observableArrayList(filtered));
            }
        });

        var container = new VBox();
        container.getChildren().addAll(searchBox, splitPane);
        VBox.setVgrow(splitPane, Priority.ALWAYS);

        tab.setContent(container);
        return tab;
    }

    private Tab createDetailsTab() {
        var tab = new Tab("Details");
        var grid = new GridPane();
        grid.setHgap(10);
        grid.setVgap(8);
        grid.setPadding(new Insets(15));

        detailItem = createValueLabel("--");
        detailTypeId = createValueLabel("--");
        detailLocation = createValueLabel("--");
        detailQuantity = createValueLabel("--");
        detailVolume = createValueLabel("--");
        detailValue = createValueLabel("--");
        detailCategory = createValueLabel("--");
        detailGroup = createValueLabel("--");

        String[] labels = {"Item:", "Type ID:", "Location:", "Quantity:",
                "Packaged Volume:", "Estimated Value:", "Category:", "Group:"};
        Label[] values = {detailItem, detailTypeId, detailLocation, detailQuantity,
                detailVolume, detailValue, detailCategory, detailGroup};

        for (int i = 0; i < labels.length; i++) {
            var lbl = new Label(labels[i]);
            lbl.setStyle("-fx-font-weight: bold; -fx-text-fill: #AAAAAA;");
            grid.add(lbl, 0, i);
            grid.add(values[i], 1, i);
        }

        tab.setContent(new ScrollPane(grid));
        return tab;
    }

    // Full list for search/filter
    private List<AssetRepository.AssetRow> allAssets = List.of();

    private void refreshData(int characterId) {
        if (characterId <= 0) {
            treeView.getRoot().getChildren().clear();
            assetTable.setItems(FXCollections.observableArrayList());
            totalLabel.setText("Total value: --");
            allAssets = List.of();
            return;
        }

        Thread.ofVirtual().name("assets-load").start(() -> {
            try {
                var assets = appServices.getAssetRepository().findByCharacter(characterId);

                // Group by location
                Map<Long, String> locations = new LinkedHashMap<>();
                for (var asset : assets) {
                    locations.putIfAbsent(asset.locationId(),
                            "Location " + asset.locationId());
                }

                Platform.runLater(() -> {
                    allAssets = assets;
                    locationMap.clear();
                    treeView.getRoot().getChildren().clear();

                    for (var entry : locations.entrySet()) {
                        String name = entry.getValue();
                        locationMap.put(name, entry.getKey());
                        treeView.getRoot().getChildren().add(new TreeItem<>(name));
                    }

                    totalLabel.setText("Total items: " + assets.size());
                    assetTable.setItems(FXCollections.observableArrayList(assets));
                });
            } catch (Exception e) {
                log.error("Failed to load assets for character {}", characterId, e);
            }
        });
    }

    private void filterByLocation(long locationId) {
        var filtered = allAssets.stream()
                .filter(a -> a.locationId() == locationId)
                .toList();
        assetTable.setItems(FXCollections.observableArrayList(filtered));
    }

    private void updateDetails(AssetRepository.AssetRow asset) {
        String name = appServices.getItemTypeCache().getName(asset.typeId())
                .orElse("Type " + asset.typeId());
        detailItem.setText(name);
        detailTypeId.setText(String.valueOf(asset.typeId()));
        detailLocation.setText("Location " + asset.locationId());
        detailQuantity.setText(String.valueOf(asset.quantity()));
        detailVolume.setText("--");
        detailValue.setText("--");
        detailCategory.setText(asset.locationType() != null ? asset.locationType() : "--");
        detailGroup.setText(asset.locationFlag() != null ? asset.locationFlag() : "--");
    }

    private Label createValueLabel(String text) {
        var label = new Label(text);
        label.setStyle("-fx-text-fill: #CCCCCC;");
        return label;
    }

    @Override
    public String getTitle() { return "Assets"; }

    @Override
    public void onActivated() {
        log.debug("Assets workspace activated");
