190	    private void updatePriceChart(java.util.List<MarketStatistics> history) {
191	        priceChart.getData().clear();
192	        if (history.isEmpty()) return;
193	
194	        var avgSeries = new XYChart.Series<String, Number>();
195	        avgSeries.setName("Average");
196	        var lowSeries = new XYChart.Series<String, Number>();
197	        lowSeries.setName("Low");
198	        var highSeries = new XYChart.Series<String, Number>();
199	        highSeries.setName("High");
200	
201	        int count = Math.min(history.size(), 60);
202	        for (int i = count - 1; i >= 0; i--) {
203	            var stat = history.get(i);
204	            String dateStr = stat.date() != null ? stat.date().toString() : "?";
205	            double avg = (stat.open() + stat.close()) / 2.0;
206	            avgSeries.getData().add(new XYChart.Data<>(dateStr, avg));
207	            lowSeries.getData().add(new XYChart.Data<>(dateStr, stat.low()));
208	            highSeries.getData().add(new XYChart.Data<>(dateStr, stat.high()));
209	        }
210	        priceChart.getData().addAll(avgSeries, lowSeries, highSeries);
211	    }
