package com.sampleapp.ui.workspace;

import com.sampleapp.common.IskFormatter;
import com.sampleapp.core.app.AppState;
import com.sampleapp.core.app.FeatureGate;
import com.sampleapp.core.app.FeatureGate.FeatureSet;
import com.sampleapp.core.app.FeatureGate.SubscriptionTier;
import com.sampleapp.core.model.HubPrices;
import com.sampleapp.core.model.MarketOrder;
import com.sampleapp.core.model.MarketPrice;
import com.sampleapp.core.model.MarketStatistics;
import javafx.application.Platform;
import javafx.beans.property.SimpleIntegerProperty;
import javafx.beans.property.SimpleLongProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.chart.CategoryAxis;
import javafx.scene.chart.LineChart;
import javafx.scene.chart.NumberAxis;
import javafx.scene.chart.XYChart;
import javafx.scene.control.*;
import javafx.scene.layout.*;

import java.time.format.DateTimeFormatter;
import java.util.Comparator;
import java.util.LinkedHashMap;
import java.util.Map;

/**
 * Market workspace with tabs for Search, Appraisal, and Browser.
 * Appraisal multi-hub feature is gated to Professional tier.
 */
public class MarketWorkspace extends Workspace {

    private static final DateTimeFormatter DT_FMT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");

    private final FeatureGate featureGate;
    private final WorkspaceDataService dataService;

    // Search tab
    private final ObservableList<MarketPrice> searchResults = FXCollections.observableArrayList();
    private LineChart<String, Number> priceChart;

    // Appraisal tab
    private final ObservableList<HubPrices> appraisalResults = FXCollections.observableArrayList();

    // Browser tab
    private final ObservableList<MarketOrder> sellOrders = FXCollections.observableArrayList();
    private final ObservableList<MarketOrder> buyOrders = FXCollections.observableArrayList();

    public MarketWorkspace(AppState appState, FeatureGate featureGate,
                           WorkspaceDataService dataService) {
        super(appState);
        this.featureGate = featureGate;
        this.dataService = dataService;

        tabPane.getTabs().addAll(
                createSearchTab(),
                createAppraisalTab(),
                createBrowserTab()
        );
    }

    @SuppressWarnings("unchecked")
    private Tab createSearchTab() {
        var tab = new Tab("Search");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Search controls
        var searchBox = new HBox(10);
        var searchField = new TextField();
        searchField.setPromptText("Search items...");
        searchField.setPrefWidth(300);
        var regionCombo = new ComboBox<String>();
        regionCombo.getItems().addAll("The Forge", "Domain", "Sinq Laison",
                "Metropolis", "Heimatar");
        regionCombo.setValue("The Forge");
        var searchButton = new Button("Search");
        searchBox.getChildren().addAll(searchField, regionCombo, searchButton);

        // Results table
        var table = new TableView<MarketPrice>();
        var nameCol = new TableColumn<MarketPrice, String>("Item");
        nameCol.setPrefWidth(250);
        nameCol.setCellValueFactory(c -> {
            var prop = new SimpleStringProperty("Type #" + c.getValue().typeId());
            dataService.resolveTypeName(c.getValue().typeId())
                    .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
            return prop;
        });
        var buyCol = new TableColumn<MarketPrice, String>("Buy Price");
        buyCol.setPrefWidth(120);
        buyCol.setCellValueFactory(c -> new SimpleStringProperty(IskFormatter.formatRaw(c.getValue().buyPrice())));
        var sellCol = new TableColumn<MarketPrice, String>("Sell Price");
        sellCol.setPrefWidth(120);
        sellCol.setCellValueFactory(c -> new SimpleStringProperty(IskFormatter.formatRaw(c.getValue().sellPrice())));
        var volumeCol = new TableColumn<MarketPrice, String>("Hub");
        volumeCol.setPrefWidth(100);
        volumeCol.setCellValueFactory(c -> {
            var prop = new SimpleStringProperty("Hub #" + c.getValue().hubId());
            dataService.resolveLocationName(c.getValue().hubId())
                    .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
            return prop;
        });
        var spreadCol = new TableColumn<MarketPrice, String>("Spread");
        spreadCol.setPrefWidth(80);
        spreadCol.setCellValueFactory(c -> {
            double buy = c.getValue().buyPrice();
            double sell = c.getValue().sellPrice();
            double spread = sell > 0 ? ((sell - buy) / sell) * 100.0 : 0;
            return new SimpleStringProperty(String.format("%.1f%%", spread));
        });

        table.getColumns().addAll(nameCol, buyCol, sellCol, volumeCol, spreadCol);
        table.setItems(searchResults);
        table.setPlaceholder(new Label("Search for market items"));
        VBox.setVgrow(table, Priority.ALWAYS);

        // Price history chart
        var xAxis = new CategoryAxis();
        xAxis.setLabel("Date");
        var yAxis = new NumberAxis();
        yAxis.setLabel("Price (ISK)");
        priceChart = new LineChart<>(xAxis, yAxis);
        priceChart.setTitle("Price History");
        priceChart.setPrefHeight(200);
        priceChart.setCreateSymbols(false);

        searchButton.setOnAction(e -> {
            String query = searchField.getText();
            if (query == null || query.isBlank()) return;
            searchButton.setDisable(true);
            int regionId = regionNameToId(regionCombo.getValue());
            dataService.searchMarket(query, regionId)
                    .thenAccept(data -> Platform.runLater(() -> {
                        searchResults.setAll(data);
                        searchButton.setDisable(false);
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            log.error("Market search failed", ex);
                            searchButton.setDisable(false);
                        });
                        return null;
                    });
        });

        // When a search result is selected, load price history AND live orders
        table.getSelectionModel().selectedItemProperty().addListener((obs, old, sel) -> {
            if (sel == null) return;
            int regionId = regionNameToId(regionCombo.getValue());

            // Load price history
            dataService.getMarketHistory(sel.typeId(), regionId)
                    .thenAccept(history -> Platform.runLater(() -> updatePriceChart(history)))
                    .exceptionally(ex -> {
                        log.error("Failed to load price history", ex);
                        return null;
                    });

            // Also fetch live region orders and update browser tab tables
            dataService.getRegionOrders(sel.typeId(), regionId)
                    .thenAccept(orders -> Platform.runLater(() -> {
                        sellOrders.setAll(orders.stream()
                                .filter(o -> !o.isBuyOrder())
                                .sorted(java.util.Comparator.comparingDouble(MarketOrder::price))
                                .toList());
                        buyOrders.setAll(orders.stream()
                                .filter(MarketOrder::isBuyOrder)
                                .sorted(java.util.Comparator.comparingDouble(MarketOrder::price).reversed())
                                .toList());
                    }))
                    .exceptionally(ex -> {
                        log.error("Failed to load region orders for type {}", sel.typeId(), ex);
                        return null;
                    });
        });

        vbox.getChildren().addAll(searchBox, table, priceChart);
        tab.setContent(vbox);
        return tab;
    }

    @SuppressWarnings("unchecked")
    private void updatePriceChart(java.util.List<MarketStatistics> history) {
        priceChart.getData().clear();
        if (history.isEmpty()) return;

        var avgSeries = new XYChart.Series<String, Number>();
        avgSeries.setName("Average");
        var lowSeries = new XYChart.Series<String, Number>();
        lowSeries.setName("Low");
        var highSeries = new XYChart.Series<String, Number>();
        highSeries.setName("High");

        int count = Math.min(history.size(), 60);
        for (int i = count - 1; i >= 0; i--) {
            var stat = history.get(i);
            String dateStr = stat.date() != null ? stat.date().toString() : "?";
            double avg = (stat.open() + stat.close()) / 2.0;
            avgSeries.getData().add(new XYChart.Data<>(dateStr, avg));
            lowSeries.getData().add(new XYChart.Data<>(dateStr, stat.low()));
            highSeries.getData().add(new XYChart.Data<>(dateStr, stat.high()));
        }
        priceChart.getData().addAll(avgSeries, lowSeries, highSeries);
    }

    @SuppressWarnings("unchecked")
    private Tab createAppraisalTab() {
        var tab = new Tab("Appraisal");

        boolean multiHub = featureGate.isFeatureAvailable(FeatureSet.MULTI_HUB_APPRAISAL,
                SubscriptionTier.PROFESSIONAL);

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        var pasteArea = new TextArea();
        pasteArea.setPromptText("Paste items here (one per line, or EVE format)...");
        pasteArea.setPrefRowCount(8);

        var hubCombo = new ComboBox<String>();
        if (multiHub) {
            hubCombo.getItems().addAll(
                    "Jita IV - Moon 4 - Caldari Navy Assembly Plant",
                    "Amarr VIII (Oris) - Emperor Family Academy",
                    "Dodixie IX - Moon 20 - Federation Navy Assembly Plant",
                    "Rens VI - Moon 8 - Brutor Tribe Treasury",
                    "Hek VIII - Moon 12 - Boundless Creation Factory"
            );
        } else {
            hubCombo.getItems().add("Jita IV - Moon 4 - Caldari Navy Assembly Plant");
            hubCombo.setDisable(true);
        }
        hubCombo.setValue("Jita IV - Moon 4 - Caldari Navy Assembly Plant");

        var appraise = new Button("Appraise");

        if (!multiHub) {
            var lockedNote = new Label("Multi-hub appraisal requires Professional subscription");
            lockedNote.setStyle("-fx-text-fill: #888888; -fx-font-style: italic;");
            vbox.getChildren().add(lockedNote);
        }

        if (multiHub) {
            // Full multi-hub appraisal table
            var resultTable = new TableView<HubPrices>();
            var itemCol = new TableColumn<HubPrices, String>("Item");
            itemCol.setPrefWidth(200);
            itemCol.setCellValueFactory(c -> {
                var prop = new SimpleStringProperty("Type #" + c.getValue().typeId());
                dataService.resolveTypeName(c.getValue().typeId())
                        .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
                return prop;
            });
            var jitaCol = new TableColumn<HubPrices, String>("Jita");
            jitaCol.setPrefWidth(110);
            jitaCol.setCellValueFactory(c -> new SimpleStringProperty(IskFormatter.formatRaw(c.getValue().jitaSell())));
            var amarrCol = new TableColumn<HubPrices, String>("Amarr");
            amarrCol.setPrefWidth(110);
            amarrCol.setCellValueFactory(c -> new SimpleStringProperty(IskFormatter.formatRaw(c.getValue().amarrSell())));
            var dodixieCol = new TableColumn<HubPrices, String>("Dodixie");
            dodixieCol.setPrefWidth(110);
            dodixieCol.setCellValueFactory(c -> new SimpleStringProperty(IskFormatter.formatRaw(c.getValue().dodixieSell())));
            var bestCol = new TableColumn<HubPrices, String>("Best Hub");
            bestCol.setPrefWidth(120);
            bestCol.setCellValueFactory(c -> {
                var hp = c.getValue();
                double max = Math.max(hp.jitaSell(), Math.max(hp.amarrSell(), hp.dodixieSell()));
                String best = max == hp.jitaSell() ? "Jita" :
                        max == hp.amarrSell() ? "Amarr" : "Dodixie";
                return new SimpleStringProperty(best);
            });
            resultTable.getColumns().addAll(itemCol, jitaCol, amarrCol, dodixieCol, bestCol);
            resultTable.setItems(appraisalResults);
            resultTable.setPlaceholder(new Label("Paste items to appraise across hubs"));
            VBox.setVgrow(resultTable, Priority.ALWAYS);

            appraise.setOnAction(e -> {
                // Parse pasted text to type IDs (simplified)
                appraise.setDisable(true);
                appraisalResults.clear();
                // In real impl, parse item names/IDs from paste area
                appraise.setDisable(false);
            });

            vbox.getChildren().addAll(pasteArea, new HBox(10, hubCombo, appraise), resultTable);
        } else {
            // Simple single-hub appraisal
            var resultTable = new TableView<MarketPrice>();
            var itemCol = new TableColumn<MarketPrice, String>("Item");
            itemCol.setPrefWidth(250);
            itemCol.setCellValueFactory(c -> {
                var prop = new SimpleStringProperty("Type #" + c.getValue().typeId());
                dataService.resolveTypeName(c.getValue().typeId())
                        .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
                return prop;
            });
            var buyCol = new TableColumn<MarketPrice, String>("Buy");
            buyCol.setPrefWidth(120);
            buyCol.setCellValueFactory(c -> new SimpleStringProperty(IskFormatter.formatRaw(c.getValue().buyPrice())));
            var sellCol = new TableColumn<MarketPrice, String>("Sell");
            sellCol.setPrefWidth(120);
            sellCol.setCellValueFactory(c -> new SimpleStringProperty(IskFormatter.formatRaw(c.getValue().sellPrice())));
            resultTable.getColumns().addAll(itemCol, buyCol, sellCol);
            resultTable.setPlaceholder(new Label("Paste items to appraise"));
            VBox.setVgrow(resultTable, Priority.ALWAYS);

            vbox.getChildren().addAll(pasteArea, new HBox(10, hubCombo, appraise), resultTable);
        }

        tab.setContent(vbox);
        return tab;
    }

    /**
     * Represents an item in the market browser tree.
     * If {@code isType} is true, this is a selectable item type; otherwise it is a market group (folder).
     */
    private record MarketTreeItem(int id, String name, boolean isType) {
        @Override
        public String toString() {
            return name;
        }
    }

    /**
     * Represents a search result in the browser search list.
     */
    private record BrowserSearchResult(int typeId, String name) {
        @Override
        public String toString() {
            return name;
        }
    }

    /** Well-known top-level market group names with representative category IDs for fallback browsing. */
    private static final Map<String, Integer> ROOT_MARKET_GROUPS = new LinkedHashMap<>();
    static {
        ROOT_MARKET_GROUPS.put("Ships", 6);
        ROOT_MARKET_GROUPS.put("Ammunition & Charges", 8);
        ROOT_MARKET_GROUPS.put("Drones", 18);
        ROOT_MARKET_GROUPS.put("Ship Equipment", 7);
        ROOT_MARKET_GROUPS.put("Blueprints & Reactions", 9);
        ROOT_MARKET_GROUPS.put("Manufacture & Research", 4);
        ROOT_MARKET_GROUPS.put("Planetary Commodities", 43);
        ROOT_MARKET_GROUPS.put("Ship Modifications", 66);
        ROOT_MARKET_GROUPS.put("Implants & Boosters", 20);
        ROOT_MARKET_GROUPS.put("Skills", 16);
        ROOT_MARKET_GROUPS.put("Trade Goods", 17);
    }

    @SuppressWarnings("unchecked")
    private Tab createBrowserTab() {
        var tab = new Tab("Browser");

        var mainSplit = new SplitPane();

        // ---- Left pane: region selector, search, and tree ----
        var leftPane = new VBox(5);
        leftPane.setPadding(new Insets(5));

        // Region selector
        var browserRegionCombo = new ComboBox<String>();
        browserRegionCombo.getItems().addAll("The Forge", "Domain", "Sinq Laison",
                "Metropolis", "Heimatar");
        browserRegionCombo.setValue("The Forge");
        browserRegionCombo.setMaxWidth(Double.MAX_VALUE);

        // Search box
        var browserSearchField = new TextField();
        browserSearchField.setPromptText("Search items by name...");
        var browserSearchBtn = new Button("Search");
        var searchBox = new HBox(5, browserSearchField, browserSearchBtn);
        HBox.setHgrow(browserSearchField, Priority.ALWAYS);
        searchBox.setAlignment(Pos.CENTER_LEFT);

        // Search results list (hidden by default)
        var searchResultsList = new ListView<BrowserSearchResult>();
        searchResultsList.setMaxHeight(200);
        searchResultsList.setVisible(false);
        searchResultsList.setManaged(false);
        searchResultsList.setPlaceholder(new Label("No results"));

        // Market group tree
        var treeView = new TreeView<MarketTreeItem>();
        var rootItem = new TreeItem<>(new MarketTreeItem(0, "Market", false));
        rootItem.setExpanded(true);
        treeView.setRoot(rootItem);

        // Populate root groups (categories as fallback until SDE market groups are available)
        for (var entry : ROOT_MARKET_GROUPS.entrySet()) {
            var groupNode = new TreeItem<>(new MarketTreeItem(entry.getValue(), entry.getKey(), false));
            // Add a placeholder child so the expand arrow is shown
            groupNode.getChildren().add(new TreeItem<>(new MarketTreeItem(-1, "Loading...", false)));
            rootItem.getChildren().add(groupNode);
        }

        // Lazy load children when a group node is expanded
        treeView.setCellFactory(tv -> new TreeCell<>() {
            @Override
            protected void updateItem(MarketTreeItem item, boolean empty) {
                super.updateItem(item, empty);
                if (empty || item == null) {
                    setText(null);
                    setStyle("");
                } else {
                    setText(item.name());
                    if (item.isType()) {
                        setStyle("-fx-text-fill: #CCCCCC;");
                    } else {
                        setStyle("-fx-text-fill: #FFCC00; -fx-font-weight: bold;");
                    }
                }
            }
        });

        // When a group is expanded for the first time, load its child types from the type cache
        rootItem.getChildren().forEach(groupItem -> {
            groupItem.expandedProperty().addListener((obs, wasExpanded, isExpanded) -> {
                if (isExpanded && groupItem.getChildren().size() == 1
                        && groupItem.getChildren().get(0).getValue().id() == -1) {
                    // Replace placeholder with actual items
                    int categoryId = groupItem.getValue().id();
                    loadCategoryItems(groupItem, categoryId);
                }
            });
        });

        VBox.setVgrow(treeView, Priority.ALWAYS);
        leftPane.getChildren().addAll(browserRegionCombo, searchBox, searchResultsList, treeView);

        // ---- Right pane: item info header, order tables, price chart ----
        var rightPane = new VBox(5);
        rightPane.setPadding(new Insets(5));

        // Item info header
        var itemNameLabel = new Label("Select an item to view orders");
        itemNameLabel.setStyle("-fx-font-size: 14px; -fx-font-weight: bold; -fx-text-fill: #FFFFFF;");
        var itemGroupLabel = new Label("");
        itemGroupLabel.setStyle("-fx-font-size: 11px; -fx-text-fill: #888888;");
        var headerBox = new VBox(2, itemNameLabel, itemGroupLabel);
        headerBox.setPadding(new Insets(0, 0, 5, 0));

        // Loading indicator
        var loadingLabel = new Label("");
        loadingLabel.setStyle("-fx-text-fill: #AAAAAA; -fx-font-style: italic;");

        // Sell orders table
        var sellLabel = new Label("Sell Orders");
        sellLabel.setStyle("-fx-font-weight: bold; -fx-text-fill: #55FF55;");

        var sellTable = new TableView<MarketOrder>();
        var sPriceCol = new TableColumn<MarketOrder, String>("Price");
        sPriceCol.setPrefWidth(120);
        sPriceCol.setCellValueFactory(c -> new SimpleStringProperty(IskFormatter.formatRaw(c.getValue().price())));
        var sVolCol = new TableColumn<MarketOrder, Number>("Volume");
        sVolCol.setPrefWidth(80);
        sVolCol.setCellValueFactory(c -> new SimpleIntegerProperty(c.getValue().volumeRemain()));
        var sTotalCol = new TableColumn<MarketOrder, String>("Total");
        sTotalCol.setPrefWidth(120);
        sTotalCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().price() * c.getValue().volumeRemain())));
        var sLocCol = new TableColumn<MarketOrder, String>("Location");
        sLocCol.setPrefWidth(200);
        sLocCol.setCellValueFactory(c -> {
            var prop = new SimpleStringProperty("Location #" + c.getValue().locationId());
            dataService.resolveLocationName(c.getValue().locationId())
                    .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
            return prop;
        });
        var sExpCol = new TableColumn<MarketOrder, String>("Issued");
        sExpCol.setPrefWidth(100);
        sExpCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().issued() != null ? c.getValue().issued().toLocalDate().toString() : "--"));
        sellTable.getColumns().addAll(sPriceCol, sVolCol, sTotalCol, sLocCol, sExpCol);
        sellTable.setItems(sellOrders);
        sellTable.setPlaceholder(new Label("No sell orders"));

        // Buy orders table
        var buyLabel = new Label("Buy Orders");
        buyLabel.setStyle("-fx-font-weight: bold; -fx-text-fill: #5599FF;");

        var buyTable = new TableView<MarketOrder>();
        var bPriceCol = new TableColumn<MarketOrder, String>("Price");
        bPriceCol.setPrefWidth(120);
        bPriceCol.setCellValueFactory(c -> new SimpleStringProperty(IskFormatter.formatRaw(c.getValue().price())));
        var bVolCol = new TableColumn<MarketOrder, Number>("Volume");
        bVolCol.setPrefWidth(80);
        bVolCol.setCellValueFactory(c -> new SimpleIntegerProperty(c.getValue().volumeRemain()));
        var bTotalCol = new TableColumn<MarketOrder, String>("Total");
        bTotalCol.setPrefWidth(120);
        bTotalCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().price() * c.getValue().volumeRemain())));
        var bLocCol = new TableColumn<MarketOrder, String>("Location");
        bLocCol.setPrefWidth(200);
        bLocCol.setCellValueFactory(c -> {
            var prop = new SimpleStringProperty("Location #" + c.getValue().locationId());
            dataService.resolveLocationName(c.getValue().locationId())
                    .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
            return prop;
        });
        var bRangeCol = new TableColumn<MarketOrder, String>("Range");
        bRangeCol.setPrefWidth(80);
        bRangeCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().duration() + "d"));
        buyTable.getColumns().addAll(bPriceCol, bVolCol, bTotalCol, bLocCol, bRangeCol);
        buyTable.setItems(buyOrders);
        buyTable.setPlaceholder(new Label("No buy orders"));

        // Price history chart for browser
        var bxAxis = new CategoryAxis();
        bxAxis.setLabel("Date");
        var byAxis = new NumberAxis();
        byAxis.setLabel("Price (ISK)");
        var browserPriceChart = new LineChart<>(bxAxis, byAxis);
        browserPriceChart.setTitle("Price History");
        browserPriceChart.setPrefHeight(180);
        browserPriceChart.setCreateSymbols(false);
        browserPriceChart.setLegendVisible(true);

        VBox.setVgrow(sellTable, Priority.ALWAYS);
        VBox.setVgrow(buyTable, Priority.ALWAYS);
        rightPane.getChildren().addAll(
                headerBox, loadingLabel,
                sellLabel, sellTable,
                buyLabel, buyTable,
                browserPriceChart
        );

        // ---- Wire item selection to order fetching ----
        Runnable clearOrders = () -> {
            sellOrders.clear();
            buyOrders.clear();
            browserPriceChart.getData().clear();
            loadingLabel.setText("");
        };

        // Load orders for a given type
        java.util.function.BiConsumer<Integer, String> loadOrdersForType = (typeId, typeName) -> {
            int regionId = regionNameToId(browserRegionCombo.getValue());
            itemNameLabel.setText(typeName);
            itemGroupLabel.setText("Type ID: " + typeId + " | Region: " + browserRegionCombo.getValue());
            loadingLabel.setText("Loading orders...");
            clearOrders.run();
            loadingLabel.setText("Loading orders...");

            dataService.getRegionOrders(typeId, regionId)
                    .thenAccept(orders -> Platform.runLater(() -> {
                        sellOrders.setAll(orders.stream()
                                .filter(o -> !o.isBuyOrder())
                                .sorted(Comparator.comparingDouble(MarketOrder::price))
                                .toList());
                        buyOrders.setAll(orders.stream()
                                .filter(MarketOrder::isBuyOrder)
                                .sorted(Comparator.comparingDouble(MarketOrder::price).reversed())
                                .toList());
                        loadingLabel.setText(sellOrders.size() + " sell, " + buyOrders.size() + " buy orders");
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            log.error("Failed to load orders for type {}", typeId, ex);
                            loadingLabel.setText("Failed to load orders");
                        });
                        return null;
                    });

            // Also load price history
            dataService.getMarketHistory(typeId, regionId)
                    .thenAccept(history -> Platform.runLater(() -> {
                        browserPriceChart.getData().clear();
                        if (history.isEmpty()) return;
                        updateBrowserPriceChart(browserPriceChart, history);
                    }))
                    .exceptionally(ex -> {
                        log.error("Failed to load price history for type {}", typeId, ex);
                        return null;
                    });
        };

        // Tree selection listener
        treeView.getSelectionModel().selectedItemProperty().addListener((obs, old, sel) -> {
            if (sel == null || sel.getValue() == null) return;
            var item = sel.getValue();
            if (item.isType()) {
                // Hide search results when tree item selected
                searchResultsList.setVisible(false);
                searchResultsList.setManaged(false);
                loadOrdersForType.accept(item.id(), item.name());
            }
        });

        // Search functionality
        Runnable doSearch = () -> {
            String query = browserSearchField.getText();
            if (query == null || query.length() < 2) return;
            browserSearchBtn.setDisable(true);
            int regionId = regionNameToId(browserRegionCombo.getValue());

            dataService.searchMarket(query, regionId)
                    .thenAccept(results -> Platform.runLater(() -> {
                        searchResultsList.getItems().clear();
                        for (var mp : results) {
                            // Resolve names asynchronously; for now use type ID
                            int typeId = mp.typeId();
                            var result = new BrowserSearchResult(typeId, "Type #" + typeId);
                            searchResultsList.getItems().add(result);
                            dataService.resolveTypeName(typeId)
                                    .thenAccept(name -> Platform.runLater(() -> {
                                        // Update the item in the list
                                        int idx = searchResultsList.getItems().indexOf(result);
                                        if (idx >= 0) {
                                            searchResultsList.getItems().set(idx,
                                                    new BrowserSearchResult(typeId, name));
                                        }
                                    }));
                        }
                        searchResultsList.setVisible(true);
                        searchResultsList.setManaged(true);
                        browserSearchBtn.setDisable(false);
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            log.error("Browser search failed", ex);
                            browserSearchBtn.setDisable(false);
                        });
                        return null;
                    });
        };

        browserSearchBtn.setOnAction(e -> doSearch.run());
        browserSearchField.setOnAction(e -> doSearch.run());

        // Search result selection
        searchResultsList.getSelectionModel().selectedItemProperty().addListener((obs, old, sel) -> {
            if (sel == null) return;
            treeView.getSelectionModel().clearSelection();
            loadOrdersForType.accept(sel.typeId(), sel.name());
        });

        // When region changes, reload orders for currently selected item
        browserRegionCombo.valueProperty().addListener((obs, old, newRegion) -> {
            if (newRegion == null) return;
            // Check tree selection first
            var treeSelected = treeView.getSelectionModel().getSelectedItem();
            if (treeSelected != null && treeSelected.getValue() != null && treeSelected.getValue().isType()) {
                loadOrdersForType.accept(treeSelected.getValue().id(), treeSelected.getValue().name());
            } else {
                // Check search selection
                var searchSelected = searchResultsList.getSelectionModel().getSelectedItem();
                if (searchSelected != null) {
                    loadOrdersForType.accept(searchSelected.typeId(), searchSelected.name());
                }
            }
        });

        mainSplit.getItems().addAll(leftPane, rightPane);
        mainSplit.setDividerPositions(0.28);
        registerSplitPane("browser-split", mainSplit);

        tab.setContent(mainSplit);
        return tab;
    }

    /**
     * Loads item types for a category and adds them as children of the given tree node.
     * Currently the SDE market group hierarchy is not yet imported, so tree groups show
     * a hint to use the search box instead. Once the SdeMarketGroups table is populated
     * by the SDE import task, this method can be enhanced to load child groups and types
     * from the database.
     */
    private void loadCategoryItems(TreeItem<MarketTreeItem> parentNode, int categoryId) {
        Platform.runLater(() -> {
            parentNode.getChildren().clear();
            parentNode.getChildren().add(new TreeItem<>(
                    new MarketTreeItem(-1, "(Use search above to find items)", false)));
        });
    }

    @SuppressWarnings("unchecked")
    private void updateBrowserPriceChart(LineChart<String, Number> chart,
                                          java.util.List<MarketStatistics> history) {
        var avgSeries = new XYChart.Series<String, Number>();
        avgSeries.setName("Average");
        var lowSeries = new XYChart.Series<String, Number>();
        lowSeries.setName("Low");
        var highSeries = new XYChart.Series<String, Number>();
        highSeries.setName("High");

        int count = Math.min(history.size(), 60);
        for (int i = count - 1; i >= 0; i--) {
            var stat = history.get(i);
            String dateStr = stat.date() != null ? stat.date().toString() : "?";
            double avg = (stat.open() + stat.close()) / 2.0;
            avgSeries.getData().add(new XYChart.Data<>(dateStr, avg));
            lowSeries.getData().add(new XYChart.Data<>(dateStr, stat.low()));
            highSeries.getData().add(new XYChart.Data<>(dateStr, stat.high()));
        }
        chart.getData().addAll(avgSeries, lowSeries, highSeries);
    }

    private static int regionNameToId(String name) {
        return switch (name) {
            case "The Forge" -> 10000002;
            case "Domain" -> 10000043;
            case "Sinq Laison" -> 10000032;
            case "Metropolis" -> 10000042;
            case "Heimatar" -> 10000030;
            default -> 10000002;
        };
    }

    @Override
    public String getTitle() { return "Market"; }

    @Override
    public void onActivated() { log.debug("Market workspace activated"); }

    @Override
    public void onCharacterChanged(int characterId) {
        log.debug("Market: character changed to {}", characterId);
        // Market workspace is largely search-driven, not character-specific
        // Clear results on character change for clean state
        if (characterId <= 0) {
            searchResults.clear();
            sellOrders.clear();
            buyOrders.clear();
            priceChart.getData().clear();
        }
    }
}

