440	    private void loadCorpOffers(int corporationId, boolean forceRefresh) {
441	        if (!forceRefresh) {
442	            List<LoyaltyOffer> cached = corpOffersCache.get(corporationId);
443	            if (cached != null) {
444	                Platform.runLater(() -> corpOffersList.setAll(cached));
445	                return;
446	            }
447	        }
448	
449	        Thread.ofVirtual().name("lp-store-load-offers-" + corporationId).start(() -> {
450	            try {
451	                List<LoyaltyOffer> offers = dataService.getLpStoreOffers(corporationId).join();
452	                corpOffersCache.put(corporationId, offers);
453	
454	                // Pre-resolve type names for offers
455	                for (LoyaltyOffer offer : offers) {
456	                    resolveAndCacheTypeName(offer.typeId());
457	                    if (offer.requiredItems() != null) {
458	                        for (var req : offer.requiredItems()) {
459	                            resolveAndCacheTypeName(req.typeId());
460	                        }
461	                    }
462	                }
463	
464	                Platform.runLater(() -> {
465	                    corpOffersList.setAll(offers);
466	                    updateStoreEntryOfferCount(corporationId, offers.size());
467	                });
468	            } catch (Exception ex) {
469	                log.error("Failed to load LP store offers for corp {}", corporationId, ex);
470	            }
471	        });
472	    }
