474	    private void resolveAndCacheTypeName(int typeId) {
475	        if (resolvedTypeNames.containsKey(typeId)) return;
476	        try {
477	            String name = dataService.resolveTypeName(typeId).join();
478	            resolvedTypeNames.put(typeId, name);
479	        } catch (Exception ex) {
480	            log.debug("Failed to resolve type name for {}", typeId, ex);
481	        }
482	    }
