508	    private void updateStoreEntryOfferCount(int corporationId, int count) {
509	        for (int i = 0; i < storesList.size(); i++) {
510	            CorpStoreEntry entry = storesList.get(i);
511	            if (entry.corporationId == corporationId && entry.offersCount != count) {
512	                storesList.set(i, new CorpStoreEntry(
513	                        entry.corporationId, entry.corporationName, entry.faction,
514	                        count, entry.totalLp));
515	                break;
516	            }
517	        }
518	    }
