598	
599	    private String formatRequiredItemsPlaceholder(List<LoyaltyOfferRequirement> reqs) {
600	        if (reqs == null || reqs.isEmpty()) return "None";
601	        var sb = new StringBuilder();
602	        for (var req : reqs) {
603	            if (!sb.isEmpty()) sb.append(", ");
604	            String name = resolvedTypeNames.get(req.typeId());
605	            if (name != null) {
606	                sb.append(req.quantity()).append("x ").append(name);
607	            } else {
608	                sb.append(req.quantity()).append("x Type#").append(req.typeId());
609	            }
610	        }
611	        return sb.toString();
612	    }
613	
614	    private String formatRequiredItemsResolved(List<LoyaltyOfferRequirement> reqs) {
615	        if (reqs == null || reqs.isEmpty()) return "None";
616	        var sb = new StringBuilder();
617	        for (var req : reqs) {
618	            if (!sb.isEmpty()) sb.append(", ");
619	            String name = resolvedTypeNames.getOrDefault(req.typeId(), "Type#" + req.typeId());
620	            sb.append(req.quantity()).append("x ").append(name);
621	        }
622	        return sb.toString();
623	    }
624	
625	    private void resolveRequiredItems(List<LoyaltyOfferRequirement> reqs, SimpleStringProperty prop) {
626	        boolean anyUnresolved = reqs.stream()
627	                .anyMatch(r -> !resolvedTypeNames.containsKey(r.typeId()));
628	        if (!anyUnresolved) return;
629	
630	        Thread.ofVirtual().name("lp-store-resolve-reqs").start(() -> {
631	            for (var req : reqs) {
632	                resolveAndCacheTypeName(req.typeId());
633	            }
634	            String resolved = formatRequiredItemsResolved(reqs);
635	            Platform.runLater(() -> prop.set(resolved));
636	        });
637	    }
