647	    private static String getFactionForCorp(int corporationId) {
648	        // Map corps to their faction by ID range / known associations
649	        if (corporationId >= 1000035 && corporationId <= 1000052) return "Caldari State";
650	        if (corporationId >= 1000080 && corporationId <= 1000085) return "Amarr Empire";
651	        if (corporationId >= 1000119 && corporationId <= 1000132) return "Gallente Federation";
652	        if (corporationId >= 1000168 && corporationId <= 1000182) return "Minmatar Republic";
653	        if (corporationId >= 1000160 && corporationId <= 1000164) return "CONCORD";
654	        if (corporationId == 1000060) return "Gallente Federation";
655	        return "--";
656	    }
