676	    @Override
677	    public void onCharacterChanged(int characterId) {
678	        log.debug("LP Store: character changed to {}", characterId);
679	        if (characterId <= 0) {
680	            Platform.runLater(() -> {
681	                storesList.clear();
682	                corpOffersList.clear();
683	                allItemsList.clear();
684	                itemProvidersList.clear();
685	                corpNameLabel.setText("Select a corporation");
686	                corpImageView.setImage(null);
687	                itemNameLabel.setText("Select an item");
688	                itemImageView.setImage(null);
689	                lastUpdatedLabel.setText("Last Updated: --");
690	                cacheExpiresLabel.setText("Cache Expires: --");
691	            });
692	            lpBalances.clear();
693	            corpOffersCache.clear();
694	            return;
695	        }
696	
697	        Thread.ofVirtual().name("lp-store-load-balances").start(() -> {
698	            try {
699	                List<LoyaltyPoints> points = dataService.getLoyaltyPoints(characterId).join();
700	                lpBalances.clear();
701	                for (var lp : points) {
702	                    lpBalances.put(lp.corporationId(), lp.loyaltyPoints());
703	                }
704	
705	                // Build stores list entries sorted by LP descending
706	                List<CorpStoreEntry> entries = new ArrayList<>();
707	                for (var lp : points) {
708	                    int corpId = lp.corporationId();
709	                    String name = resolveCorpName(corpId);
710	                    String faction = getFactionForCorp(corpId);
711	                    int cachedCount = corpOffersCache.containsKey(corpId)
712	                            ? corpOffersCache.get(corpId).size() : 0;
713	                    entries.add(new CorpStoreEntry(corpId, name, faction, cachedCount, lp.loyaltyPoints()));
714	                }
715	                entries.sort(Comparator.comparingInt((CorpStoreEntry e) -> e.totalLp).reversed());
716	
717	                Platform.runLater(() -> storesList.setAll(entries));
718	
719	                // Start loading all corp offers in the background
720	                loadAllCorpOffers();
721	            } catch (Exception ex) {
722	                log.error("Failed to load loyalty points for character {}", characterId, ex);
723	            }
724	        });
725	    }
726	
727	    // ========================================================================
728	    // Internal Data Models
729	    // ========================================================================
730	
731	    /**
732	     * Row entry for the stores table showing a corporation with LP.
733	     */
734	    private record CorpStoreEntry(
735	            int corporationId,
736	            String corporationName,
737	            String faction,
738	            int offersCount,
739	            int totalLp
740	    ) {}
741	
742	    /**
743	     * Row entry for the all-items table showing an item across all LP stores.
744	     */
