package com.sampleapp.ui.workspace;

import com.sampleapp.common.IskFormatter;
import com.sampleapp.core.app.AppState;
import com.sampleapp.core.model.LoyaltyOffer;
import com.sampleapp.core.model.LoyaltyOfferRequirement;
import com.sampleapp.core.model.LoyaltyPoints;
import javafx.application.Platform;
import javafx.beans.property.SimpleIntegerProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.collections.transformation.FilteredList;
import javafx.collections.transformation.SortedList;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.control.*;
import javafx.scene.image.Image;
import javafx.scene.image.ImageView;
import javafx.scene.layout.*;

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

/**
 * LP Store browser workspace for browsing loyalty point store offers.
 * Features two tabs: LP Stores (browse by corporation) and Item Search (browse by item).
 */
public class LpStoreWorkspace extends Workspace {

    private static final DateTimeFormatter DT_FMT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");

    // Well-known NPC corporation ID → name mapping
    private static final Map<Integer, String> CORP_NAMES = Map.ofEntries(
            Map.entry(1000035, "Caldari Navy"),
            Map.entry(1000120, "Federation Navy"),
            Map.entry(1000080, "Imperial Navy"),
            Map.entry(1000180, "Republic Fleet"),
            Map.entry(1000130, "Sisters of EVE"),
            Map.entry(1000170, "Thukker Tribe"),
            Map.entry(1000060, "CreoDron"),
            Map.entry(1000047, "Lai Dai Corporation"),
            Map.entry(1000049, "Kaalakiota Corporation"),
            Map.entry(1000041, "Ishukone Corporation"),
            Map.entry(1000125, "Servant Sisters of EVE"),
            Map.entry(1000084, "Amarr Navy"),
            Map.entry(1000179, "Republic Justice Department"),
            Map.entry(1000181, "Republic Parliament"),
            Map.entry(1000182, "Republic Security Services"),
            Map.entry(1000036, "Caldari State"),
            Map.entry(1000046, "Hyasyoda Corporation"),
            Map.entry(1000048, "CBD Corporation"),
            Map.entry(1000050, "Wiyrkomi Corporation"),
            Map.entry(1000051, "Sukuuvestaa Corporation"),
            Map.entry(1000052, "Nugoeihuvi Corporation"),
            Map.entry(1000081, "Amarr Empire"),
            Map.entry(1000082, "Ministry of War"),
            Map.entry(1000083, "Emperor Family"),
            Map.entry(1000085, "Theology Council"),
            Map.entry(1000119, "Gallente Federation"),
            Map.entry(1000121, "Federal Intelligence Office"),
            Map.entry(1000122, "Federal Defense Union"),
            Map.entry(1000123, "Federal Freight"),
            Map.entry(1000124, "Poteque Pharmaceuticals"),
            Map.entry(1000131, "Intaki Commerce"),
            Map.entry(1000132, "Duvolle Laboratories"),
            Map.entry(1000168, "Brutor Tribe"),
            Map.entry(1000169, "Sebiestor Tribe"),
            Map.entry(1000171, "Minmatar Republic"),
            Map.entry(1000172, "Tribal Liberation Force"),
            Map.entry(1000161, "Concord"),
            Map.entry(1000162, "DED"),
            Map.entry(1000163, "Inner Circle"),
            Map.entry(1000164, "CONCORD Assembly")
    );

    private final WorkspaceDataService dataService;

    // LP Stores tab state
    private final ObservableList<CorpStoreEntry> storesList = FXCollections.observableArrayList();
    private final ObservableList<LoyaltyOffer> corpOffersList = FXCollections.observableArrayList();
    private Label lastUpdatedLabel;
    private Label cacheExpiresLabel;
    private Label corpNameLabel;
    private ImageView corpImageView;
    private TextField storesSearchField;

    // Item Search tab state
    private final ObservableList<AllItemEntry> allItemsList = FXCollections.observableArrayList();
    private final ObservableList<ItemProviderEntry> itemProvidersList = FXCollections.observableArrayList();
    private Label itemNameLabel;
    private ImageView itemImageView;
    private TextField itemSearchField;

    // Shared state
    private final Map<Integer, Integer> lpBalances = new ConcurrentHashMap<>();
    private final Map<Integer, List<LoyaltyOffer>> corpOffersCache = new ConcurrentHashMap<>();
    private final Map<Integer, String> resolvedTypeNames = new ConcurrentHashMap<>();

    public LpStoreWorkspace(AppState appState, WorkspaceDataService dataService) {
        super(appState);
        this.dataService = dataService;

        tabPane.getTabs().addAll(createLpStoresTab(), createItemSearchTab());
    }

    // ========================================================================
    // LP Stores Tab
    // ========================================================================

    @SuppressWarnings("unchecked")
    private Tab createLpStoresTab() {
        var tab = new Tab("LP Stores");

        var root = new VBox(8);
        root.setPadding(new Insets(10));

        // --- Header section ---
        var titleLabel = new Label("Loyalty Point Store Browser");
        titleLabel.setStyle("-fx-font-size: 18; -fx-font-weight: bold;");

        lastUpdatedLabel = new Label("Last Updated: --");
        lastUpdatedLabel.setStyle("-fx-text-fill: #888;");
        cacheExpiresLabel = new Label("Cache Expires: --");
        cacheExpiresLabel.setStyle("-fx-text-fill: #888;");

        var updateStoresBtn = new Button("Update LP Stores");
        updateStoresBtn.setOnAction(e -> refreshStoresData());

        var headerRight = new HBox(12, lastUpdatedLabel, cacheExpiresLabel, updateStoresBtn);
        headerRight.setAlignment(Pos.CENTER_RIGHT);
        HBox.setHgrow(headerRight, Priority.ALWAYS);

        var headerBox = new HBox(12, titleLabel, headerRight);
        headerBox.setAlignment(Pos.CENTER_LEFT);

        // --- Search ---
        storesSearchField = new TextField();
        storesSearchField.setPromptText("Search stores and offers...");
        storesSearchField.setPrefWidth(300);

        // --- Stores table (upper) ---
        var storesFiltered = new FilteredList<>(storesList, p -> true);
        storesSearchField.textProperty().addListener((obs, old, val) -> {
            String filter = val != null ? val.toLowerCase().trim() : "";
            storesFiltered.setPredicate(entry -> {
                if (filter.isEmpty()) return true;
                return entry.corporationName.toLowerCase().contains(filter);
            });
        });

        var storesSorted = new SortedList<>(storesFiltered);
        var storesTable = new TableView<CorpStoreEntry>();
        storesSorted.comparatorProperty().bind(storesTable.comparatorProperty());
        storesTable.setItems(storesSorted);
        storesTable.setPlaceholder(new Label("No LP stores loaded. Select a character."));

        var corpCol = new TableColumn<CorpStoreEntry, String>("Corporation");
        corpCol.setPrefWidth(220);
        corpCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().corporationName));

        var factionCol = new TableColumn<CorpStoreEntry, String>("Faction");
        factionCol.setPrefWidth(150);
        factionCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().faction));

        var offersCountCol = new TableColumn<CorpStoreEntry, Number>("Offers");
        offersCountCol.setPrefWidth(80);
        offersCountCol.setCellValueFactory(c -> new SimpleIntegerProperty(c.getValue().offersCount));

        var totalLpCol = new TableColumn<CorpStoreEntry, String>("Total LP Holdings");
        totalLpCol.setPrefWidth(140);
        totalLpCol.setCellValueFactory(c -> new SimpleStringProperty(
                String.format("%,d LP", c.getValue().totalLp)));

        storesTable.getColumns().addAll(corpCol, factionCol, offersCountCol, totalLpCol);

        // Default sort: LP descending
        totalLpCol.setSortType(TableColumn.SortType.DESCENDING);
        storesTable.getSortOrder().add(totalLpCol);

        // --- Offers section (lower) ---
        var offersHeader = new HBox(10);
        offersHeader.setAlignment(Pos.CENTER_LEFT);
        offersHeader.setPadding(new Insets(4, 0, 4, 0));

        corpImageView = new ImageView();
        corpImageView.setFitWidth(64);
        corpImageView.setFitHeight(64);
        corpImageView.setPreserveRatio(true);

        corpNameLabel = new Label("Select a corporation");
        corpNameLabel.setStyle("-fx-font-size: 16; -fx-font-weight: bold;");

        var updateOffersBtn = new Button("Update LP Offers");
        updateOffersBtn.setOnAction(e -> {
            var selected = storesTable.getSelectionModel().getSelectedItem();
            if (selected != null) {
                loadCorpOffers(selected.corporationId, true);
            }
        });

        var offersHeaderSpacer = new Region();
        HBox.setHgrow(offersHeaderSpacer, Priority.ALWAYS);
        offersHeader.getChildren().addAll(corpImageView, corpNameLabel, offersHeaderSpacer, updateOffersBtn);

        var offersFiltered = new FilteredList<>(corpOffersList, p -> true);
        storesSearchField.textProperty().addListener((obs, old, val) -> {
            String filter = val != null ? val.toLowerCase().trim() : "";
            offersFiltered.setPredicate(offer -> {
                if (filter.isEmpty()) return true;
                String resolved = resolvedTypeNames.get(offer.typeId());
                if (resolved != null && resolved.toLowerCase().contains(filter)) return true;
                return String.valueOf(offer.typeId()).contains(filter);
            });
        });

        var offersTable = new TableView<LoyaltyOffer>();
        offersTable.setItems(offersFiltered);
        offersTable.setPlaceholder(new Label("Select a corporation to view offers"));

        var oItemCol = new TableColumn<LoyaltyOffer, String>("Item");
        oItemCol.setPrefWidth(250);
        oItemCol.setCellValueFactory(c -> {
            int typeId = c.getValue().typeId();
            String cached = resolvedTypeNames.get(typeId);
            var prop = new SimpleStringProperty(cached != null ? cached : "Type #" + typeId);
            if (cached == null) {
                dataService.resolveTypeName(typeId).thenAccept(name -> {
                    resolvedTypeNames.put(typeId, name);
                    Platform.runLater(() -> prop.set(name));
                });
            }
            return prop;
        });

        var oQtyCol = new TableColumn<LoyaltyOffer, Number>("Quantity");
        oQtyCol.setPrefWidth(70);
        oQtyCol.setCellValueFactory(c -> new SimpleIntegerProperty(c.getValue().quantity()));

        var oLpCol = new TableColumn<LoyaltyOffer, String>("LP Cost");
        oLpCol.setPrefWidth(90);
        oLpCol.setCellValueFactory(c -> new SimpleStringProperty(
                String.format("%,d", c.getValue().lpCost())));

        var oIskCol = new TableColumn<LoyaltyOffer, String>("ISK Cost");
        oIskCol.setPrefWidth(130);
        oIskCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().iskCost())));

        var oReqCol = new TableColumn<LoyaltyOffer, String>("Required Items");
        oReqCol.setPrefWidth(280);
        oReqCol.setCellValueFactory(c -> {
            var reqs = c.getValue().requiredItems();
            if (reqs == null || reqs.isEmpty()) return new SimpleStringProperty("None");
            var prop = new SimpleStringProperty(formatRequiredItemsPlaceholder(reqs));
            resolveRequiredItems(reqs, prop);
            return prop;
        });

        offersTable.getColumns().addAll(oItemCol, oQtyCol, oLpCol, oIskCol, oReqCol);

        // --- Selection listener on stores table ---
        storesTable.getSelectionModel().selectedItemProperty().addListener((obs, old, selected) -> {
            if (selected == null) {
                corpOffersList.clear();
                corpNameLabel.setText("Select a corporation");
                corpImageView.setImage(null);
                return;
            }
            corpNameLabel.setText(selected.corporationName);
            loadCorpImage(selected.corporationId);
            loadCorpOffers(selected.corporationId, false);
        });

        // --- Layout with SplitPane ---
        var storesBox = new VBox(4, storesTable);
        VBox.setVgrow(storesTable, Priority.ALWAYS);

        var offersBox = new VBox(4, offersHeader, offersTable);
        VBox.setVgrow(offersTable, Priority.ALWAYS);

        var splitPane = new SplitPane(storesBox, offersBox);
        splitPane.setOrientation(javafx.geometry.Orientation.VERTICAL);
        splitPane.setDividerPositions(0.4);
        VBox.setVgrow(splitPane, Priority.ALWAYS);

        root.getChildren().addAll(headerBox, storesSearchField, splitPane);
        tab.setContent(root);
        return tab;
    }

    // ========================================================================
    // Item Search Tab
    // ========================================================================

    @SuppressWarnings("unchecked")
    private Tab createItemSearchTab() {
        var tab = new Tab("Item Search");

        var root = new VBox(8);
        root.setPadding(new Insets(10));

        // --- Search ---
        itemSearchField = new TextField();
        itemSearchField.setPromptText("Search items...");
        itemSearchField.setPrefWidth(300);

        // --- All items table (upper) ---
        var itemsFiltered = new FilteredList<>(allItemsList, p -> true);
        itemSearchField.textProperty().addListener((obs, old, val) -> {
            String filter = val != null ? val.toLowerCase().trim() : "";
            itemsFiltered.setPredicate(entry -> {
                if (filter.isEmpty()) return true;
                return entry.itemName.toLowerCase().contains(filter);
            });
        });

        var itemsSorted = new SortedList<>(itemsFiltered);
        var itemsTable = new TableView<AllItemEntry>();
        itemsSorted.comparatorProperty().bind(itemsTable.comparatorProperty());
        itemsTable.setItems(itemsSorted);
        itemsTable.setPlaceholder(new Label("No items loaded. Select a character with LP."));

        var iItemCol = new TableColumn<AllItemEntry, String>("Item");
        iItemCol.setPrefWidth(220);
        iItemCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().itemName));

        var iQtyCol = new TableColumn<AllItemEntry, Number>("Quantity");
        iQtyCol.setPrefWidth(70);
        iQtyCol.setCellValueFactory(c -> new SimpleIntegerProperty(c.getValue().quantity));

        var iGroupCol = new TableColumn<AllItemEntry, String>("Group");
        iGroupCol.setPrefWidth(130);
        iGroupCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().group));

        var iCatCol = new TableColumn<AllItemEntry, String>("Category");
        iCatCol.setPrefWidth(110);
        iCatCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().category));

        var iLpCol = new TableColumn<AllItemEntry, String>("LP Cost");
        iLpCol.setPrefWidth(90);
        iLpCol.setCellValueFactory(c -> new SimpleStringProperty(
                String.format("%,d", c.getValue().lpCost)));

        var iIskCol = new TableColumn<AllItemEntry, String>("ISK Cost");
        iIskCol.setPrefWidth(130);
        iIskCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().iskCost)));

        var iReqCol = new TableColumn<AllItemEntry, String>("Required Items");
        iReqCol.setPrefWidth(260);
        iReqCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().requiredItemsText));

        itemsTable.getColumns().addAll(iItemCol, iQtyCol, iGroupCol, iCatCol, iLpCol, iIskCol, iReqCol);

        // Default sort: item name ascending
        iItemCol.setSortType(TableColumn.SortType.ASCENDING);
        itemsTable.getSortOrder().add(iItemCol);

        // --- Item providers section (lower) ---
        var providersHeader = new HBox(10);
        providersHeader.setAlignment(Pos.CENTER_LEFT);
        providersHeader.setPadding(new Insets(4, 0, 4, 0));

        itemImageView = new ImageView();
        itemImageView.setFitWidth(64);
        itemImageView.setFitHeight(64);
        itemImageView.setPreserveRatio(true);

        itemNameLabel = new Label("Select an item");
        itemNameLabel.setStyle("-fx-font-size: 16; -fx-font-weight: bold;");
        providersHeader.getChildren().addAll(itemImageView, itemNameLabel);

        var providersTable = new TableView<ItemProviderEntry>();
        providersTable.setItems(FXCollections.observableList(itemProvidersList));
        providersTable.setPlaceholder(new Label("Select an item to view providers"));

        var pCorpCol = new TableColumn<ItemProviderEntry, String>("Corporation");
        pCorpCol.setPrefWidth(220);
        pCorpCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().corporationName));

        var pFactionCol = new TableColumn<ItemProviderEntry, String>("Faction");
        pFactionCol.setPrefWidth(150);
        pFactionCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().faction));

        var pLpCol = new TableColumn<ItemProviderEntry, String>("My Total LP Holdings");
        pLpCol.setPrefWidth(150);
        pLpCol.setCellValueFactory(c -> new SimpleStringProperty(
                String.format("%,d LP", c.getValue().myTotalLp)));

        providersTable.getColumns().addAll(pCorpCol, pFactionCol, pLpCol);

        // --- Selection listener on items table ---
        itemsTable.getSelectionModel().selectedItemProperty().addListener((obs, old, selected) -> {
            if (selected == null) {
                itemProvidersList.clear();
                itemNameLabel.setText("Select an item");
                itemImageView.setImage(null);
                return;
            }
            itemNameLabel.setText(selected.itemName);
            loadItemImage(selected.typeId);
            populateItemProviders(selected.typeId);
        });

        // --- Layout with SplitPane ---
        var itemsBox = new VBox(4, itemsTable);
        VBox.setVgrow(itemsTable, Priority.ALWAYS);

        var providersBox = new VBox(4, providersHeader, providersTable);
        VBox.setVgrow(providersTable, Priority.ALWAYS);

        var splitPane = new SplitPane(itemsBox, providersBox);
        splitPane.setOrientation(javafx.geometry.Orientation.VERTICAL);
        splitPane.setDividerPositions(0.55);
        VBox.setVgrow(splitPane, Priority.ALWAYS);

        root.getChildren().addAll(itemSearchField, splitPane);
        tab.setContent(root);
        return tab;
    }

    // ========================================================================
    // Data Loading
    // ========================================================================

    private void refreshStoresData() {
        int charId = appState.getSelectedCharacterId();
        if (charId <= 0) {
            log.warn("Cannot refresh LP stores: no character selected");
            return;
        }
        lpBalances.clear();
        corpOffersCache.clear();
        onCharacterChanged(charId);
    }

    private void loadCorpOffers(int corporationId, boolean forceRefresh) {
        if (!forceRefresh) {
            List<LoyaltyOffer> cached = corpOffersCache.get(corporationId);
            if (cached != null) {
                Platform.runLater(() -> corpOffersList.setAll(cached));
                return;
            }
        }

        Thread.ofVirtual().name("lp-store-load-offers-" + corporationId).start(() -> {
            try {
                List<LoyaltyOffer> offers = dataService.getLpStoreOffers(corporationId).join();
                corpOffersCache.put(corporationId, offers);

                // Pre-resolve type names for offers
                for (LoyaltyOffer offer : offers) {
                    resolveAndCacheTypeName(offer.typeId());
                    if (offer.requiredItems() != null) {
                        for (var req : offer.requiredItems()) {
                            resolveAndCacheTypeName(req.typeId());
                        }
                    }
                }

                Platform.runLater(() -> {
                    corpOffersList.setAll(offers);
                    updateStoreEntryOfferCount(corporationId, offers.size());
                });
            } catch (Exception ex) {
                log.error("Failed to load LP store offers for corp {}", corporationId, ex);
            }
        });
    }

    private void resolveAndCacheTypeName(int typeId) {
        if (resolvedTypeNames.containsKey(typeId)) return;
        try {
            String name = dataService.resolveTypeName(typeId).join();
            resolvedTypeNames.put(typeId, name);
        } catch (Exception ex) {
            log.debug("Failed to resolve type name for {}", typeId, ex);
        }
    }

    private void loadCorpImage(int corporationId) {
        String url = "https://images.evetech.net/corporations/" + corporationId + "/logo?size=128";
        Thread.ofVirtual().name("lp-store-corp-image-" + corporationId).start(() -> {
            try {
                var image = new Image(url, 64, 64, true, true, true);
                Platform.runLater(() -> corpImageView.setImage(image));
            } catch (Exception ex) {
                log.debug("Failed to load corporation image for {}", corporationId, ex);
            }
        });
    }

    private void loadItemImage(int typeId) {
        String url = "https://images.evetech.net/types/" + typeId + "/icon?size=64";
        Thread.ofVirtual().name("lp-store-item-image-" + typeId).start(() -> {
            try {
                var image = new Image(url, 64, 64, true, true, true);
                Platform.runLater(() -> itemImageView.setImage(image));
            } catch (Exception ex) {
                log.debug("Failed to load item image for type {}", typeId, ex);
            }
        });
    }

    private void updateStoreEntryOfferCount(int corporationId, int count) {
        for (int i = 0; i < storesList.size(); i++) {
            CorpStoreEntry entry = storesList.get(i);
            if (entry.corporationId == corporationId && entry.offersCount != count) {
                storesList.set(i, new CorpStoreEntry(
                        entry.corporationId, entry.corporationName, entry.faction,
                        count, entry.totalLp));
                break;
            }
        }
    }

    private void populateItemProviders(int typeId) {
        itemProvidersList.clear();
        for (var corpEntry : corpOffersCache.entrySet()) {
            int corpId = corpEntry.getKey();
            boolean provides = corpEntry.getValue().stream()
                    .anyMatch(o -> o.typeId() == typeId);
            if (provides) {
                int lp = lpBalances.getOrDefault(corpId, 0);
                itemProvidersList.add(new ItemProviderEntry(
                        resolveCorpName(corpId),
                        getFactionForCorp(corpId),
                        lp));
            }
        }
    }

    private void buildAllItemsList() {
        Map<Integer, AllItemEntry> itemMap = new LinkedHashMap<>();

        for (var corpEntry : corpOffersCache.entrySet()) {
            for (LoyaltyOffer offer : corpEntry.getValue()) {
                int typeId = offer.typeId();
                if (!itemMap.containsKey(typeId)) {
                    String itemName = resolvedTypeNames.getOrDefault(typeId, "Type #" + typeId);
                    String reqText = formatRequiredItemsResolved(offer.requiredItems());
                    itemMap.put(typeId, new AllItemEntry(
                            typeId, itemName, offer.quantity(), "--", "--",
                            offer.lpCost(), offer.iskCost(), reqText));
                }
            }
        }

        Platform.runLater(() -> {
            allItemsList.setAll(itemMap.values());
        });
    }

    private void loadAllCorpOffers() {
        List<Integer> corpIds = new ArrayList<>(lpBalances.keySet());
        if (corpIds.isEmpty()) return;

        Thread.ofVirtual().name("lp-store-load-all-offers").start(() -> {
            for (int corpId : corpIds) {
                try {
                    List<LoyaltyOffer> offers = dataService.getLpStoreOffers(corpId).join();
                    corpOffersCache.put(corpId, offers);

                    // Pre-resolve type names
                    for (LoyaltyOffer offer : offers) {
                        resolveAndCacheTypeName(offer.typeId());
                        if (offer.requiredItems() != null) {
                            for (var req : offer.requiredItems()) {
                                resolveAndCacheTypeName(req.typeId());
                            }
                        }
                    }

                    final int count = offers.size();
                    Platform.runLater(() -> updateStoreEntryOfferCount(corpId, count));
                } catch (Exception ex) {
                    log.error("Failed to load LP store offers for corp {}", corpId, ex);
                }
            }

            // After all loaded, build the all-items list for Item Search tab
            buildAllItemsList();

            Platform.runLater(() -> {
                lastUpdatedLabel.setText("Last Updated: " + LocalDateTime.now().format(DT_FMT));
                cacheExpiresLabel.setText("Cache Expires: " +
                        LocalDateTime.now().plusHours(1).format(DT_FMT));
            });
        });
    }

    // ========================================================================
    // Required Items Formatting
    // ========================================================================

    private String formatRequiredItemsPlaceholder(List<LoyaltyOfferRequirement> reqs) {
        if (reqs == null || reqs.isEmpty()) return "None";
        var sb = new StringBuilder();
        for (var req : reqs) {
            if (!sb.isEmpty()) sb.append(", ");
            String name = resolvedTypeNames.get(req.typeId());
            if (name != null) {
                sb.append(req.quantity()).append("x ").append(name);
            } else {
                sb.append(req.quantity()).append("x Type#").append(req.typeId());
            }
        }
        return sb.toString();
    }

    private String formatRequiredItemsResolved(List<LoyaltyOfferRequirement> reqs) {
        if (reqs == null || reqs.isEmpty()) return "None";
        var sb = new StringBuilder();
        for (var req : reqs) {
            if (!sb.isEmpty()) sb.append(", ");
            String name = resolvedTypeNames.getOrDefault(req.typeId(), "Type#" + req.typeId());
            sb.append(req.quantity()).append("x ").append(name);
        }
        return sb.toString();
    }

    private void resolveRequiredItems(List<LoyaltyOfferRequirement> reqs, SimpleStringProperty prop) {
        boolean anyUnresolved = reqs.stream()
                .anyMatch(r -> !resolvedTypeNames.containsKey(r.typeId()));
        if (!anyUnresolved) return;

        Thread.ofVirtual().name("lp-store-resolve-reqs").start(() -> {
            for (var req : reqs) {
                resolveAndCacheTypeName(req.typeId());
            }
            String resolved = formatRequiredItemsResolved(reqs);
            Platform.runLater(() -> prop.set(resolved));
        });
    }

    // ========================================================================
    // Corporation Name / Faction Resolution
    // ========================================================================

    static String resolveCorpName(int corporationId) {
        return CORP_NAMES.getOrDefault(corporationId, "Corporation #" + corporationId);
    }

    private static String getFactionForCorp(int corporationId) {
        // Map corps to their faction by ID range / known associations
        if (corporationId >= 1000035 && corporationId <= 1000052) return "Caldari State";
        if (corporationId >= 1000080 && corporationId <= 1000085) return "Amarr Empire";
        if (corporationId >= 1000119 && corporationId <= 1000132) return "Gallente Federation";
        if (corporationId >= 1000168 && corporationId <= 1000182) return "Minmatar Republic";
        if (corporationId >= 1000160 && corporationId <= 1000164) return "CONCORD";
        if (corporationId == 1000060) return "Gallente Federation";
        return "--";
    }

    // ========================================================================
    // Workspace Lifecycle
    // ========================================================================

    @Override
    public String getTitle() {
        return "LP Store";
    }

    @Override
    public void onActivated() {
        log.debug("LP Store workspace activated");
        int charId = appState.getSelectedCharacterId();
        if (charId > 0 && lpBalances.isEmpty()) {
            onCharacterChanged(charId);
        }
    }

    @Override
    public void onCharacterChanged(int characterId) {
        log.debug("LP Store: character changed to {}", characterId);
        if (characterId <= 0) {
            Platform.runLater(() -> {
                storesList.clear();
                corpOffersList.clear();
                allItemsList.clear();
                itemProvidersList.clear();
                corpNameLabel.setText("Select a corporation");
                corpImageView.setImage(null);
                itemNameLabel.setText("Select an item");
                itemImageView.setImage(null);
                lastUpdatedLabel.setText("Last Updated: --");
                cacheExpiresLabel.setText("Cache Expires: --");
            });
            lpBalances.clear();
            corpOffersCache.clear();
            return;
        }

        Thread.ofVirtual().name("lp-store-load-balances").start(() -> {
            try {
                List<LoyaltyPoints> points = dataService.getLoyaltyPoints(characterId).join();
                lpBalances.clear();
                for (var lp : points) {
                    lpBalances.put(lp.corporationId(), lp.loyaltyPoints());
                }

                // Build stores list entries sorted by LP descending
                List<CorpStoreEntry> entries = new ArrayList<>();
                for (var lp : points) {
                    int corpId = lp.corporationId();
                    String name = resolveCorpName(corpId);
                    String faction = getFactionForCorp(corpId);
                    int cachedCount = corpOffersCache.containsKey(corpId)
                            ? corpOffersCache.get(corpId).size() : 0;
                    entries.add(new CorpStoreEntry(corpId, name, faction, cachedCount, lp.loyaltyPoints()));
                }
                entries.sort(Comparator.comparingInt((CorpStoreEntry e) -> e.totalLp).reversed());

                Platform.runLater(() -> storesList.setAll(entries));

                // Start loading all corp offers in the background
                loadAllCorpOffers();
            } catch (Exception ex) {
                log.error("Failed to load loyalty points for character {}", characterId, ex);
            }
        });
    }

    // ========================================================================
    // Internal Data Models
    // ========================================================================

    /**
     * Row entry for the stores table showing a corporation with LP.
     */
    private record CorpStoreEntry(
            int corporationId,
            String corporationName,
            String faction,
            int offersCount,
            int totalLp
    ) {}

    /**
     * Row entry for the all-items table showing an item across all LP stores.
     */
    private record AllItemEntry(
            int typeId,
            String itemName,
            int quantity,
            String group,
            String category,
            int lpCost,
            double iskCost,
            String requiredItemsText
    ) {}

    /**
     * Row entry for the item providers table showing which corps offer an item.
     */
    private record ItemProviderEntry(
            String corporationName,
            String faction,
            int myTotalLp
    ) {}
}

