1	package com.sampleapp.app.service;
2	import com.sampleapp.core.service.EventBus;
3	
4	import com.sampleapp.core.subscription.FeatureGate;
5	import com.sampleapp.core.subscription.FeatureSet;
6	import com.sampleapp.data.repository.CharacterRepository;
7	import com.google.inject.Inject;
8	import com.google.inject.Singleton;
9	import org.slf4j.Logger;
10	import org.slf4j.LoggerFactory;
11	
12	import java.util.List;
13	import java.util.concurrent.Executors;
14	import java.util.concurrent.ScheduledExecutorService;
15	import java.util.concurrent.ScheduledFuture;
16	import java.util.concurrent.TimeUnit;
17	
18	/**
19	 * Background ESI data polling service with configurable scheduling.
20	 * <p>
21	 * Periodically syncs all registered characters via {@link BusinessLogic#syncCharacter(int)}.
22	 * Mirrors the C# hourly timer from {@code BusinessEvents.StartClocks()}.
23	 */
24	@Singleton
25	public class SyncService {
26	
27	    private static final Logger log = LoggerFactory.getLogger(SyncService.class);
28	
29	    private final BusinessLogic businessLogic;
30	    private final CharacterRepository characterRepo;
31	    private final FeatureGate featureGate;
32	    private final EventBus eventBus;
33	    private final ScheduledExecutorService scheduler;
34	
35	    private volatile boolean running = false;
36	    private ScheduledFuture<?> scheduledTask;
37	
38	    @Inject
39	    public SyncService(BusinessLogic businessLogic,
40	                       CharacterRepository characterRepo,
41	                       FeatureGate featureGate,
42	                       EventBus eventBus) {
43	        this.businessLogic = businessLogic;
44	        this.characterRepo = characterRepo;
45	        this.featureGate = featureGate;
46	        this.eventBus = eventBus;
47	        this.scheduler = Executors.newSingleThreadScheduledExecutor(r -> {
48	            Thread t = new Thread(r, "esi-sync-scheduler");
49	            t.setDaemon(true);
50	            return t;
51	        });
52	    }
53	
54	    /**
55	     * Start periodic ESI sync for all registered characters.
56	     *
57	     * @param intervalMinutes interval between sync cycles in minutes
58	     */
59	    public void start(int intervalMinutes) {
60	        if (running) {
61	            log.warn("SyncService is already running");
62	            return;
63	        }
64	
65	        if (!featureGate.hasFeature(FeatureSet.ESI_SYNC)) {
66	            log.info("ESI sync feature not enabled -- SyncService will not start");
67	            return;
68	        }
69	
70	        running = true;
71	        log.info("Starting ESI sync service with {}min interval", intervalMinutes);
72	
73	        // Initial sync after 1 minute, then every intervalMinutes
74	        scheduledTask = scheduler.scheduleAtFixedRate(
75	                this::syncAll,
76	                1,
77	                intervalMinutes,
78	                TimeUnit.MINUTES
79	        );
80	    }
81	
82	    /**
83	     * Stop the periodic sync.
84	     */
85	    public void stop() {
86	        if (!running) {
87	            return;
88	        }
89	
90	        running = false;
91	        if (scheduledTask != null) {
92	            scheduledTask.cancel(false);
93	            scheduledTask = null;
94	        }
95	        log.info("ESI sync service stopped");
96	    }
97	
98	    /**
99	     * Whether the sync service is currently running.
100	     */
101	    public boolean isRunning() {
102	        return running;
103	    }
104	
105	    /**
106	     * Sync all registered characters. Called by the scheduler.
107	     */
108	    private void syncAll() {
109	        if (!running) {
110	            return;
111	        }
112	
113	        try {
114	            List<CharacterRepository.CharacterRow> characters = characterRepo.findAll();
115	            if (characters.isEmpty()) {
116	                log.debug("No characters registered -- skipping sync cycle");
117	                return;
118	            }
119	
120	            log.info("Starting ESI sync cycle for {} characters", characters.size());
121	            eventBus.publish(EventBus.Event.ESI_SYNC_STARTED);
122	
123	            for (var character : characters) {
124	                if (!running) {
125	                    log.info("Sync interrupted -- service stopped");
126	                    return;
127	                }
128	
129	                try {
130	                    businessLogic.syncCharacter(character.characterId()).join();
131	                } catch (Exception e) {
132	                    log.error("Failed to sync character {} ({})",
133	                            character.name(), character.characterId(), e);
134	                }
135	            }
136	
137	            eventBus.publish(EventBus.Event.ESI_SYNC_COMPLETED);
138	            log.info("ESI sync cycle completed for {} characters", characters.size());
139	        } catch (Exception e) {
140	            log.error("Unexpected error during sync cycle", e);
141	            eventBus.publish(EventBus.Event.ESI_SYNC_FAILED);
142	        }
143	    }
144	
145	    /**
146	     * Shut down the scheduler thread pool. Call on application exit.
147	     */
148	    public void shutdown() {
149	        stop();
150	        scheduler.shutdownNow();
151	    }
152	}
