312	                if (rens.isPresent()) {
313	                    rensBuy = rens.get().buyPrice();
314	                    rensSell = rens.get().sellPrice();
315	                }
316	
317	                results.add(new HubPrices(
318	                        typeId,
319	                        jitaBuy, jitaSell,
320	                        amarrBuy, amarrSell,
321	                        dodixieBuy, dodixieSell,
