334	    @Override
335	    public CompletableFuture<List<TradeOpportunity>> scanStationTrades(long stationId, double minProfit, int minVolume) {
336	        return CompletableFuture.supplyAsync(() -> {
337	            log.debug("scanStationTrades for station {} minProfit={} minVolume={}", stationId, minProfit, minVolume);
338	            try {
339	                int regionId = stationToRegion(stationId);
340	                log.info("Fetching region orders for region {} (station {})...", regionId, stationId);
341	
342	                // Fetch ALL orders in the region from ESI (paginated)
343	                List<RegionOrder> allOrders = esiClient.market.getRegionOrders(regionId).join();
344	                log.info("Fetched {} total region orders, filtering to station {}", allOrders.size(), stationId);
345	
346	                // Filter to orders at this station only
347	                List<RegionOrder> stationOrders = allOrders.stream()
348	                        .filter(o -> o.locationId() == stationId)
349	                        .toList();
350	
351	                // Group by typeId
352	                Map<Integer, List<RegionOrder>> byType = stationOrders.stream()
353	                        .collect(Collectors.groupingBy(RegionOrder::typeId));
354	
355	                List<TradeOpportunity> opportunities = new ArrayList<>();
356	                for (var entry : byType.entrySet()) {
357	                    int typeId = entry.getKey();
358	                    var orders = entry.getValue();
359	
360	                    // Find best buy (highest buy order) and best sell (lowest sell order)
361	                    OptionalDouble bestBuy = orders.stream()
362	                            .filter(RegionOrder::isBuyOrder)
363	                            .mapToDouble(RegionOrder::price)
364	                            .max();
365	                    OptionalDouble bestSell = orders.stream()
366	                            .filter(o -> !o.isBuyOrder())
367	                            .mapToDouble(RegionOrder::price)
368	                            .min();
369	
370	                    if (bestBuy.isEmpty() || bestSell.isEmpty()) continue;
371	
372	                    double buyPrice = bestBuy.getAsDouble();
373	                    double sellPrice = bestSell.getAsDouble();
374	                    double profit = sellPrice - buyPrice;
375	                    double margin = sellPrice > 0 ? profit / sellPrice : 0;
376	
377	                    if (profit < minProfit) continue;
378	                    if (margin <= 0) continue;
379	
380	                    // Count total sell volume for this type
381	                    long sellVolume = orders.stream()
382	                            .filter(o -> !o.isBuyOrder())
383	                            .mapToLong(RegionOrder::volumeRemain)
384	                            .sum();
385	
386	                    // Count number of sell orders (competition)
387	                    long orderCount = orders.stream()
388	                            .filter(o -> !o.isBuyOrder())
389	                            .count();
390	
391	                    String typeName = typeCacheRepo.findNameById(typeId).orElse("Type #" + typeId);
392	
393	                    opportunities.add(new TradeOpportunity(
394	                            typeId, typeName, buyPrice, sellPrice, margin,
395	                            orderCount, (double) sellVolume
396	                    ));
397	                }
398	
399	                // Cache the prices we found for future use
400	                for (var opp : opportunities) {
401	                    stationPriceRepo.upsert(opp.typeId(), stationId, opp.buyPrice(), opp.sellPrice());
402	                }
403	
404	                opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
405	                log.info("Found {} station trade opportunities", opportunities.size());
406	                return opportunities;
407	            } catch (Exception e) {
408	                log.error("Failed to scan station trades for station {}", stationId, e);
409	                return List.of();
410	            }
411	        });
412	    }
