414	    @Override
415	    public CompletableFuture<List<TradeOpportunity>> scanRegionalTrades(int fromRegionId, int toRegionId,
416	                                                                        double minMargin, double maxCargo, double budget) {
417	        return CompletableFuture.supplyAsync(() -> {
418	            log.debug("scanRegionalTrades from {} to {} minMargin={} maxCargo={} budget={}",
419	                    fromRegionId, toRegionId, minMargin, maxCargo, budget);
420	            try {
421	                log.info("Fetching region orders for regions {} and {}...", fromRegionId, toRegionId);
422	
423	                // Fetch orders from both regions in parallel
424	                var fromOrdersFuture = esiClient.market.getRegionOrders(fromRegionId);
425	                var toOrdersFuture = esiClient.market.getRegionOrders(toRegionId);
426	
427	                List<RegionOrder> fromOrders = fromOrdersFuture.join();
428	                List<RegionOrder> toOrders = toOrdersFuture.join();
429	                log.info("Fetched {} orders from source region, {} from destination region",
430	                        fromOrders.size(), toOrders.size());
431	
432	                // Build price maps: for source, find lowest sell price per type
433	                Map<Integer, Double> sourceSellPrices = new HashMap<>();
434	                Map<Integer, Long> sourceVolumes = new HashMap<>();
435	                for (var order : fromOrders) {
436	                    if (order.isBuyOrder()) continue; // skip buy orders
437	                    sourceSellPrices.merge(order.typeId(), order.price(), Math::min);
438	                    sourceVolumes.merge(order.typeId(), (long) order.volumeRemain(), Long::sum);
439	                }
440	
441	                // For destination, find lowest sell price (what we undercut)
442	                Map<Integer, Double> destSellPrices = new HashMap<>();
443	                for (var order : toOrders) {
444	                    if (order.isBuyOrder()) continue;
445	                    destSellPrices.merge(order.typeId(), order.price(), Math::min);
446	                }
447	
448	                List<TradeOpportunity> opportunities = new ArrayList<>();
449	                for (var entry : sourceSellPrices.entrySet()) {
450	                    int typeId = entry.getKey();
451	                    double buyCost = entry.getValue();
452	                    Double sellRevenue = destSellPrices.get(typeId);
453	
454	                    if (sellRevenue == null || buyCost <= 0 || sellRevenue <= 0) continue;
455	
456	                    double margin = (sellRevenue - buyCost) / sellRevenue;
457	                    if (margin < minMargin) continue;
458	
459	                    // Check cargo volume constraint
460	                    var typeInfo = typeCacheRepo.findById(typeId);
461	                    if (typeInfo.isPresent() && maxCargo > 0) {
462	                        double vol = typeInfo.get().packagedVolume() > 0
463	                                ? typeInfo.get().packagedVolume()
464	                                : typeInfo.get().volume();
465	                        if (vol > maxCargo) continue;
466	                    }
467	
468	                    // Check budget constraint
469	                    if (budget > 0 && buyCost > budget) continue;
470	
471	                    long volume = sourceVolumes.getOrDefault(typeId, 0L);
472	                    String typeName = typeCacheRepo.findNameById(typeId).orElse("Type #" + typeId);
473	
474	                    opportunities.add(new TradeOpportunity(
475	                            typeId, typeName, buyCost, sellRevenue, margin,
476	                            volume, (double) volume
477	                    ));
478	                }
479	
480	                opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
481	                log.info("Found {} regional trade opportunities", opportunities.size());
482	                return opportunities;
483	            } catch (Exception e) {
484	                log.error("Failed to scan regional trades from {} to {}", fromRegionId, toRegionId, e);
485	                return List.of();
486	            }
487	        });
488	    }
