565	    public CompletableFuture<List<FleetMemberInfo>> getFleetMembers(int characterId) {
566	        return CompletableFuture.supplyAsync(() -> {
567	            log.debug("getFleetMembers for character {}", characterId);
568	            try {
569	                String token = tokenManager.getValidToken(characterId).join();
570	                // First get the character's fleet ID
571	                var fleetInfoResp = esiClient.fleets.getCharacterFleet(characterId, token).join();
572	                if (!fleetInfoResp.isSuccess() || fleetInfoResp.data() == null) {
573	                    return List.<FleetMemberInfo>of();
574	                }
575	                long fleetId = fleetInfoResp.data().fleetId();
576	
577	                // Get fleet members
578	                var membersResp = esiClient.fleets.getFleetMembers(fleetId, token).join();
579	                if (!membersResp.isSuccess() || membersResp.data() == null) {
580	                    return List.<FleetMemberInfo>of();
581	                }
582	
583	                // Get fleet wings for wing/squad names
584	                var wingsResp = esiClient.fleets.getFleetWings(fleetId, token).join();
585	                Map<Long, String> wingNames = new HashMap<>();
586	                Map<Long, String> squadNames = new HashMap<>();
587	                if (wingsResp.isSuccess() && wingsResp.data() != null) {
588	                    for (var wing : wingsResp.data()) {
589	                        wingNames.put(wing.id(), wing.name());
590	                        if (wing.squads() != null) {
591	                            for (var squad : wing.squads()) {
592	                                squadNames.put(squad.id(), squad.name());
593	                            }
594	                        }
595	                    }
596	                }
597	
598	                // Resolve character names via universe names
599	                List<Integer> charIds = membersResp.data().stream()
600	                        .map(com.sampleapp.esi.dto.FleetMember::characterId)
601	                        .toList();
602	                Map<Integer, String> charNames = new HashMap<>();
