604	                    try {
605	                        var namesResp = esiClient.universe.getNames(charIds).join();
606	                        if (namesResp.isSuccess() && namesResp.data() != null) {
607	                            for (var name : namesResp.data()) {
608	                                charNames.put(name.id(), name.name());
609	                            }
610	                        }
611	                    } catch (Exception e) {
612	                        log.warn("Failed to resolve fleet member names", e);
613	                    }
614	                }
615	
616	                return membersResp.data().stream()
617	                        .map(m -> new FleetMemberInfo(
618	                                m.characterId(),
619	                                charNames.getOrDefault(m.characterId(), "Character #" + m.characterId()),
620	                                "", // ship name not available from ESI fleet members
621	                                "Ship Type #" + m.shipTypeId(),
622	                                "System #" + m.solarSystemId(),
623	                                m.role() != null ? m.role() : "--",
624	                                squadNames.getOrDefault(m.squadId(), "Squad #" + m.squadId()),
625	                                wingNames.getOrDefault(m.wingId(), "Wing #" + m.wingId())
626	                        ))
627	                        .toList();
628	            } catch (Exception e) {
629	                log.error("Failed to load fleet members for character {}", characterId, e);
630	                return List.of();
631	            }
632	        });
