package com.sampleapp.app.service;

import com.sampleapp.common.Constants;
import com.sampleapp.core.model.*;
import com.sampleapp.data.StationStatsDatabase;
import com.sampleapp.data.repository.*;
import com.sampleapp.esi.EsiClient;
import com.sampleapp.esi.TokenManager;
import com.sampleapp.ui.workspace.WorkspaceDataService;
import com.google.inject.Inject;
import jakarta.inject.Singleton;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import com.sampleapp.esi.dto.RegionOrder;

import java.time.LocalDate;
import java.time.LocalDateTime;
import java.util.*;
import java.util.concurrent.CompletableFuture;
import java.util.stream.Collectors;

/**
 * Full implementation of {@link WorkspaceDataService}.
 * Delegates to repositories for local data and to the ESI client for live market data.
 */
@Singleton
public class WorkspaceDataServiceImpl implements WorkspaceDataService {

    private static final Logger log = LoggerFactory.getLogger(WorkspaceDataServiceImpl.class);

    private final BusinessLogic businessLogic;
    private final EsiClient esiClient;
    private final TokenManager tokenManager;
    private final MarketOrderRepository marketOrderRepo;
    private final MarketTransactionRepository marketTransactionRepo;
    private final WalletRepository walletRepo;
    private final AssetRepository assetRepo;
    private final BlueprintRepository blueprintRepo;
    private final IndustryJobRepository industryJobRepo;
    private final ContractRepository contractRepo;
    private final LoyaltyRepository loyaltyRepo;
    private final StationPriceRepository stationPriceRepo;
    private final MarketStatisticsRepository marketStatisticsRepo;
    private final TypeCacheRepository typeCacheRepo;
    private final StationStatsDatabase stationStatsDb;
    private final ProfitTrackerLogic profitTrackerLogic;

    @Inject
    public WorkspaceDataServiceImpl(BusinessLogic businessLogic,
                                    EsiClient esiClient,
                                    TokenManager tokenManager,
                                    MarketOrderRepository marketOrderRepo,
                                    MarketTransactionRepository marketTransactionRepo,
                                    WalletRepository walletRepo,
                                    AssetRepository assetRepo,
                                    BlueprintRepository blueprintRepo,
                                    IndustryJobRepository industryJobRepo,
                                    ContractRepository contractRepo,
                                    LoyaltyRepository loyaltyRepo,
                                    StationPriceRepository stationPriceRepo,
                                    MarketStatisticsRepository marketStatisticsRepo,
                                    TypeCacheRepository typeCacheRepo,
                                    StationStatsDatabase stationStatsDb,
                                    ProfitTrackerLogic profitTrackerLogic) {
        this.businessLogic = businessLogic;
        this.esiClient = esiClient;
        this.tokenManager = tokenManager;
        this.marketOrderRepo = marketOrderRepo;
        this.marketTransactionRepo = marketTransactionRepo;
        this.walletRepo = walletRepo;
        this.assetRepo = assetRepo;
        this.blueprintRepo = blueprintRepo;
        this.industryJobRepo = industryJobRepo;
        this.contractRepo = contractRepo;
        this.loyaltyRepo = loyaltyRepo;
        this.stationPriceRepo = stationPriceRepo;
        this.marketStatisticsRepo = marketStatisticsRepo;
        this.typeCacheRepo = typeCacheRepo;
        this.stationStatsDb = stationStatsDb;
        this.profitTrackerLogic = profitTrackerLogic;
    }

    // ================================================================
    // Industry
    // ================================================================

    @Override
    public CompletableFuture<List<IndustryJob>> getIndustryJobs(int characterId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getIndustryJobs for character {}", characterId);
            List<IndustryJobRepository.IndustryJobRow> rows = industryJobRepo.findByCharacter(characterId);
            return rows.stream()
                    .map(r -> new IndustryJob(
                            r.jobId(),
                            r.activityId(),
                            r.blueprintTypeId(),
                            r.runs(),
                            r.duration(),
                            r.status(),
                            r.startDate(),
                            r.endDate(),
                            r.cost(),
                            r.facilityId() != null ? r.facilityId() : 0L,
                            r.productTypeId() != null ? r.productTypeId() : 0
                    ))
                    .toList();
        });
    }

    @Override
    public CompletableFuture<List<BlueprintModel>> getBlueprints(int characterId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getBlueprints for character {}", characterId);
            List<BlueprintRepository.BlueprintRow> rows = blueprintRepo.findByCharacter(characterId);
            return rows.stream()
                    .map(r -> new BlueprintModel(
                            r.itemId(),
                            r.typeId(),
                            r.locationId(),
                            r.runs(),
                            r.materialEfficiency(),
                            r.timeEfficiency(),
                            r.isCopy()
                    ))
                    .toList();
        });
    }

    @Override
    public CompletableFuture<List<MiningLedger>> getMiningLedger(int characterId, LocalDate from, LocalDate to) {
        log.debug("getMiningLedger stub for character {} (no mining repo yet)", characterId);
        return CompletableFuture.completedFuture(List.of());
    }

    @Override
    public CompletableFuture<List<TypeMaterial>> getBlueprintMaterials(int blueprintTypeId) {
        log.debug("getBlueprintMaterials stub for blueprint {} (not yet implemented)", blueprintTypeId);
        return CompletableFuture.completedFuture(List.of());
    }

    // ================================================================
    // Accounting / Wallet
    // ================================================================

    @Override
    public CompletableFuture<List<JournalEntry>> getJournalEntries(int characterId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getJournalEntries for character {}", characterId);
            List<WalletRepository.WalletJournalRow> rows = walletRepo.findJournalByCharacter(characterId);
            return rows.stream()
                    .map(r -> new JournalEntry(
                            r.journalId(),
                            r.date(),
                            r.transactionType(),
                            r.amount(),
                            r.balance(),
                            r.description(),
                            r.firstPartyId() != null ? r.firstPartyId() : 0L,
                            r.secondPartyId() != null ? r.secondPartyId() : 0L
                    ))
                    .toList();
        });
    }

    @Override
    public CompletableFuture<List<MarketTransaction>> getTransactions(int characterId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getTransactions for character {}", characterId);
            List<MarketTransactionRepository.MarketTransactionRow> rows =
                    marketTransactionRepo.findByCharacter(characterId);
            return rows.stream()
                    .map(r -> new MarketTransaction(
                            r.transactionId(),
                            r.date(),
                            r.typeId(),
                            r.quantity(),
                            r.unitPrice(),
                            r.clientId(),
                            r.isBuy(),
                            r.locationId()
                    ))
                    .toList();
        });
    }

    @Override
    public CompletableFuture<List<ProfitModel>> getProfitSummary(int characterId, LocalDate from, LocalDate to) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getProfitSummary for character {}", characterId);
            LocalDateTime fromDt = from != null ? from.atStartOfDay() : LocalDateTime.now().minusDays(30);
            LocalDateTime toDt = to != null ? to.atTime(23, 59, 59) : LocalDateTime.now();
            // Default skill levels for estimation (level 5 accounting, 5 broker)
            return profitTrackerLogic.calculateProfits(characterId, fromDt, toDt, 5, 5, 0.0, 0.0);
        });
    }

    // ================================================================
    // Market
    // ================================================================

    @Override
    public CompletableFuture<List<MarketPrice>> searchMarket(String query, int regionId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("searchMarket for query '{}' in region {}", query, regionId);
            List<TypeCacheRepository.TypeCacheRow> types = typeCacheRepo.findByName(query);
            List<MarketPrice> results = new ArrayList<>();
            for (TypeCacheRepository.TypeCacheRow type : types) {
                List<StationPriceRepository.StationPriceRow> prices = stationPriceRepo.findByType(type.typeId());
                if (prices.isEmpty()) {
                    results.add(new MarketPrice(type.typeId(), 0.0, 0.0, 0L));
                } else {
                    for (StationPriceRepository.StationPriceRow price : prices) {
                        results.add(new MarketPrice(
                                price.typeId(),
                                price.buyPrice(),
                                price.sellPrice(),
                                price.locationId()
                        ));
                    }
                }
            }
            return results;
        });
    }

    @Override
    public CompletableFuture<List<MarketStatistics>> getMarketHistory(int typeId, int regionId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getMarketHistory for type {} in region {}", typeId, regionId);
            List<MarketStatisticsRepository.MarketStatisticsRow> rows =
                    marketStatisticsRepo.findByTypeAndRegion(typeId, regionId);
            return rows.stream()
                    .map(r -> new MarketStatistics(
                            r.date(),
                            r.openPrice(),
                            r.highPrice(),
                            r.lowPrice(),
                            r.closePrice(),
                            r.volume(),
                            r.orderCount()
                    ))
                    .toList();
        });
    }

    @Override
    public CompletableFuture<List<MarketOrder>> getRegionOrders(int typeId, int regionId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getRegionOrders for type {} in region {}", typeId, regionId);
            try {
                var esiOrders = esiClient.market.getRegionOrdersForType(regionId, "all", typeId).join();
                return esiOrders.stream()
                        .map(o -> new MarketOrder(
                                o.orderId(),
                                o.typeId(),
                                o.price(),
                                o.volumeRemain(),
                                o.volumeTotal(),
                                o.isBuyOrder(),
                                o.duration(),
                                o.issued().toLocalDateTime(),
                                o.locationId(),
                                "active",
                                regionId
                        ))
                        .toList();
            } catch (Exception e) {
                log.error("Failed to fetch region orders for type {} in region {}", typeId, regionId, e);
                return List.of();
            }
        });
    }

    @Override
    public CompletableFuture<List<HubPrices>> appraiseItems(List<Integer> typeIds) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("appraiseItems for {} types", typeIds.size());
            List<HubPrices> results = new ArrayList<>();
            for (int typeId : typeIds) {
                double jitaBuy = 0, jitaSell = 0;
                double amarrBuy = 0, amarrSell = 0;
                double dodixieBuy = 0, dodixieSell = 0;
                double hekBuy = 0, hekSell = 0;
                double rensBuy = 0, rensSell = 0;

                var jita = stationPriceRepo.findById(typeId, Constants.JITA);
                if (jita.isPresent()) {
                    jitaBuy = jita.get().buyPrice();
                    jitaSell = jita.get().sellPrice();
                }

                var amarr = stationPriceRepo.findById(typeId, Constants.AMARR);
                if (amarr.isPresent()) {
                    amarrBuy = amarr.get().buyPrice();
                    amarrSell = amarr.get().sellPrice();
                }

                var dodixie = stationPriceRepo.findById(typeId, Constants.DODIXIE);
                if (dodixie.isPresent()) {
                    dodixieBuy = dodixie.get().buyPrice();
                    dodixieSell = dodixie.get().sellPrice();
                }

                var hek = stationPriceRepo.findById(typeId, Constants.HEK);
                if (hek.isPresent()) {
                    hekBuy = hek.get().buyPrice();
                    hekSell = hek.get().sellPrice();
                }

                var rens = stationPriceRepo.findById(typeId, Constants.RENS);
                if (rens.isPresent()) {
                    rensBuy = rens.get().buyPrice();
                    rensSell = rens.get().sellPrice();
                }

                results.add(new HubPrices(
                        typeId,
                        jitaBuy, jitaSell,
                        amarrBuy, amarrSell,
                        dodixieBuy, dodixieSell,
                        hekBuy, hekSell,
                        rensBuy, rensSell
                ));
            }
            return results;
        });
    }

    // ================================================================
    // Trader
    // ================================================================

    @Override
    public CompletableFuture<List<TradeOpportunity>> scanStationTrades(long stationId, double minProfit, int minVolume) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("scanStationTrades for station {} minProfit={} minVolume={}", stationId, minProfit, minVolume);
            try {
                int regionId = stationToRegion(stationId);
                log.info("Fetching region orders for region {} (station {})...", regionId, stationId);

                // Fetch ALL orders in the region from ESI (paginated)
                List<RegionOrder> allOrders = esiClient.market.getRegionOrders(regionId).join();
                log.info("Fetched {} total region orders, filtering to station {}", allOrders.size(), stationId);

                // Filter to orders at this station only
                List<RegionOrder> stationOrders = allOrders.stream()
                        .filter(o -> o.locationId() == stationId)
                        .toList();

                // Group by typeId
                Map<Integer, List<RegionOrder>> byType = stationOrders.stream()
                        .collect(Collectors.groupingBy(RegionOrder::typeId));

                List<TradeOpportunity> opportunities = new ArrayList<>();
                for (var entry : byType.entrySet()) {
                    int typeId = entry.getKey();
                    var orders = entry.getValue();

                    // Find best buy (highest buy order) and best sell (lowest sell order)
                    OptionalDouble bestBuy = orders.stream()
                            .filter(RegionOrder::isBuyOrder)
                            .mapToDouble(RegionOrder::price)
                            .max();
                    OptionalDouble bestSell = orders.stream()
                            .filter(o -> !o.isBuyOrder())
                            .mapToDouble(RegionOrder::price)
                            .min();

                    if (bestBuy.isEmpty() || bestSell.isEmpty()) continue;

                    double buyPrice = bestBuy.getAsDouble();
                    double sellPrice = bestSell.getAsDouble();
                    double profit = sellPrice - buyPrice;
                    double margin = sellPrice > 0 ? profit / sellPrice : 0;

                    if (profit < minProfit) continue;
                    if (margin <= 0) continue;

                    // Count total sell volume for this type
                    long sellVolume = orders.stream()
                            .filter(o -> !o.isBuyOrder())
                            .mapToLong(RegionOrder::volumeRemain)
                            .sum();

                    // Count number of sell orders (competition)
                    long orderCount = orders.stream()
                            .filter(o -> !o.isBuyOrder())
                            .count();

                    String typeName = typeCacheRepo.findNameById(typeId).orElse("Type #" + typeId);

                    opportunities.add(new TradeOpportunity(
                            typeId, typeName, buyPrice, sellPrice, margin,
                            orderCount, (double) sellVolume
                    ));
                }

                // Cache the prices we found for future use
                for (var opp : opportunities) {
                    stationPriceRepo.upsert(opp.typeId(), stationId, opp.buyPrice(), opp.sellPrice());
                }

                opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
                log.info("Found {} station trade opportunities", opportunities.size());
                return opportunities;
            } catch (Exception e) {
                log.error("Failed to scan station trades for station {}", stationId, e);
                return List.of();
            }
        });
    }

    @Override
    public CompletableFuture<List<TradeOpportunity>> scanRegionalTrades(int fromRegionId, int toRegionId,
                                                                        double minMargin, double maxCargo, double budget) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("scanRegionalTrades from {} to {} minMargin={} maxCargo={} budget={}",
                    fromRegionId, toRegionId, minMargin, maxCargo, budget);
            try {
                log.info("Fetching region orders for regions {} and {}...", fromRegionId, toRegionId);

                // Fetch orders from both regions in parallel
                var fromOrdersFuture = esiClient.market.getRegionOrders(fromRegionId);
                var toOrdersFuture = esiClient.market.getRegionOrders(toRegionId);

                List<RegionOrder> fromOrders = fromOrdersFuture.join();
                List<RegionOrder> toOrders = toOrdersFuture.join();
                log.info("Fetched {} orders from source region, {} from destination region",
                        fromOrders.size(), toOrders.size());

                // Build price maps: for source, find lowest sell price per type
                Map<Integer, Double> sourceSellPrices = new HashMap<>();
                Map<Integer, Long> sourceVolumes = new HashMap<>();
                for (var order : fromOrders) {
                    if (order.isBuyOrder()) continue; // skip buy orders
                    sourceSellPrices.merge(order.typeId(), order.price(), Math::min);
                    sourceVolumes.merge(order.typeId(), (long) order.volumeRemain(), Long::sum);
                }

                // For destination, find lowest sell price (what we undercut)
                Map<Integer, Double> destSellPrices = new HashMap<>();
                for (var order : toOrders) {
                    if (order.isBuyOrder()) continue;
                    destSellPrices.merge(order.typeId(), order.price(), Math::min);
                }

                List<TradeOpportunity> opportunities = new ArrayList<>();
                for (var entry : sourceSellPrices.entrySet()) {
                    int typeId = entry.getKey();
                    double buyCost = entry.getValue();
                    Double sellRevenue = destSellPrices.get(typeId);

                    if (sellRevenue == null || buyCost <= 0 || sellRevenue <= 0) continue;

                    double margin = (sellRevenue - buyCost) / sellRevenue;
                    if (margin < minMargin) continue;

                    // Check cargo volume constraint
                    var typeInfo = typeCacheRepo.findById(typeId);
                    if (typeInfo.isPresent() && maxCargo > 0) {
                        double vol = typeInfo.get().packagedVolume() > 0
                                ? typeInfo.get().packagedVolume()
                                : typeInfo.get().volume();
                        if (vol > maxCargo) continue;
                    }

                    // Check budget constraint
                    if (budget > 0 && buyCost > budget) continue;

                    long volume = sourceVolumes.getOrDefault(typeId, 0L);
                    String typeName = typeCacheRepo.findNameById(typeId).orElse("Type #" + typeId);

                    opportunities.add(new TradeOpportunity(
                            typeId, typeName, buyCost, sellRevenue, margin,
                            volume, (double) volume
                    ));
                }

                opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
                log.info("Found {} regional trade opportunities", opportunities.size());
                return opportunities;
            } catch (Exception e) {
                log.error("Failed to scan regional trades from {} to {}", fromRegionId, toRegionId, e);
                return List.of();
            }
        });
    }

    /**
     * Maps well-known trade hub station IDs to their region IDs.
     */
    private static int stationToRegion(long stationId) {
        if (stationId == 60003760L) return 10000002; // Jita -> The Forge
        if (stationId == 60008494L) return 10000043; // Amarr -> Domain
        if (stationId == 60011866L) return 10000032; // Dodixie -> Sinq Laison
        if (stationId == 60004588L) return 10000030; // Rens -> Heimatar
        if (stationId == 60005686L) return 10000042; // Hek -> Metropolis
        return 10000002; // default to The Forge
    }

    // ================================================================
    // LP Store
    // ================================================================

    @Override
    public CompletableFuture<List<LoyaltyOffer>> getLpStoreOffers(int corporationId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getLpStoreOffers for corporation {}", corporationId);
            try {
                var response = esiClient.loyalty.getStoreOffers(corporationId).join();
                if (response.isSuccess() && response.data() != null) {
                    return response.data().stream()
                            .map(o -> new LoyaltyOffer(
                                    o.offerId(),
                                    o.typeId(),
                                    o.quantity(),
                                    o.lpCost(),
                                    (double) o.iskCost(),
                                    o.requiredItems() != null
                                            ? o.requiredItems().stream()
                                            .map(ri -> new LoyaltyOfferRequirement(ri.typeId(), ri.quantity()))
                                            .toList()
                                            : List.of()
                            ))
                            .toList();
                }
                return List.<LoyaltyOffer>of();
            } catch (Exception e) {
                log.error("Failed to fetch LP store offers for corporation {}", corporationId, e);
                return List.of();
            }
        });
    }

    @Override
    public CompletableFuture<List<LoyaltyPoints>> getLoyaltyPoints(int characterId) {
