package com.sampleapp.data.repository;

import com.sampleapp.data.DatabaseManager;
import jakarta.inject.Inject;
import jakarta.inject.Singleton;

import java.util.List;
import java.util.Optional;

/**
 * Repository for the SdeMarketGroups table (market group hierarchy).
 */
@Singleton
public class MarketGroupRepository extends BaseRepository {

    public record MarketGroupRow(
            int marketGroupId, Integer parentGroupId, String name,
            boolean hasTypes, Integer iconId
    ) {}

    private static final RowMapper<MarketGroupRow> MAPPER = rs -> new MarketGroupRow(
            rs.getInt("MarketGroupId"),
            rs.getObject("ParentGroupId") != null ? rs.getInt("ParentGroupId") : null,
            rs.getString("Name"),
            rs.getBoolean("HasTypes"),
            rs.getObject("IconId") != null ? rs.getInt("IconId") : null
    );

    @Inject
    public MarketGroupRepository(DatabaseManager db) {
        super(db);
    }

    public List<MarketGroupRow> findAll() {
        return query("SELECT * FROM SdeMarketGroups ORDER BY Name", MAPPER);
    }

    /**
     * Returns children of the given parent. Pass null for root-level groups.
     */
    public List<MarketGroupRow> findByParent(Integer parentId) {
        if (parentId == null) {
            return query("SELECT * FROM SdeMarketGroups WHERE ParentGroupId IS NULL ORDER BY Name", MAPPER);
        }
        return query("SELECT * FROM SdeMarketGroups WHERE ParentGroupId = ? ORDER BY Name", MAPPER, parentId);
    }

    public Optional<MarketGroupRow> findById(int id) {
        return queryOne("SELECT * FROM SdeMarketGroups WHERE MarketGroupId = ?", MAPPER, id);
    }

    /**
     * Bulk loads market group entries from SDE data.
     */
    public void bulkLoad(List<MarketGroupRow> rows) {
        String sql = """
                MERGE INTO SdeMarketGroups
                (MarketGroupId, ParentGroupId, Name, HasTypes, IconId)
                KEY (MarketGroupId)
                VALUES (?, ?, ?, ?, ?)
                """;
        List<Object[]> params = rows.stream()
                .map(r -> new Object[]{
                        r.marketGroupId(), r.parentGroupId(), r.name(),
                        r.hasTypes(), r.iconId()
                })
                .toList();
        batchInsert(sql, params);
    }

    public int count() {
        return queryOne("SELECT COUNT(*) AS cnt FROM SdeMarketGroups",
                rs -> rs.getInt("cnt"))
                .orElse(0);
    }
}

