    groupItem.expandedProperty().addListener((obs, wasExpanded, isExpanded) -> {
        if (isExpanded && groupItem.getChildren().size() == 1
                && groupItem.getChildren().get(0).getValue().id() == -1) {
            int groupId = groupItem.getValue().id();
            Thread.ofVirtual().name("market-tree-expand-" + groupId).start(() -> {
                try {
                    // Load child groups
                    var childGroups = dataService.getChildMarketGroups(groupId).join();
                    // Load items in this group
                    var items = dataService.getMarketGroupItems(groupId).join();

                    Platform.runLater(() -> {
                        groupItem.getChildren().clear();
                        // Add child groups (folders)
                        for (var child : childGroups) {
                            var childNode = new TreeItem<>(new MarketTreeItem(child.marketGroupId(), child.name(), false));
                            childNode.getChildren().add(new TreeItem<>(new MarketTreeItem(-1, "Loading...", false)));
                            setupLazyLoad(childNode);
                            groupItem.getChildren().add(childNode);
                        }
                        // Add items (leaves)
                        for (var item : items) {
                            groupItem.getChildren().add(new TreeItem<>(new MarketTreeItem(item.typeId(), item.name(), true)));
                        }
                    });
                } catch (Exception e) {
                    Platform.runLater(() -> {
                        groupItem.getChildren().clear();
                        groupItem.getChildren().add(new TreeItem<>(new MarketTreeItem(-1, "Failed to load", false)));
                    });
                }
            });
        }
    });
}
```

