600	    private static int hubToRegionIdFromFullName(String fullHubName) {
601	        if (fullHubName.startsWith("Jita")) return 10000002;
602	        if (fullHubName.startsWith("Amarr")) return 10000043;
603	        if (fullHubName.startsWith("Dodixie")) return 10000032;
604	        if (fullHubName.startsWith("Rens")) return 10000030;
605	        if (fullHubName.startsWith("Hek")) return 10000042;
606	        return 10000002;
607	    }
