990	    private void updateShoppingTree(TreeItem<String> root, List<TradeOpportunity> data, String sourceHub) {
991	        root.getChildren().clear();
992	
993	        // Group all items under the source hub system
994	        var systemNode = new TreeItem<>(sourceHub + " - Buy List");
995	        systemNode.setExpanded(true);
996	
997	        for (var opp : data) {
998	            long qty = opp.volume();
999	            String label = String.format("%s x%d  -  %s",
1000	                    opp.typeName(), qty, IskFormatter.format(opp.buyPrice() * qty));
1001	            systemNode.getChildren().add(new TreeItem<>(label));
1002	        }
1003	
1004	        double totalCost = data.stream()
1005	                .mapToDouble(o -> o.buyPrice() * o.volume())
1006	                .sum();
1007	        var summaryNode = new TreeItem<>(String.format("Total: %s (%d items)",
1008	                IskFormatter.format(totalCost), data.size()));
1009	
1010	        root.getChildren().addAll(systemNode, summaryNode);
1011	    }
