package com.sampleapp.ui.workspace;

import com.sampleapp.common.IskFormatter;
import com.sampleapp.core.app.AppState;
import com.sampleapp.core.app.FeatureGate;
import com.sampleapp.core.app.FeatureGate.FeatureSet;
import com.sampleapp.core.app.FeatureGate.SubscriptionTier;
import com.sampleapp.core.model.MarketOrder;
import com.sampleapp.core.model.TradeOpportunity;
import javafx.application.Platform;
import javafx.beans.property.SimpleDoubleProperty;
import javafx.beans.property.SimpleLongProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.collections.transformation.FilteredList;
import javafx.collections.transformation.SortedList;
import javafx.geometry.Insets;
import javafx.geometry.Orientation;
import javafx.geometry.Pos;
import javafx.scene.control.*;
import javafx.scene.input.Clipboard;
import javafx.scene.input.ClipboardContent;
import javafx.scene.layout.*;

import java.time.format.DateTimeFormatter;
import java.util.*;

/**
 * Trader workspace with feature-gated tabs:
 * - Station Trader (requires STATION_TRADER + Professional)
 * - Regional Day-Trader (requires REGIONAL_DAY_TRADER + Professional)
 * Shows "subscription required" message for locked features.
 */
public class TraderWorkspace extends Workspace {

    private final FeatureGate featureGate;
    private final WorkspaceDataService dataService;

    private final ObservableList<TradeOpportunity> stationOpportunities = FXCollections.observableArrayList();
    private final ObservableList<TradeOpportunity> regionalOpportunities = FXCollections.observableArrayList();

    // Station trader favorites and blacklist
    private final ObservableList<Integer> favoriteTypeIds = FXCollections.observableArrayList();
    private final ObservableList<Integer> blacklistTypeIds = FXCollections.observableArrayList();

    // Regional in-transit items
    private final ObservableList<TradeOpportunity> inTransitItems = FXCollections.observableArrayList();

    // Regional summary labels
    private Label totalInvestmentLabel;
    private Label totalProfitLabel;
    private Label roiLabel;
    private Label cargoUsedLabel;

    // Station detail panel
    private TableView<MarketOrder> buyOrdersTable;
    private TableView<MarketOrder> sellOrdersTable;
    private Label detailItemLabel;

    // Hub station ID mapping
    private static final Map<String, Long> HUB_STATION_IDS = Map.of(
            "Jita IV - Moon 4 - Caldari Navy Assembly Plant", 60003760L,
            "Amarr VIII (Oris) - Emperor Family Academy", 60008494L,
            "Dodixie IX - Moon 20 - Federation Navy Assembly Plant", 60011866L,
            "Rens VI - Moon 8 - Brutor Tribe Treasury", 60004588L,
            "Hek VIII - Moon 12 - Boundless Creation Factory", 60005686L
    );

    // Hub name to region ID mapping
    private static final Map<String, Integer> HUB_REGION_IDS = Map.of(
            "Jita", 10000002,
            "Amarr", 10000043,
            "Dodixie", 10000032,
            "Rens", 10000030,
            "Hek", 10000042
    );

    public TraderWorkspace(AppState appState, FeatureGate featureGate,
                           WorkspaceDataService dataService) {
        super(appState);
        this.featureGate = featureGate;
        this.dataService = dataService;

        tabPane.getTabs().addAll(
                createStationTraderTab(),
                createRegionalDayTraderTab()
        );
    }

    // -----------------------------------------------------------------------
    // Station Trader Tab
    // -----------------------------------------------------------------------

    @SuppressWarnings("unchecked")
    private Tab createStationTraderTab() {
        var tab = new Tab("Station Trader");

        if (!featureGate.isFeatureAvailable(FeatureSet.STATION_TRADER,
                SubscriptionTier.PROFESSIONAL)) {
            tab.setContent(new FeatureLockedPane(
                    "Station Trader", "Professional"));
            return tab;
        }

        // --- Top bar: Hub selection + Scan ---
        var hubBox = new HBox(10);
        hubBox.setPadding(new Insets(5));
        hubBox.setAlignment(Pos.CENTER_LEFT);
        var hubCombo = new ComboBox<String>();
        hubCombo.getItems().addAll(
                "Jita IV - Moon 4 - Caldari Navy Assembly Plant",
                "Amarr VIII (Oris) - Emperor Family Academy",
                "Dodixie IX - Moon 20 - Federation Navy Assembly Plant",
                "Rens VI - Moon 8 - Brutor Tribe Treasury",
                "Hek VIII - Moon 12 - Boundless Creation Factory"
        );
        hubCombo.setValue("Jita IV - Moon 4 - Caldari Navy Assembly Plant");
        var scanBtn = new Button("Scan Market");
        var importBtn = new Button("Import Orders");
        hubBox.getChildren().addAll(new Label("Hub:"), hubCombo, scanBtn, importBtn);

        // --- Side panel with accordion-style TitledPanes ---
        var sidePanel = new VBox(5);
        sidePanel.setPrefWidth(260);
        sidePanel.setPadding(new Insets(5));

        // Filters pane
        var filtersGrid = new GridPane();
        filtersGrid.setHgap(8);
        filtersGrid.setVgap(6);
        filtersGrid.setPadding(new Insets(8));

        var minProfitField = new TextField("1000000");
        minProfitField.setPrefWidth(130);
        var minMarginField = new TextField("5");
        minMarginField.setPrefWidth(130);
        var minDailyDemandField = new TextField("10");
        minDailyDemandField.setPrefWidth(130);
        var priceHistoryCombo = new ComboBox<Integer>();
        priceHistoryCombo.getItems().addAll(7, 14, 30, 60, 90);
        priceHistoryCombo.setValue(30);
        priceHistoryCombo.setPrefWidth(130);
        var minPeriodRoiField = new TextField("5");
        minPeriodRoiField.setPrefWidth(130);
        var flagExtremePricesCheck = new CheckBox("Flag Extreme Prices");

        filtersGrid.add(new Label("Min Profit:"), 0, 0);
        filtersGrid.add(minProfitField, 1, 0);
        filtersGrid.add(new Label("Min Margin %:"), 0, 1);
        filtersGrid.add(minMarginField, 1, 1);
        filtersGrid.add(new Label("Min Daily Demand:"), 0, 2);
        filtersGrid.add(minDailyDemandField, 1, 2);
        filtersGrid.add(new Label("Price History Days:"), 0, 3);
        filtersGrid.add(priceHistoryCombo, 1, 3);
        filtersGrid.add(new Label("Min Period ROI %:"), 0, 4);
        filtersGrid.add(minPeriodRoiField, 1, 4);
        filtersGrid.add(flagExtremePricesCheck, 0, 5, 2, 1);

        var filtersTitledPane = new TitledPane("Filters", filtersGrid);
        filtersTitledPane.setExpanded(true);

        // Assets/Orders pane
        var assetsGrid = new GridPane();
        assetsGrid.setHgap(8);
        assetsGrid.setVgap(6);
        assetsGrid.setPadding(new Insets(8));

        var assetsScopeCombo = new ComboBox<String>();
        assetsScopeCombo.getItems().addAll("All", "Station", "Region");
        assetsScopeCombo.setValue("All");
        assetsScopeCombo.setPrefWidth(130);
        var activeOrdersCombo = new ComboBox<String>();
        activeOrdersCombo.getItems().addAll("All", "Character", "Station");
        activeOrdersCombo.setValue("All");
        activeOrdersCombo.setPrefWidth(130);

        assetsGrid.add(new Label("Assets Scope:"), 0, 0);
        assetsGrid.add(assetsScopeCombo, 1, 0);
        assetsGrid.add(new Label("Active Orders:"), 0, 1);
        assetsGrid.add(activeOrdersCombo, 1, 1);

        var assetsTitledPane = new TitledPane("Assets / Orders", assetsGrid);
        assetsTitledPane.setExpanded(false);

        // Purchase Volume pane
        var purchaseGrid = new GridPane();
        purchaseGrid.setHgap(8);
        purchaseGrid.setVgap(6);
        purchaseGrid.setPadding(new Insets(8));

        var daysOfSupplySpinner = new Spinner<Integer>(1, 30, 3);
        daysOfSupplySpinner.setPrefWidth(130);
        daysOfSupplySpinner.setEditable(true);

        purchaseGrid.add(new Label("Days of Supply:"), 0, 0);
        purchaseGrid.add(daysOfSupplySpinner, 1, 0);

        var purchaseTitledPane = new TitledPane("Purchase Volume", purchaseGrid);
        purchaseTitledPane.setExpanded(false);

        sidePanel.getChildren().addAll(filtersTitledPane, assetsTitledPane, purchaseTitledPane);

        // --- Favorites tab ---
        var favoritesListView = new ListView<>(favoriteTypeIds);
        favoritesListView.setCellFactory(lv -> new ListCell<>() {
            @Override
            protected void updateItem(Integer typeId, boolean empty) {
                super.updateItem(typeId, empty);
                if (empty || typeId == null) {
                    setText(null);
                } else {
                    setText("Type ID: " + typeId);
                    dataService.resolveTypeName(typeId).thenAccept(name ->
                            Platform.runLater(() -> setText(name + " (" + typeId + ")")));
                }
            }
        });
        var addFavoriteField = new TextField();
        addFavoriteField.setPromptText("Type ID");
        addFavoriteField.setPrefWidth(100);
        var addFavoriteBtn = new Button("Add");
        addFavoriteBtn.setOnAction(e -> {
            try {
                int id = Integer.parseInt(addFavoriteField.getText().trim());
                if (!favoriteTypeIds.contains(id)) {
                    favoriteTypeIds.add(id);
                }
                addFavoriteField.clear();
            } catch (NumberFormatException ignored) {
                // invalid input, ignore
            }
        });
        var removeFavoriteBtn = new Button("Remove");
        removeFavoriteBtn.setOnAction(e -> {
            var selected = favoritesListView.getSelectionModel().getSelectedItem();
            if (selected != null) {
                favoriteTypeIds.remove(selected);
            }
        });
        var favBtnBox = new HBox(5, addFavoriteField, addFavoriteBtn, removeFavoriteBtn);
        favBtnBox.setPadding(new Insets(5));
        var favoritesContent = new VBox(5, favoritesListView, favBtnBox);
        VBox.setVgrow(favoritesListView, Priority.ALWAYS);

        // --- Blacklist tab ---
        var blacklistListView = new ListView<>(blacklistTypeIds);
        blacklistListView.setCellFactory(lv -> new ListCell<>() {
            @Override
            protected void updateItem(Integer typeId, boolean empty) {
                super.updateItem(typeId, empty);
                if (empty || typeId == null) {
                    setText(null);
                } else {
                    setText("Type ID: " + typeId);
                    dataService.resolveTypeName(typeId).thenAccept(name ->
                            Platform.runLater(() -> setText(name + " (" + typeId + ")")));
                }
            }
        });
        var addBlacklistField = new TextField();
        addBlacklistField.setPromptText("Type ID");
        addBlacklistField.setPrefWidth(100);
        var addBlacklistBtn = new Button("Add");
        addBlacklistBtn.setOnAction(e -> {
            try {
                int id = Integer.parseInt(addBlacklistField.getText().trim());
                if (!blacklistTypeIds.contains(id)) {
                    blacklistTypeIds.add(id);
                }
                addBlacklistField.clear();
            } catch (NumberFormatException ignored) {
                // invalid input, ignore
            }
        });
        var removeBlacklistBtn = new Button("Remove");
        removeBlacklistBtn.setOnAction(e -> {
            var selected = blacklistListView.getSelectionModel().getSelectedItem();
            if (selected != null) {
                blacklistTypeIds.remove(selected);
            }
        });
        var blBtnBox = new HBox(5, addBlacklistField, addBlacklistBtn, removeBlacklistBtn);
        blBtnBox.setPadding(new Insets(5));
        var blacklistContent = new VBox(5, blacklistListView, blBtnBox);
        VBox.setVgrow(blacklistListView, Priority.ALWAYS);

        // Side TabPane for Filters / Favorites / Blacklist
        var sideTabPane = new TabPane();
        sideTabPane.setTabClosingPolicy(TabPane.TabClosingPolicy.UNAVAILABLE);
        sideTabPane.setPrefWidth(270);
        var filtersTab = new Tab("Filters", sidePanel);
        var favoritesTab = new Tab("Favorites", favoritesContent);
        var blacklistTab = new Tab("Blacklist", blacklistContent);
        sideTabPane.getTabs().addAll(filtersTab, favoritesTab, blacklistTab);

        // --- Search / filter field for table ---
        var searchField = new TextField();
        searchField.setPromptText("Search items...");
        searchField.setPrefWidth(300);
        var searchBar = new HBox(10, new Label("Filter:"), searchField);
        searchBar.setPadding(new Insets(5));
        searchBar.setAlignment(Pos.CENTER_LEFT);

        // --- Opportunities table ---
        var filteredList = new FilteredList<>(stationOpportunities, p -> true);
        searchField.textProperty().addListener((obs, oldVal, newVal) -> {
            String filterText = newVal == null ? "" : newVal.toLowerCase();
            filteredList.setPredicate(opp -> {
                if (filterText.isEmpty()) return true;
                return opp.typeName().toLowerCase().contains(filterText);
            });
        });
        var sortedList = new SortedList<>(filteredList);

        var table = new TableView<TradeOpportunity>();
        sortedList.comparatorProperty().bind(table.comparatorProperty());
        table.setItems(sortedList);

        var itemCol = new TableColumn<TradeOpportunity, String>("Item");
        itemCol.setPrefWidth(180);
        itemCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().typeName()));

        var buyCol = new TableColumn<TradeOpportunity, String>("Buy Price");
        buyCol.setPrefWidth(110);
        buyCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().buyPrice())));
        buyCol.setComparator(TraderWorkspace::compareIskStrings);

        var sellCol = new TableColumn<TradeOpportunity, String>("Sell Price");
        sellCol.setPrefWidth(110);
        sellCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().sellPrice())));
        sellCol.setComparator(TraderWorkspace::compareIskStrings);

        var profitCol = new TableColumn<TradeOpportunity, String>("Profit/Unit");
        profitCol.setPrefWidth(100);
        profitCol.setCellValueFactory(c -> {
            double profit = c.getValue().sellPrice() - c.getValue().buyPrice();
            return new SimpleStringProperty(IskFormatter.formatRaw(profit));
        });
        profitCol.setComparator(TraderWorkspace::compareIskStrings);

        var marginCol = new TableColumn<TradeOpportunity, String>("Margin %");
        marginCol.setPrefWidth(75);
        marginCol.setCellValueFactory(c -> new SimpleStringProperty(
                String.format("%.1f%%", c.getValue().margin() * 100.0)));

        var dailyVolCol = new TableColumn<TradeOpportunity, Number>("Daily Vol");
        dailyVolCol.setPrefWidth(75);
        dailyVolCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().dailyVolume()));

        var dailyProfitCol = new TableColumn<TradeOpportunity, String>("Daily Profit");
        dailyProfitCol.setPrefWidth(110);
        dailyProfitCol.setCellValueFactory(c -> {
            double profit = (c.getValue().sellPrice() - c.getValue().buyPrice()) * c.getValue().dailyVolume();
            return new SimpleStringProperty(IskFormatter.formatRaw(profit));
        });
        dailyProfitCol.setComparator(TraderWorkspace::compareIskStrings);

        var competCol = new TableColumn<TradeOpportunity, Number>("Orders");
        competCol.setPrefWidth(60);
        competCol.setCellValueFactory(c -> new SimpleLongProperty(c.getValue().volume()));

        // Additional columns from C# feature set
        int daysOfSupply = daysOfSupplySpinner.getValue();

        var purchaseUnitsCol = new TableColumn<TradeOpportunity, Number>("Purchase Units");
        purchaseUnitsCol.setPrefWidth(100);
        purchaseUnitsCol.setCellValueFactory(c -> {
            long units = Math.round(c.getValue().dailyVolume() * daysOfSupplySpinner.getValue());
            return new SimpleLongProperty(units);
        });

        var dailyTradableCol = new TableColumn<TradeOpportunity, Number>("Daily Tradable");
        dailyTradableCol.setPrefWidth(95);
        dailyTradableCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().dailyVolume()));

        var dailyBuyUnitsCol = new TableColumn<TradeOpportunity, Number>("Daily Buy Units");
        dailyBuyUnitsCol.setPrefWidth(100);
        dailyBuyUnitsCol.setCellValueFactory(c -> {
            long buyUnits = Math.round(c.getValue().dailyVolume() * 0.5);
            return new SimpleLongProperty(buyUnits);
        });

        var dailySellUnitsCol = new TableColumn<TradeOpportunity, Number>("Daily Sell Units");
        dailySellUnitsCol.setPrefWidth(100);
        dailySellUnitsCol.setCellValueFactory(c -> {
            long sellUnits = Math.round(c.getValue().dailyVolume() * 0.5);
            return new SimpleLongProperty(sellUnits);
        });

        var buyVsSellRatioCol = new TableColumn<TradeOpportunity, String>("Buy/Sell Ratio");
        buyVsSellRatioCol.setPrefWidth(85);
        buyVsSellRatioCol.setCellValueFactory(c -> {
            double sellPrice = c.getValue().sellPrice();
            double ratio = sellPrice > 0 ? c.getValue().buyPrice() / sellPrice : 0;
            return new SimpleStringProperty(String.format("%.2f", ratio));
        });

        var regionAvgTradeVolCol = new TableColumn<TradeOpportunity, Number>("Rgn Avg Trade Vol");
        regionAvgTradeVolCol.setPrefWidth(110);
        regionAvgTradeVolCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().dailyVolume()));

        var capitalRequiredCol = new TableColumn<TradeOpportunity, String>("Capital Required");
        capitalRequiredCol.setPrefWidth(110);
        capitalRequiredCol.setCellValueFactory(c -> {
            double capital = c.getValue().buyPrice() * Math.round(c.getValue().dailyVolume() * daysOfSupplySpinner.getValue());
            return new SimpleStringProperty(IskFormatter.formatRaw(capital));
        });
        capitalRequiredCol.setComparator(TraderWorkspace::compareIskStrings);

        var roiNowCol = new TableColumn<TradeOpportunity, String>("ROI Now %");
        roiNowCol.setPrefWidth(80);
        roiNowCol.setCellValueFactory(c -> {
            double buy = c.getValue().buyPrice();
            double roi = buy > 0 ? ((c.getValue().sellPrice() - buy) / buy) * 100.0 : 0;
            return new SimpleStringProperty(String.format("%.1f%%", roi));
        });

        var roiPeriodCol = new TableColumn<TradeOpportunity, String>("ROI Period %");
        roiPeriodCol.setPrefWidth(85);
        roiPeriodCol.setCellValueFactory(c -> {
            double buy = c.getValue().buyPrice();
            int days = priceHistoryCombo.getValue();
            double dailyRoi = buy > 0 ? ((c.getValue().sellPrice() - buy) / buy) : 0;
            double periodRoi = dailyRoi * days * 100.0;
            return new SimpleStringProperty(String.format("%.1f%%", periodRoi));
        });

        table.getColumns().addAll(itemCol, buyCol, sellCol, profitCol, marginCol,
                dailyVolCol, dailyProfitCol, competCol, purchaseUnitsCol, dailyTradableCol,
                dailyBuyUnitsCol, dailySellUnitsCol, buyVsSellRatioCol, regionAvgTradeVolCol,
                capitalRequiredCol, roiNowCol, roiPeriodCol);
        table.setPlaceholder(new Label("Click Scan Market to find opportunities"));

        // Context menu for table rows
        table.setRowFactory(tv -> {
            var row = new TableRow<TradeOpportunity>();
            var contextMenu = createTradeContextMenu(row, favoriteTypeIds, blacklistTypeIds);
            row.setContextMenu(contextMenu);
            return row;
        });

        // --- Item detail panel (regional buy/sell orders for selected item) ---
        detailItemLabel = new Label("Select an item to view regional orders");
        detailItemLabel.setStyle("-fx-font-weight: bold; -fx-padding: 5;");

        buyOrdersTable = createMarketOrderTable("Buy Orders");
        sellOrdersTable = createMarketOrderTable("Sell Orders");

        var buyOrdersPane = new TitledPane("Buy Orders", buyOrdersTable);
        buyOrdersPane.setExpanded(true);
        var sellOrdersPane = new TitledPane("Sell Orders", sellOrdersTable);
        sellOrdersPane.setExpanded(true);

        var detailContent = new VBox(5, detailItemLabel, buyOrdersPane, sellOrdersPane);
        detailContent.setPadding(new Insets(5));
        detailContent.setPrefHeight(200);

        // Load orders when a table row is selected
        table.getSelectionModel().selectedItemProperty().addListener((obs, oldVal, newVal) -> {
            if (newVal != null) {
                loadItemOrders(newVal, hubCombo.getValue());
            } else {
                detailItemLabel.setText("Select an item to view regional orders");
                buyOrdersTable.getItems().clear();
                sellOrdersTable.getItems().clear();
            }
        });

        // SplitPane: table on top, detail on bottom
        var tableSplit = new SplitPane();
        tableSplit.setOrientation(Orientation.VERTICAL);
        tableSplit.setDividerPositions(0.65);
        var tableContainer = new VBox(searchBar, table);
        VBox.setVgrow(table, Priority.ALWAYS);
        tableSplit.getItems().addAll(tableContainer, detailContent);

        // --- Scan action ---
        scanBtn.setOnAction(e -> {
            scanBtn.setDisable(true);
            double minProfit;
            int minVolume;
            try {
                minProfit = Double.parseDouble(minProfitField.getText().replace(",", ""));
                minVolume = Integer.parseInt(minDailyDemandField.getText().replace(",", ""));
            } catch (NumberFormatException ex) {
                scanBtn.setDisable(false);
                return;
            }
            long stationId = HUB_STATION_IDS.getOrDefault(hubCombo.getValue(), 60003760L);
            Thread.ofVirtual().name("trader-station-scan").start(() ->
                    dataService.scanStationTrades(stationId, minProfit, minVolume)
                            .thenAccept(data -> Platform.runLater(() -> {
                                // Filter out blacklisted items
                                var filtered = data.stream()
                                        .filter(opp -> !blacklistTypeIds.contains(opp.typeId()))
                                        .toList();
                                stationOpportunities.setAll(filtered);
                                scanBtn.setDisable(false);
                            }))
                            .exceptionally(ex -> {
                                Platform.runLater(() -> {
                                    log.error("Failed to scan station trades", ex);
                                    scanBtn.setDisable(false);
                                });
                                return null;
                            })
            );
        });

        // --- Main layout: side panel + table area ---
        var mainSplit = new SplitPane();
        mainSplit.setOrientation(Orientation.HORIZONTAL);
        mainSplit.setDividerPositions(0.2);
        mainSplit.getItems().addAll(sideTabPane, tableSplit);
        SplitPane.setResizableWithParent(sideTabPane, false);

        var root = new VBox(hubBox, mainSplit);
        VBox.setVgrow(mainSplit, Priority.ALWAYS);

        tab.setContent(root);
        return tab;
    }

    @SuppressWarnings("unchecked")
    private TableView<MarketOrder> createMarketOrderTable(String title) {
        var table = new TableView<MarketOrder>();
        table.setPrefHeight(150);

        var priceCol = new TableColumn<MarketOrder, String>("Price");
        priceCol.setPrefWidth(120);
        priceCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().price())));
        priceCol.setComparator(TraderWorkspace::compareIskStrings);

        var volRemainCol = new TableColumn<MarketOrder, Number>("Volume");
        volRemainCol.setPrefWidth(80);
        volRemainCol.setCellValueFactory(c -> new SimpleLongProperty(c.getValue().volumeRemain()));

        var volTotalCol = new TableColumn<MarketOrder, Number>("Total Vol");
        volTotalCol.setPrefWidth(80);
        volTotalCol.setCellValueFactory(c -> new SimpleLongProperty(c.getValue().volumeTotal()));

        var locationCol = new TableColumn<MarketOrder, String>("Location");
        locationCol.setPrefWidth(150);
        locationCol.setCellValueFactory(c -> {
            var prop = new SimpleStringProperty("" + c.getValue().locationId());
            dataService.resolveLocationName(c.getValue().locationId()).thenAccept(name ->
                    Platform.runLater(() -> prop.set(name)));
            return prop;
        });

        var durationCol = new TableColumn<MarketOrder, Number>("Duration");
        durationCol.setPrefWidth(60);
        durationCol.setCellValueFactory(c -> new SimpleLongProperty(c.getValue().duration()));

        var issuedCol = new TableColumn<MarketOrder, String>("Issued");
        issuedCol.setPrefWidth(130);
        issuedCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().issued().format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm"))));

        table.getColumns().addAll(priceCol, volRemainCol, volTotalCol, locationCol, durationCol, issuedCol);
        table.setPlaceholder(new Label("No " + title.toLowerCase()));
        return table;
    }

    private void loadItemOrders(TradeOpportunity item, String hubName) {
        detailItemLabel.setText("Loading orders for: " + item.typeName() + "...");
        buyOrdersTable.getItems().clear();
        sellOrdersTable.getItems().clear();

        int regionId = hubToRegionIdFromFullName(hubName);
        Thread.ofVirtual().name("trader-load-orders").start(() ->
                dataService.getRegionOrders(item.typeId(), regionId)
                        .thenAccept(orders -> Platform.runLater(() -> {
                            detailItemLabel.setText("Orders for: " + item.typeName());
                            var buyOrders = orders.stream()
                                    .filter(MarketOrder::isBuyOrder)
                                    .sorted(Comparator.comparingDouble(MarketOrder::price).reversed())
                                    .toList();
                            var sellOrders = orders.stream()
                                    .filter(o -> !o.isBuyOrder())
                                    .sorted(Comparator.comparingDouble(MarketOrder::price))
                                    .toList();
                            buyOrdersTable.getItems().setAll(buyOrders);
                            sellOrdersTable.getItems().setAll(sellOrders);
                        }))
                        .exceptionally(ex -> {
                            Platform.runLater(() -> {
                                detailItemLabel.setText("Failed to load orders for: " + item.typeName());
                                log.error("Failed to load item orders", ex);
                            });
                            return null;
                        })
        );
    }

    private static int hubToRegionIdFromFullName(String fullHubName) {
        if (fullHubName.startsWith("Jita")) return 10000002;
        if (fullHubName.startsWith("Amarr")) return 10000043;
        if (fullHubName.startsWith("Dodixie")) return 10000032;
        if (fullHubName.startsWith("Rens")) return 10000030;
        if (fullHubName.startsWith("Hek")) return 10000042;
        return 10000002;
    }

    // -----------------------------------------------------------------------
    // Regional Day-Trader Tab
    // -----------------------------------------------------------------------

    @SuppressWarnings("unchecked")
    private Tab createRegionalDayTraderTab() {
        var tab = new Tab("Regional Day-Trader");

        if (!featureGate.isFeatureAvailable(FeatureSet.REGIONAL_DAY_TRADER,
                SubscriptionTier.PROFESSIONAL)) {
            tab.setContent(new FeatureLockedPane(
                    "Regional Day-Trader", "Professional"));
            return tab;
        }

        // --- Route selection ---
        var routeBox = new HBox(10);
        routeBox.setPadding(new Insets(5));
        routeBox.setAlignment(Pos.CENTER_LEFT);
        var fromCombo = new ComboBox<String>();
        fromCombo.getItems().addAll("Jita", "Amarr", "Dodixie", "Rens", "Hek");
        fromCombo.setValue("Jita");
        var toCombo = new ComboBox<String>();
        toCombo.getItems().addAll("Jita", "Amarr", "Dodixie", "Rens", "Hek");
        toCombo.setValue("Amarr");
        var scanBtn = new Button("Find Opportunities");
        routeBox.getChildren().addAll(
                new Label("From:"), fromCombo,
                new Label("To:"), toCombo,
                scanBtn
        );

        // --- Settings ---
        var settingsBox = new HBox(10);
        settingsBox.setPadding(new Insets(5));
        settingsBox.setAlignment(Pos.CENTER_LEFT);
        var cargoField = new TextField("60000");
        cargoField.setPrefWidth(80);
        var budgetField = new TextField("500000000");
        budgetField.setPrefWidth(120);
        var minMarginField = new TextField("10");
        minMarginField.setPrefWidth(60);

        // Shipping rate controls
        var includeShippingCheck = new CheckBox("Include Shipping");
        var shippingRateField = new TextField("850");
        shippingRateField.setPrefWidth(80);
        shippingRateField.setPromptText("ISK/m3");
        shippingRateField.setDisable(true);
        includeShippingCheck.selectedProperty().addListener((obs, oldVal, newVal) ->
                shippingRateField.setDisable(!newVal));

        settingsBox.getChildren().addAll(
                new Label("Cargo (m3):"), cargoField,
                new Label("Budget:"), budgetField,
                new Label("Min Margin %:"), minMarginField,
                new Separator(Orientation.VERTICAL),
                includeShippingCheck,
                new Label("ISK/m3:"), shippingRateField
        );

        // --- Search / filter field ---
        var searchField = new TextField();
        searchField.setPromptText("Search items...");
        searchField.setPrefWidth(300);
        var searchBar = new HBox(10, new Label("Filter:"), searchField);
        searchBar.setPadding(new Insets(5));
        searchBar.setAlignment(Pos.CENTER_LEFT);

        // --- Opportunities table ---
        var filteredList = new FilteredList<>(regionalOpportunities, p -> true);
        searchField.textProperty().addListener((obs, oldVal, newVal) -> {
            String filterText = newVal == null ? "" : newVal.toLowerCase();
            filteredList.setPredicate(opp -> {
                if (filterText.isEmpty()) return true;
                return opp.typeName().toLowerCase().contains(filterText);
            });
        });
        var sortedList = new SortedList<>(filteredList);

        var table = new TableView<TradeOpportunity>();
        sortedList.comparatorProperty().bind(table.comparatorProperty());
        table.setItems(sortedList);

        var itemCol = new TableColumn<TradeOpportunity, String>("Item");
        itemCol.setPrefWidth(180);
        itemCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().typeName()));

        var buyPriceCol = new TableColumn<TradeOpportunity, String>("Buy (Source)");
        buyPriceCol.setPrefWidth(110);
        buyPriceCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().buyPrice())));
        buyPriceCol.setComparator(TraderWorkspace::compareIskStrings);

        var sellPriceCol = new TableColumn<TradeOpportunity, String>("Sell (Dest)");
        sellPriceCol.setPrefWidth(110);
        sellPriceCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().sellPrice())));
        sellPriceCol.setComparator(TraderWorkspace::compareIskStrings);

        var profitCol = new TableColumn<TradeOpportunity, String>("Profit/Unit");
        profitCol.setPrefWidth(100);
        profitCol.setCellValueFactory(c -> {
            double profit = c.getValue().sellPrice() - c.getValue().buyPrice();
            return new SimpleStringProperty(IskFormatter.formatRaw(profit));
        });
        profitCol.setComparator(TraderWorkspace::compareIskStrings);

        var marginCol = new TableColumn<TradeOpportunity, String>("Margin %");
        marginCol.setPrefWidth(75);
        marginCol.setCellValueFactory(c -> new SimpleStringProperty(
                String.format("%.1f%%", c.getValue().margin() * 100.0)));

        var volumeCol = new TableColumn<TradeOpportunity, Number>("Volume");
        volumeCol.setPrefWidth(70);
        volumeCol.setCellValueFactory(c -> new SimpleLongProperty(c.getValue().volume()));

        var dailyVolCol = new TableColumn<TradeOpportunity, Number>("Daily Vol");
        dailyVolCol.setPrefWidth(70);
        dailyVolCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().dailyVolume()));

        var totalProfitCol = new TableColumn<TradeOpportunity, String>("Total Profit");
        totalProfitCol.setPrefWidth(120);
        totalProfitCol.setCellValueFactory(c -> {
            double total = (c.getValue().sellPrice() - c.getValue().buyPrice()) * c.getValue().volume();
            return new SimpleStringProperty(IskFormatter.formatRaw(total));
        });
        totalProfitCol.setComparator(TraderWorkspace::compareIskStrings);

        // Security column — derive a rough security status from the region
        var securityCol = new TableColumn<TradeOpportunity, String>("Security");
        securityCol.setPrefWidth(65);
        securityCol.setCellValueFactory(c -> new SimpleStringProperty("High"));

        // ISK/m3 column
        var iskPerM3Col = new TableColumn<TradeOpportunity, String>("ISK/m3");
        iskPerM3Col.setPrefWidth(90);
        iskPerM3Col.setCellValueFactory(c -> {
            double profit = c.getValue().sellPrice() - c.getValue().buyPrice();
            // Assume ~1 m3 per unit as a default; real data would have actual volume
            return new SimpleStringProperty(IskFormatter.formatRaw(profit));
        });
        iskPerM3Col.setComparator(TraderWorkspace::compareIskStrings);

        // Shipping cost column
        var shippingCostCol = new TableColumn<TradeOpportunity, String>("Shipping Cost");
        shippingCostCol.setPrefWidth(100);
        shippingCostCol.setCellValueFactory(c -> {
            if (!includeShippingCheck.isSelected()) {
                return new SimpleStringProperty("--");
            }
            double rate;
            try {
                rate = Double.parseDouble(shippingRateField.getText().replace(",", ""));
            } catch (NumberFormatException ex) {
                rate = 0;
            }
            // Shipping cost = rate * volume (assume 1 m3/unit default)
            double cost = rate * c.getValue().volume();
            return new SimpleStringProperty(IskFormatter.formatRaw(cost));
        });
        shippingCostCol.setComparator(TraderWorkspace::compareIskStrings);

        // In Transit count column
        var inTransitCol = new TableColumn<TradeOpportunity, Number>("In Transit");
        inTransitCol.setPrefWidth(70);
        inTransitCol.setCellValueFactory(c -> {
            long count = inTransitItems.stream()
                    .filter(t -> t.typeId() == c.getValue().typeId())
                    .count();
            return new SimpleLongProperty(count);
        });

        table.getColumns().addAll(itemCol, buyPriceCol, sellPriceCol, profitCol, marginCol,
                volumeCol, dailyVolCol, totalProfitCol, securityCol, iskPerM3Col,
                shippingCostCol, inTransitCol);
        table.setPlaceholder(new Label("Select route and click Find Opportunities"));

        // Context menu for regional table rows
        table.setRowFactory(tv -> {
            var row = new TableRow<TradeOpportunity>();
            var contextMenu = createTradeContextMenu(row, favoriteTypeIds, blacklistTypeIds);
            row.setContextMenu(contextMenu);
            return row;
        });

        // --- In Transit tab ---
        var inTransitTextArea = new TextArea();
        inTransitTextArea.setPromptText("Paste item names or type IDs here, one per line...");
        inTransitTextArea.setPrefRowCount(5);

        var addInTransitBtn = new Button("Add");
        var clearInTransitBtn = new Button("Clear");

        var inTransitTable = new TableView<TradeOpportunity>();
        var itItemCol = new TableColumn<TradeOpportunity, String>("Item");
        itItemCol.setPrefWidth(200);
        itItemCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().typeName()));
        var itBuyCol = new TableColumn<TradeOpportunity, String>("Buy Price");
        itBuyCol.setPrefWidth(110);
        itBuyCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().buyPrice())));
        var itSellCol = new TableColumn<TradeOpportunity, String>("Sell Price");
        itSellCol.setPrefWidth(110);
        itSellCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().sellPrice())));
        var itProfitCol = new TableColumn<TradeOpportunity, String>("Profit");
        itProfitCol.setPrefWidth(110);
        itProfitCol.setCellValueFactory(c -> {
            double profit = (c.getValue().sellPrice() - c.getValue().buyPrice()) * c.getValue().volume();
            return new SimpleStringProperty(IskFormatter.formatRaw(profit));
        });
        inTransitTable.getColumns().addAll(itItemCol, itBuyCol, itSellCol, itProfitCol);
        inTransitTable.setItems(inTransitItems);
        inTransitTable.setPlaceholder(new Label("No items in transit"));

        addInTransitBtn.setOnAction(e -> {
            String text = inTransitTextArea.getText();
            if (text == null || text.isBlank()) return;
            // Match pasted items against current regional opportunities by name
            String[] lines = text.split("\\n");
            for (String line : lines) {
                String trimmed = line.trim().toLowerCase();
                if (trimmed.isEmpty()) continue;
                for (var opp : regionalOpportunities) {
                    if (opp.typeName().toLowerCase().contains(trimmed)) {
                        if (!inTransitItems.contains(opp)) {
                            inTransitItems.add(opp);
                        }
                        break;
                    }
                }
            }
            inTransitTextArea.clear();
            table.refresh(); // Refresh in-transit column
        });

        clearInTransitBtn.setOnAction(e -> {
            inTransitItems.clear();
            table.refresh();
        });

        var inTransitBtnBar = new HBox(5, addInTransitBtn, clearInTransitBtn);
        inTransitBtnBar.setPadding(new Insets(5));
        var inTransitContent = new VBox(5, inTransitTextArea, inTransitBtnBar, inTransitTable);
        VBox.setVgrow(inTransitTable, Priority.ALWAYS);
        inTransitContent.setPadding(new Insets(5));

        // --- Shopping list panel (TreeView grouped by system) ---
        var shoppingTree = new TreeView<String>();
        var shoppingRoot = new TreeItem<String>("Shopping List");
        shoppingRoot.setExpanded(true);
        shoppingTree.setRoot(shoppingRoot);
        shoppingTree.setShowRoot(true);

        // --- Side TabPane for In Transit / Shopping List ---
        var sideTabPane = new TabPane();
        sideTabPane.setTabClosingPolicy(TabPane.TabClosingPolicy.UNAVAILABLE);
        sideTabPane.setPrefWidth(300);
        var inTransitTab = new Tab("In Transit", inTransitContent);
        var shoppingListTab = new Tab("Shopping List", shoppingTree);
        sideTabPane.getTabs().addAll(inTransitTab, shoppingListTab);

        // --- Trip summary ---
        var summaryBox = new HBox(20);
        summaryBox.setPadding(new Insets(8));
        summaryBox.setStyle("-fx-background-color: #252526;");
        totalInvestmentLabel = new Label("Total Investment: --");
        totalProfitLabel = new Label("Total Profit: --");
        roiLabel = new Label("ROI: --");
        cargoUsedLabel = new Label("Cargo Used: --");
        summaryBox.getChildren().addAll(totalInvestmentLabel, totalProfitLabel, roiLabel, cargoUsedLabel);

        // --- Scan action ---
        scanBtn.setOnAction(e -> {
            scanBtn.setDisable(true);
            double minMargin;
            double maxCargo;
            double budget;
            try {
                minMargin = Double.parseDouble(minMarginField.getText()) / 100.0;
                maxCargo = Double.parseDouble(cargoField.getText().replace(",", ""));
                budget = Double.parseDouble(budgetField.getText().replace(",", ""));
            } catch (NumberFormatException ex) {
                scanBtn.setDisable(false);
                return;
            }
            int fromRegion = hubToRegionId(fromCombo.getValue());
            int toRegion = hubToRegionId(toCombo.getValue());

            double shippingRate = 0;
            if (includeShippingCheck.isSelected()) {
                try {
                    shippingRate = Double.parseDouble(shippingRateField.getText().replace(",", ""));
                } catch (NumberFormatException ignored) {
                    // default to 0
                }
            }
            final double finalShippingRate = shippingRate;

            Thread.ofVirtual().name("trader-regional-scan").start(() ->
                    dataService.scanRegionalTrades(fromRegion, toRegion, minMargin, maxCargo, budget)
                            .thenAccept(data -> Platform.runLater(() -> {
                                regionalOpportunities.setAll(data);
                                updateRegionalSummary(data, finalShippingRate);
                                updateShoppingTree(shoppingRoot, data, fromCombo.getValue());
                                scanBtn.setDisable(false);
                            }))
                            .exceptionally(ex -> {
                                Platform.runLater(() -> {
                                    log.error("Failed to scan regional trades", ex);
                                    scanBtn.setDisable(false);
                                });
                                return null;
                            })
            );
        });

        // --- Main layout ---
        var tableContainer = new VBox(searchBar, table);
        VBox.setVgrow(table, Priority.ALWAYS);

        var centerSplit = new SplitPane();
        centerSplit.setOrientation(Orientation.HORIZONTAL);
        centerSplit.setDividerPositions(0.7);
        centerSplit.getItems().addAll(tableContainer, sideTabPane);
        SplitPane.setResizableWithParent(sideTabPane, false);

        var root = new VBox(routeBox, settingsBox, centerSplit, summaryBox);
        VBox.setVgrow(centerSplit, Priority.ALWAYS);

        tab.setContent(root);
        return tab;
    }

    // -----------------------------------------------------------------------
    // Context Menu
    // -----------------------------------------------------------------------

    private ContextMenu createTradeContextMenu(TableRow<TradeOpportunity> row,
                                                ObservableList<Integer> favorites,
                                                ObservableList<Integer> blacklist) {
        var contextMenu = new ContextMenu();

        var openInGameItem = new MenuItem("Open in Game");
        openInGameItem.setOnAction(e -> {
            var opp = row.getItem();
            if (opp != null) {
                // Copy showinfo link to clipboard for in-game use
                String showInfo = "showinfo:" + opp.typeId();
                var content = new ClipboardContent();
                content.putString(showInfo);
                Clipboard.getSystemClipboard().setContent(content);
                log.info("Copied showinfo link for {} to clipboard", opp.typeName());
            }
        });

        var addToFavoritesItem = new MenuItem("Add to Favorites");
        addToFavoritesItem.setOnAction(e -> {
            var opp = row.getItem();
            if (opp != null && !favorites.contains(opp.typeId())) {
                favorites.add(opp.typeId());
            }
        });

        var addToBlacklistItem = new MenuItem("Add to Blacklist");
        addToBlacklistItem.setOnAction(e -> {
            var opp = row.getItem();
            if (opp != null && !blacklist.contains(opp.typeId())) {
                blacklist.add(opp.typeId());
            }
        });

        contextMenu.getItems().addAll(openInGameItem, addToFavoritesItem, addToBlacklistItem);
        return contextMenu;
    }

    // -----------------------------------------------------------------------
    // Shopping Tree
    // -----------------------------------------------------------------------

    private void updateShoppingTree(TreeItem<String> root, List<TradeOpportunity> data, String sourceHub) {
        root.getChildren().clear();

        // Group all items under the source hub system
        var systemNode = new TreeItem<>(sourceHub + " - Buy List");
        systemNode.setExpanded(true);

        for (var opp : data) {
            long qty = opp.volume();
            String label = String.format("%s x%d  -  %s",
                    opp.typeName(), qty, IskFormatter.format(opp.buyPrice() * qty));
            systemNode.getChildren().add(new TreeItem<>(label));
        }

        double totalCost = data.stream()
                .mapToDouble(o -> o.buyPrice() * o.volume())
                .sum();
        var summaryNode = new TreeItem<>(String.format("Total: %s (%d items)",
                IskFormatter.format(totalCost), data.size()));

        root.getChildren().addAll(systemNode, summaryNode);
    }

    // -----------------------------------------------------------------------
    // Regional Summary
    // -----------------------------------------------------------------------

    private void updateRegionalSummary(List<TradeOpportunity> data, double shippingRate) {
        double totalInvest = 0;
        double totalProfit = 0;
        double totalShipping = 0;
        for (var opp : data) {
            totalInvest += opp.buyPrice() * opp.volume();
            double unitProfit = opp.sellPrice() - opp.buyPrice();
            totalProfit += unitProfit * opp.volume();
            // Shipping cost: rate * volume (assume 1 m3/unit)
            totalShipping += shippingRate * opp.volume();
        }
        double netProfit = totalProfit - totalShipping;
        totalInvestmentLabel.setText("Total Investment: " + IskFormatter.format(totalInvest));
        totalProfitLabel.setText("Total Profit: " + IskFormatter.format(netProfit));
        double roi = totalInvest > 0 ? (netProfit / totalInvest) * 100.0 : 0;
        roiLabel.setText(String.format("ROI: %.1f%%", roi));
        cargoUsedLabel.setText(String.format("Cargo Used: %,d m3",
                data.stream().mapToLong(TradeOpportunity::volume).sum()));
    }

    // -----------------------------------------------------------------------
    // Utility
    // -----------------------------------------------------------------------

    private static int hubToRegionId(String hub) {
        return switch (hub) {
            case "Jita" -> 10000002;
            case "Amarr" -> 10000043;
            case "Dodixie" -> 10000032;
            case "Rens" -> 10000030;
            case "Hek" -> 10000042;
            default -> 10000002;
        };
    }

    /**
     * Comparator for ISK-formatted strings so table columns sort numerically.
     */
    private static int compareIskStrings(String a, String b) {
        try {
            double va = Double.parseDouble(a.replace(",", "").replace("%", "").replace("--", "0").trim());
            double vb = Double.parseDouble(b.replace(",", "").replace("%", "").replace("--", "0").trim());
            return Double.compare(va, vb);
        } catch (NumberFormatException e) {
            return a.compareTo(b);
        }
    }

    @Override
    public String getTitle() { return "Trader"; }

    @Override
    public void onActivated() { log.debug("Trader workspace activated"); }

    @Override
    public void onCharacterChanged(int characterId) {
        log.debug("Trader: character changed to {}", characterId);
        if (characterId <= 0) {
            stationOpportunities.clear();
            regionalOpportunities.clear();
            inTransitItems.clear();
        }
    }
}

