package com.sampleapp.esi.api;

import com.sampleapp.esi.EsiClient;
import com.sampleapp.esi.EsiResponse;
import com.sampleapp.esi.dto.*;
import com.fasterxml.jackson.core.type.TypeReference;

import java.util.List;
import java.util.concurrent.CompletableFuture;

public class MarketApi {

    private final EsiClient client;

    public MarketApi(EsiClient client) {
        this.client = client;
    }

    /** GET /v2/characters/{characterId}/orders/ */
    public CompletableFuture<EsiResponse<List<CharacterOrder>>> getCharacterOrders(int characterId, String token) {
        return client.get(
                "/v2/characters/" + characterId + "/orders/",
                new TypeReference<>() {},
                token
        );
    }

    /** GET /v1/characters/{characterId}/orders/history/ — paginated */
    public CompletableFuture<List<CharacterOrder>> getCharacterOrderHistory(int characterId, String token) {
