15	import com.sampleapp.core.model.UserCharacter;
16	import com.google.inject.Guice;
17	import com.google.inject.Injector;
18	import javafx.application.Application;
19	import javafx.application.Platform;
20	import javafx.scene.Scene;
21	import javafx.stage.Stage;
22	import javafx.stage.StageStyle;
23	import org.slf4j.Logger;
24	import org.slf4j.LoggerFactory;
