26	import java.nio.file.Files;
27	import java.nio.file.Path;
28	import java.util.List;
29	
30	/**
31	 * Main entry point for the Sample App application.
32	 * Handles initialization sequence: splash -> config -> database -> UI.
33	 */
34	public class SampleApp extends Application {
35	
36	    private static final Logger log = LoggerFactory.getLogger(SampleApp.class);
37	    private static final String APP_VERSION = "2.1.245";
38	
39	    private AppState appState;
40	    private Injector injector;
41	    private Path dataDir;
42	    private boolean devMode;
43	    private boolean resetConfig;
44	    private boolean portableMode;
45	
46	    // Service references for shutdown
47	    private DatabaseManager databaseManager;
48	    private StationStatsDatabase stationStatsDatabase;
49	    private SyncService syncService;
50	    private StationTradeService stationTradeService;
51	
52	    @Override
53	    public void init() {
54	        parseArguments(getParameters().getRaw());
55	    }
56	
57	    @Override
58	    public void start(Stage primaryStage) {
59	        log.info("Starting Sample App v{}", APP_VERSION);
60	
61	        // Show splash screen
62	        var splashStage = new Stage(StageStyle.UNDECORATED);
63	        var splashScreen = new SplashScreen();
64	        var splashScene = new Scene(splashScreen, 470, 270);
65	        splashScene.getStylesheets().add(
66	                getClass().getResource("/css/dark-theme.css").toExternalForm());
67	        splashStage.setScene(splashScene);
68	        splashStage.setTitle("Sample App - Loading");
69	        splashStage.centerOnScreen();
70	        splashStage.show();
71	
72	        // Run initialization on background thread
73	        Thread.ofVirtual().name("init").start(() -> {
74	            try {
75	                // Step 1: Resolve data directory
76	                splashScreen.updateStatus("Resolving data directory...", 0.05);
77	                resolveDataDir();
78	
79	                // Step 2: Load configuration
80	                splashScreen.updateStatus("Loading configuration...", 0.15);
81	                var config = loadConfig();
82	
83	                // Step 3: Initialize Guice
84	                splashScreen.updateStatus("Initializing dependency injection...", 0.25);
85	                var module = new AppModule(config, dataDir, devMode);
86	                injector = Guice.createInjector(module);
87	                appState = injector.getInstance(AppState.class);
88	
89	                // Step 4: Initialize databases
90	                splashScreen.updateStatus("Initializing databases...", 0.40);
91	                initializeDatabases();
92	
93	                // Step 4b: Load SDE if type cache is empty
94	                loadSdeIfNeeded(splashScreen);
95	
96	                // Step 4c: Populate in-memory ItemTypeCache from DB
97	                splashScreen.updateStatus("Loading item type cache...", 0.52);
98	                populateItemTypeCache();
99	
100	                // Step 5: Initialize feature gate and load characters
101	                splashScreen.updateStatus("Loading characters...", 0.55);
102	                initializeFeatureGate();
103	                loadCharacters();
104	
105	                // Step 6: Create main window
106	                splashScreen.updateStatus("Building user interface...", 0.70);
107	                Platform.runLater(() -> {
108	                    try {
109	                        createMainWindow(primaryStage, splashStage, splashScreen);
110	                    } catch (Exception e) {
111	                        log.error("Failed to create main window", e);
112	                        showErrorAndExit(e);
113	                    }
114	                });
115	            } catch (Exception e) {
116	                log.error("Initialization failed", e);
117	                Platform.runLater(() -> showErrorAndExit(e));
118	            }
119	        });
120	    }
121	
122	    private void createMainWindow(Stage primaryStage, Stage splashStage, SplashScreen splashScreen) {
123	        splashScreen.updateStatus("Preparing main window...", 0.85);
124	
125	        var mainWindow = injector.getInstance(com.sampleapp.ui.MainWindow.class);
126	        var scene = new Scene(mainWindow, 1280, 800);
127	        scene.getStylesheets().add(
128	                getClass().getResource("/css/dark-theme.css").toExternalForm());
129	
130	        primaryStage.setScene(scene);
131	        primaryStage.setTitle("Sample App v" + APP_VERSION);
132	        primaryStage.setMinWidth(960);
133	        primaryStage.setMinHeight(600);
134	
135	        // Step 7: Start background services
136	        splashScreen.updateStatus("Starting background services...", 0.95);
137	        startBackgroundServices();
138	
139	        splashScreen.updateStatus("Ready!", 1.0);
140	
141	        // Close splash and show main window
142	        splashStage.close();
143	        primaryStage.show();
144	
145	        log.info("Sample App started successfully");
146	    }
147	
148	    @Override
149	    public void stop() {
150	        log.info("Shutting down Sample App...");
151	
152	        // Save workspace layout on shutdown
153	        if (injector != null) {
154	            try {
155	                var mainWindow = injector.getInstance(com.sampleapp.ui.MainWindow.class);
156	                mainWindow.saveLayoutOnShutdown();
157	            } catch (Exception e) {
158	                log.debug("Failed to save layout on shutdown", e);
159	            }
160	        }
161	
162	        // Stop background services
163	        if (syncService != null) {
164	            syncService.shutdown();
165	        }
166	        if (stationTradeService != null) {
167	            stationTradeService.shutdown();
168	        }
169	
170	        // Close databases
171	        if (stationStatsDatabase != null) {
172	            stationStatsDatabase.close();
173	        }
174	        if (databaseManager != null) {
175	            databaseManager.close();
176	        }
177	
178	        if (appState != null) {
179	            appState.shutdown();
180	        }
181	
182	        log.info("Sample App shutdown complete");
183	    }
184	
185	    private void parseArguments(List<String> args) {
186	        for (String arg : args) {
187	            if (arg.startsWith("--data-dir=")) {
188	                dataDir = Path.of(arg.substring("--data-dir=".length()));
189	            } else if ("--dev".equals(arg)) {
190	                devMode = true;
191	                log.info("Developer mode enabled");
192	            } else if ("--reset-config".equals(arg)) {
193	                resetConfig = true;
194	                log.info("Configuration reset requested");
195	            } else if ("--portable".equals(arg)) {
196	                portableMode = true;
197	                log.info("Portable mode enabled");
198	            }
199	        }
200	    }
201	
202	    private void resolveDataDir() {
203	        if (dataDir == null) {
204	            if (portableMode) {
205	                dataDir = Path.of(System.getProperty("user.dir"), ".sampleapp");
206	            } else {
207	                dataDir = Path.of(System.getProperty("user.home"), ".sampleapp");
208	            }
209	        }
210	        try {
211	            Files.createDirectories(dataDir);
212	            Files.createDirectories(dataDir.resolve("logs"));
213	            Files.createDirectories(dataDir.resolve("cache"));
214	            Files.createDirectories(dataDir.resolve("db"));
215	            log.info("Data directory: {}", dataDir);
216	        } catch (Exception e) {
217	            throw new RuntimeException("Failed to create data directory: " + dataDir, e);
218	        }
219	    }
220	
221	    private AppConfig loadConfig() {
222	        var configPath = dataDir.resolve("config.json");
223	        if (resetConfig) {
224	            try {
225	                Files.deleteIfExists(configPath);
226	                log.info("Configuration reset to defaults");
227	            } catch (Exception e) {
228	                log.warn("Failed to delete config file", e);
229	            }
230	        }
231	        return AppConfig.load(configPath);
232	    }
233	
234	    private void initializeDatabases() {
235	        log.info("Initializing H2 databases in {}", dataDir.resolve("db"));
236	
237	        databaseManager = injector.getInstance(DatabaseManager.class);
238	        databaseManager.initialize();
239	
240	        stationStatsDatabase = injector.getInstance(StationStatsDatabase.class);
241	        stationStatsDatabase.initialize();
242	
243	        log.info("Databases initialized successfully");
244	    }
245	
246	    private void loadSdeIfNeeded(SplashScreen splashScreen) {
247	        try {
248	            var typeCacheRepo = injector.getInstance(TypeCacheRepository.class);
249	            if (typeCacheRepo.count() == 0) {
250	                splashScreen.updateStatus("Loading static data...", 0.50);
251	                Path sdeDir = resolveSdeDir();
252	                if (sdeDir != null && Files.exists(sdeDir)) {
253	                    var marketGroupRepo = injector.getInstance(MarketGroupRepository.class);
254	                    var dbManager = injector.getInstance(DatabaseManager.class);
255	                    var sdeLoader = new SdeLoader(typeCacheRepo, marketGroupRepo, dbManager);
256	                    sdeLoader.loadAll(sdeDir);
257	                    log.info("SDE data loaded successfully");
258	                } else {
259	                    log.warn("SDE directory not found - type names will be unavailable. " +
260	                            "Checked: {}/sde, D:\\Eve_data\\sde, {}/.sampleapp/sde",
261	                            dataDir, System.getProperty("user.home"));
262	                }
263	            } else {
264	                log.info("TypeCache already populated ({} entries), skipping SDE load",
265	                        typeCacheRepo.count());
266	            }
267	        } catch (Exception e) {
268	            log.error("Failed to load SDE data (non-fatal, continuing startup)", e);
269	        }
270	    }
271	
272	    /**
273	     * Resolves the SDE directory by checking multiple candidate locations.
274	     */
275	    private Path resolveSdeDir() {
276	        // 1. dataDir/sde/
277	        Path candidate = dataDir.resolve("sde");
278	        if (Files.exists(candidate.resolve("types.yaml"))) {
279	            log.info("Using SDE directory: {}", candidate);
280	            return candidate;
281	        }
282	
283	        // 2. D:\Eve_data\sde\ (shared C# data directory)
284	        candidate = Path.of("D:", "Eve_data", "sde");
285	        if (Files.exists(candidate.resolve("types.yaml"))) {
286	            log.info("Using SDE directory: {}", candidate);
287	            return candidate;
288	        }
289	
290	        // 3. User home ~/.sampleapp/sde/
291	        candidate = Path.of(System.getProperty("user.home"), ".sampleapp", "sde");
292	        if (Files.exists(candidate.resolve("types.yaml"))) {
293	            log.info("Using SDE directory: {}", candidate);
294	            return candidate;
295	        }
296	
297	        return null;
298	    }
299	
300	    private void initializeFeatureGate() {
301	        log.info("Initializing feature gates (devMode={})", devMode);
302	        // UI FeatureGate is auto-configured by Guice injection (takes AppConfig + @DevMode)
303	        injector.getInstance(com.sampleapp.core.app.FeatureGate.class);
304	
305	        // Subscription FeatureGate (used by StationTradeService) - enable all in dev mode
306	        var subscriptionGate = injector.getInstance(com.sampleapp.core.subscription.FeatureGate.class);
307	        if (devMode) {
308	            subscriptionGate.enableAll();
309	        }
310	    }
311	
312	    private void populateItemTypeCache() {
313	        try {
314	            var typeCacheRepo = injector.getInstance(TypeCacheRepository.class);
315	            var itemTypeCache = injector.getInstance(ItemTypeCache.class);
316	            var rows = typeCacheRepo.findAll();
317	            var items = rows.stream()
318	                    .map(r -> new ItemType(
319	                            r.typeId(), r.name(),
320	                            r.groupId() != null ? r.groupId() : 0,
321	                            r.categoryId() != null ? r.categoryId() : 0,
322	                            r.volume(), r.packagedVolume(), r.published()))
