343	    @Override
344	    public CompletableFuture<List<TradeOpportunity>> scanStationTrades(long stationId, double minProfit, int minVolume) {
345	        return CompletableFuture.supplyAsync(() -> {
346	            log.debug("scanStationTrades for station {} minProfit={} minVolume={}", stationId, minProfit, minVolume);
347	            try {
348	                int regionId = stationToRegion(stationId);
349	                log.info("Fetching region orders for region {} (station {})...", regionId, stationId);
350	
351	                // Fetch ALL orders in the region from ESI (paginated)
352	                List<RegionOrder> allOrders = esiClient.market.getRegionOrders(regionId).join();
353	                log.info("Fetched {} total region orders, filtering to station {}", allOrders.size(), stationId);
354	
355	                // Filter to orders at this station only
356	                List<RegionOrder> stationOrders = allOrders.stream()
357	                        .filter(o -> o.locationId() == stationId)
358	                        .toList();
359	
360	                // Group by typeId
361	                Map<Integer, List<RegionOrder>> byType = stationOrders.stream()
362	                        .collect(Collectors.groupingBy(RegionOrder::typeId));
363	
364	                List<TradeOpportunity> opportunities = new ArrayList<>();
365	                for (var entry : byType.entrySet()) {
366	                    int typeId = entry.getKey();
367	                    var orders = entry.getValue();
368	
369	                    // Find best buy (highest buy order) and best sell (lowest sell order)
370	                    OptionalDouble bestBuy = orders.stream()
371	                            .filter(RegionOrder::isBuyOrder)
372	                            .mapToDouble(RegionOrder::price)
373	                            .max();
374	                    OptionalDouble bestSell = orders.stream()
375	                            .filter(o -> !o.isBuyOrder())
376	                            .mapToDouble(RegionOrder::price)
377	                            .min();
378	
379	                    if (bestBuy.isEmpty() || bestSell.isEmpty()) continue;
380	
381	                    double buyPrice = bestBuy.getAsDouble();
382	                    double sellPrice = bestSell.getAsDouble();
383	                    double profit = sellPrice - buyPrice;
384	                    double margin = sellPrice > 0 ? profit / sellPrice : 0;
385	
386	                    if (profit < minProfit) continue;
387	                    if (margin <= 0) continue;
388	
389	                    // Count total sell volume for this type
390	                    long sellVolume = orders.stream()
391	                            .filter(o -> !o.isBuyOrder())
392	                            .mapToLong(RegionOrder::volumeRemain)
393	                            .sum();
394	
395	                    // Count number of sell orders (competition)
396	                    long orderCount = orders.stream()
397	                            .filter(o -> !o.isBuyOrder())
398	                            .count();
399	
400	                    String typeName = typeCacheRepo.findNameById(typeId).orElse("Type #" + typeId);
401	
402	                    opportunities.add(new TradeOpportunity(
403	                            typeId, typeName, buyPrice, sellPrice, margin,
404	                            orderCount, (double) sellVolume
405	                    ));
406	                }
407	
408	                // Cache the prices we found for future use
409	                for (var opp : opportunities) {
410	                    stationPriceRepo.upsert(opp.typeId(), stationId, opp.buyPrice(), opp.sellPrice());
411	                }
412	
413	                opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
414	                log.info("Found {} station trade opportunities", opportunities.size());
415	                return opportunities;
416	            } catch (Exception e) {
417	                log.error("Failed to scan station trades for station {}", stationId, e);
418	                return List.of();
419	            }
420	        });
421	    }
