423	    @Override
424	    public CompletableFuture<List<TradeOpportunity>> scanRegionalTrades(int fromRegionId, int toRegionId,
425	                                                                        double minMargin, double maxCargo, double budget) {
426	        return CompletableFuture.supplyAsync(() -> {
427	            log.debug("scanRegionalTrades from {} to {} minMargin={} maxCargo={} budget={}",
428	                    fromRegionId, toRegionId, minMargin, maxCargo, budget);
429	            try {
430	                log.info("Fetching region orders for regions {} and {}...", fromRegionId, toRegionId);
431	
432	                // Fetch orders from both regions in parallel
433	                var fromOrdersFuture = esiClient.market.getRegionOrders(fromRegionId);
434	                var toOrdersFuture = esiClient.market.getRegionOrders(toRegionId);
435	
436	                List<RegionOrder> fromOrders = fromOrdersFuture.join();
437	                List<RegionOrder> toOrders = toOrdersFuture.join();
438	                log.info("Fetched {} orders from source region, {} from destination region",
439	                        fromOrders.size(), toOrders.size());
440	
441	                // Build price maps: for source, find lowest sell price per type
442	                Map<Integer, Double> sourceSellPrices = new HashMap<>();
443	                Map<Integer, Long> sourceVolumes = new HashMap<>();
444	                for (var order : fromOrders) {
445	                    if (order.isBuyOrder()) continue; // skip buy orders
446	                    sourceSellPrices.merge(order.typeId(), order.price(), Math::min);
447	                    sourceVolumes.merge(order.typeId(), (long) order.volumeRemain(), Long::sum);
448	                }
449	
450	                // For destination, find lowest sell price (what we undercut)
451	                Map<Integer, Double> destSellPrices = new HashMap<>();
452	                for (var order : toOrders) {
453	                    if (order.isBuyOrder()) continue;
454	                    destSellPrices.merge(order.typeId(), order.price(), Math::min);
455	                }
456	
457	                List<TradeOpportunity> opportunities = new ArrayList<>();
458	                for (var entry : sourceSellPrices.entrySet()) {
459	                    int typeId = entry.getKey();
460	                    double buyCost = entry.getValue();
461	                    Double sellRevenue = destSellPrices.get(typeId);
462	
463	                    if (sellRevenue == null || buyCost <= 0 || sellRevenue <= 0) continue;
464	
465	                    double margin = (sellRevenue - buyCost) / sellRevenue;
466	                    if (margin < minMargin) continue;
467	
468	                    // Check cargo volume constraint
469	                    var typeInfo = typeCacheRepo.findById(typeId);
470	                    if (typeInfo.isPresent() && maxCargo > 0) {
471	                        double vol = typeInfo.get().packagedVolume() > 0
472	                                ? typeInfo.get().packagedVolume()
473	                                : typeInfo.get().volume();
474	                        if (vol > maxCargo) continue;
475	                    }
476	
477	                    // Check budget constraint
478	                    if (budget > 0 && buyCost > budget) continue;
479	
480	                    long volume = sourceVolumes.getOrDefault(typeId, 0L);
481	                    String typeName = typeCacheRepo.findNameById(typeId).orElse("Type #" + typeId);
482	
483	                    opportunities.add(new TradeOpportunity(
484	                            typeId, typeName, buyCost, sellRevenue, margin,
485	                            volume, (double) volume
486	                    ));
487	                }
488	
489	                opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
490	                log.info("Found {} regional trade opportunities", opportunities.size());
491	                return opportunities;
492	            } catch (Exception e) {
493	                log.error("Failed to scan regional trades from {} to {}", fromRegionId, toRegionId, e);
494	                return List.of();
495	            }
496	        });
497	    }
