499	    /**
500	     * Maps well-known trade hub station IDs to their region IDs.
501	     */
502	    private static int stationToRegion(long stationId) {
503	        if (stationId == 60003760L) return 10000002; // Jita -> The Forge
504	        if (stationId == 60008494L) return 10000043; // Amarr -> Domain
505	        if (stationId == 60011866L) return 10000032; // Dodixie -> Sinq Laison
506	        if (stationId == 60004588L) return 10000030; // Rens -> Heimatar
507	        if (stationId == 60005686L) return 10000042; // Hek -> Metropolis
508	        return 10000002; // default to The Forge
509	    }
