657	
658	                // Get fleet wings for wing/squad names
659	                var wingsResp = esiClient.fleets.getFleetWings(fleetId, token).join();
660	                Map<Long, String> wingNames = new HashMap<>();
661	                Map<Long, String> squadNames = new HashMap<>();
662	                if (wingsResp.isSuccess() && wingsResp.data() != null) {
663	                    for (var wing : wingsResp.data()) {
664	                        wingNames.put(wing.id(), wing.name());
665	                        if (wing.squads() != null) {
666	                            for (var squad : wing.squads()) {
667	                                squadNames.put(squad.id(), squad.name());
668	                            }
669	                        }
670	                    }
671	                }
672	
673	                // Resolve character names via universe names
674	                List<Integer> charIds = membersResp.data().stream()
675	                        .map(com.sampleapp.esi.dto.FleetMember::characterId)
676	                        .toList();
677	                Map<Integer, String> charNames = new HashMap<>();
678	                if (!charIds.isEmpty()) {
679	                    try {
680	                        var namesResp = esiClient.universe.getNames(charIds).join();
681	                        if (namesResp.isSuccess() && namesResp.data() != null) {
682	                            for (var name : namesResp.data()) {
683	                                charNames.put(name.id(), name.name());
684	                            }
685	                        }
686	                    } catch (Exception e) {
687	                        log.warn("Failed to resolve fleet member names", e);
688	                    }
689	                }
690	
691	                return membersResp.data().stream()
692	                        .map(m -> new FleetMemberInfo(
693	                                m.characterId(),
694	                                charNames.getOrDefault(m.characterId(), "Character #" + m.characterId()),
695	                                "", // ship name not available from ESI fleet members
696	                                "Ship Type #" + m.shipTypeId(),
697	                                "System #" + m.solarSystemId(),
698	                                m.role() != null ? m.role() : "--",
699	                                squadNames.getOrDefault(m.squadId(), "Squad #" + m.squadId()),
700	                                wingNames.getOrDefault(m.wingId(), "Wing #" + m.wingId())
701	                        ))
702	                        .toList();
703	            } catch (Exception e) {
704	                log.error("Failed to load fleet members for character {}", characterId, e);
705	                return List.of();
