830	    private String resolveLocationNameSync(long locationId) {
831	        if (locationId <= 0) return "Unknown Location";
832	
833	        // Solar system IDs: 30,000,000 - 33,000,000
834	        if (locationId >= 30_000_000 && locationId < 33_000_000) {
835	            try {
836	                var resp = esiClient.universe.getSystem((int) locationId).join();
837	                if (resp.isSuccess() && resp.data() != null) {
838	                    return resp.data().name();
839	                }
840	            } catch (Exception e) {
841	                log.debug("Failed to resolve system name for {}", locationId, e);
842	            }
843	        }
844	
845	        // NPC station IDs: 60,000,000 - 64,000,000
846	        if (locationId >= 60_000_000 && locationId < 64_000_000) {
847	            try {
848	                var resp = esiClient.universe.getStation((int) locationId).join();
849	                if (resp.isSuccess() && resp.data() != null) {
850	                    return resp.data().name();
851	                }
852	            } catch (Exception e) {
853	                log.debug("Failed to resolve station name for {}", locationId, e);
854	            }
855	        }
856	
857	        // Structures: >= 64,000,000 (Upwell structures, requires auth)
858	        if (locationId >= 64_000_000) {
859	            // Try to resolve via any available character token
860	            try {
861	                var characters = characterRepo.findAll();
862	                for (var character : characters) {
863	                    try {
864	                        String token = tokenManager.getValidToken(character.characterId()).join();
865	                        var resp = esiClient.universe.getStructure(locationId, token).join();
866	                        if (resp.isSuccess() && resp.data() != null) {
867	                            return resp.data().name();
868	                        }
869	                    } catch (Exception e) {
870	                        // This character may not have access, try next
871	                        continue;
872	                    }
873	                }
874	            } catch (Exception e) {
875	                log.debug("Failed to resolve structure name for {}", locationId, e);
876	            }
877	            return "Structure " + locationId;
878	        }
879	
880	        // Try universe names API as a fallback for other ID ranges
881	        if (locationId > 0 && locationId <= Integer.MAX_VALUE) {
882	            try {
883	                var resp = esiClient.universe.getNames(List.of((int) locationId)).join();
884	                if (resp.isSuccess() && resp.data() != null && !resp.data().isEmpty()) {
885	                    return resp.data().get(0).name();
886	                }
887	            } catch (Exception e) {
888	                log.debug("Failed to resolve name via universe names for {}", locationId, e);
889	            }
890	        }
891	
892	        return "Location " + locationId;
893	    }
