    @Override
    public CompletableFuture<List<ContractModel>> getPublicContracts(int regionId, String typeFilter) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getPublicContracts for region {} typeFilter={}", regionId, typeFilter);
            try {
                if (regionId <= 0) {
                    log.warn("Invalid region ID for public contracts: {}", regionId);
                    return List.<ContractModel>of();
                }
                List<com.sampleapp.esi.dto.Contract> contracts = esiClient.contracts.getPublicContracts(regionId).join();
                log.info("Fetched {} public contracts from region {}", contracts.size(), regionId);

                return contracts.stream()
                        .filter(c -> typeFilter == null || typeFilter.isEmpty()
                                || (c.type() != null && c.type().replace("_", " ").equalsIgnoreCase(typeFilter)))
                        .limit(500) // Limit to prevent UI overload
                        .map(c -> new ContractModel(
                                c.contractId(),
                                c.type() != null ? c.type().replace("_", " ") : "--",
                                c.status() != null ? c.status() : "--",
                                c.price() != null ? c.price() : 0.0,
                                c.buyout() != null ? c.buyout() : 0.0,
                                c.collateral() != null ? c.collateral() : 0.0,
                                c.reward() != null ? c.reward() : 0.0,
                                c.volume() != null ? c.volume() : 0.0,
                                c.availability() != null ? c.availability() : "--",
                                c.issuerCorporationId(),
                                c.issuerId(),
                                c.dateIssued() != null ? c.dateIssued().toLocalDateTime() : null,
                                c.dateExpired() != null ? c.dateExpired().toLocalDateTime() : null
                        ))
                        .toList();
            } catch (Exception e) {
                log.error("Failed to fetch public contracts for region {}", regionId, e);
                return List.of();
            }
        });
