57	
58	        long elapsed = System.currentTimeMillis() - start;
59	        LOG.info("SDE loading complete in {}ms: {} types, {} groups, {} categories, {} market groups",
60	                elapsed, types, groups, categories, marketGroups);
61	    }
62	
63	    // -------------------------------------------------------------------------
64	    // Types
