66	
67	    private int loadTypes(Path file) {
68	        if (!Files.exists(file)) {
69	            LOG.warn("types.yaml not found at {}", file);
70	            return 0;
71	        }
72	        LOG.info("Loading types from {}", file);
73	
74	        List<TypeCacheRow> batch = new ArrayList<>(BATCH_SIZE);
75	        int totalLoaded = 0;
76	
77	        try (BufferedReader reader = Files.newBufferedReader(file, StandardCharsets.UTF_8)) {
78	            String line;
79	            // Current entry state
80	            Integer currentId = null;
81	            String name = null;
82	            Integer groupId = null;
83	            Integer categoryId = null;
84	            double volume = 0;
85	            boolean published = false;
86	            Integer marketGroupId = null;
87	            double mass = 0;
88	            boolean inName = false; // true when we're inside a "name:" block
89	
90	            while ((line = reader.readLine()) != null) {
91	                if (line.isEmpty()) continue;
92	
93	                // Top-level entry: "1234:"
94	                if (!line.startsWith(" ") && line.endsWith(":")) {
95	                    // Flush previous entry
96	                    if (currentId != null && published) {
97	                        batch.add(new TypeCacheRow(currentId, name != null ? name : "Type #" + currentId,
98	                                groupId, categoryId, volume, volume, published, marketGroupId));
99	                        if (batch.size() >= BATCH_SIZE) {
100	                            typeCacheRepo.bulkLoad(batch);
101	                            totalLoaded += batch.size();
102	                            batch.clear();
103	                            if (totalLoaded % 10000 == 0) {
104	                                LOG.info("  ... loaded {} types so far", totalLoaded);
105	                            }
106	                        }
107	                    }
108	
109	                    // Parse new ID
110	                    String idStr = line.substring(0, line.length() - 1).trim();
111	                    try {
112	                        currentId = Integer.parseInt(idStr);
113	                    } catch (NumberFormatException e) {
114	                        currentId = null;
115	                    }
116	
117	                    // Reset fields
118	                    name = null;
119	                    groupId = null;
120	                    categoryId = null;
121	                    volume = 0;
122	                    published = false;
123	                    marketGroupId = null;
124	                    mass = 0;
125	                    inName = false;
126	                    continue;
127	                }
128	
129	                if (currentId == null) continue;
130	
131	                String trimmed = line.stripLeading();
132	
133	                // Inside "name:" block - look for "en: ..."
134	                if (inName) {
135	                    if (trimmed.startsWith("en:")) {
136	                        name = extractStringValue(trimmed, "en:");
137	                        inName = false;
138	                    } else if (!trimmed.isEmpty() && !line.startsWith("    ")) {
