158	                } else if (trimmed.startsWith("volume:")) {
159	                    volume = parseDoubleValue(trimmed, "volume:");
160	                } else if (trimmed.startsWith("mass:")) {
161	                    mass = parseDoubleValue(trimmed, "mass:");
162	                } else if (trimmed.startsWith("marketGroupID:")) {
163	                    marketGroupId = parseIntValue(trimmed, "marketGroupID:");
164	                }
165	            }
166	
167	            // Flush last entry
168	            if (currentId != null && published) {
169	                batch.add(new TypeCacheRow(currentId, name != null ? name : "Type #" + currentId,
170	                        groupId, categoryId, volume, volume, published, marketGroupId));
171	            }
172	            if (!batch.isEmpty()) {
173	                typeCacheRepo.bulkLoad(batch);
174	                totalLoaded += batch.size();
175	            }
176	
177	        } catch (IOException e) {
178	            LOG.error("Failed to load types.yaml", e);
179	            throw new RuntimeException("Failed to load types.yaml", e);
180	        }
181	
182	        // Now update categoryId from groups table
183	        updateTypeCategoryIds();
184	
185	        LOG.info("Loaded {} published types", totalLoaded);
186	        return totalLoaded;
187	    }
