499	    // -------------------------------------------------------------------------
500	    // YAML value extraction helpers
501	    // -------------------------------------------------------------------------
502	
503	    /**
504	     * Extracts a string value after a key prefix, e.g. "en: Rifter" -> "Rifter".
505	     * Handles both quoted and unquoted values.
506	     */
507	    private String extractStringValue(String line, String key) {
508	        String raw = line.substring(key.length()).trim();
509	        // Remove surrounding quotes if present
510	        if (raw.length() >= 2 &&
511	                ((raw.startsWith("'") && raw.endsWith("'")) ||
512	                 (raw.startsWith("\"") && raw.endsWith("\"")))) {
513	            raw = raw.substring(1, raw.length() - 1);
514	        }
515	        return raw.isEmpty() ? null : raw;
516	    }
517	
518	    /**
519	     * Extracts the raw trimmed value after a key prefix.
520	     */
521	    private String extractRawValue(String line, String key) {
522	        return line.substring(key.length()).trim();
523	    }
524	
525	    /**
526	     * Parses an integer value after a key prefix. Returns null for "null" or unparseable values.
527	     */
528	    private Integer parseIntValue(String line, String key) {
529	        String raw = extractRawValue(line, key);
530	        if (raw.isEmpty() || "null".equals(raw) || "~".equals(raw)) return null;
531	        try {
532	            // Handle values like "18.0" by truncating
533	            if (raw.contains(".")) {
534	                return (int) Double.parseDouble(raw);
535	            }
536	            return Integer.parseInt(raw);
537	        } catch (NumberFormatException e) {
538	            return null;
539	        }
540	    }
541	
542	    /**
543	     * Parses a double value after a key prefix.
544	     */
545	    private double parseDoubleValue(String line, String key) {
546	        String raw = extractRawValue(line, key);
547	        if (raw.isEmpty() || "null".equals(raw) || "~".equals(raw)) return 0;
548	        try {
549	            return Double.parseDouble(raw);
550	        } catch (NumberFormatException e) {
551	            return 0;
552	        }
553	    }
554	
555	    /**
556	     * Executes a batch of SQL statements directly via the DatabaseManager connection.
557	     */
558	    private void batchExecute(String sql, List<Object[]> paramSets) {
559	        if (paramSets.isEmpty()) return;
560	        try (Connection conn = dbManager.getConnection()) {
561	            conn.setAutoCommit(false);
562	            try (PreparedStatement ps = conn.prepareStatement(sql)) {
563	                int count = 0;
564	                for (Object[] params : paramSets) {
565	                    for (int i = 0; i < params.length; i++) {
566	                        if (params[i] == null) {
567	                            ps.setNull(i + 1, java.sql.Types.NULL);
568	                        } else {
569	                            ps.setObject(i + 1, params[i]);
570	                        }
571	                    }
572	                    ps.addBatch();
573	                    count++;
574	                    if (count % 1000 == 0) {
575	                        ps.executeBatch();
576	                    }
577	                }
578	                ps.executeBatch();
579	                conn.commit();
580	            } catch (SQLException e) {
581	                conn.rollback();
582	                throw e;
583	            }
584	        } catch (SQLException e) {
585	            throw new RuntimeException("Batch execute failed: " + sql, e);
586	        }
587	    }
588	}
