package com.sampleapp.data.sde;

import com.sampleapp.data.DatabaseManager;
import com.sampleapp.data.repository.MarketGroupRepository;
import com.sampleapp.data.repository.MarketGroupRepository.MarketGroupRow;
import com.sampleapp.data.repository.TypeCacheRepository;
import com.sampleapp.data.repository.TypeCacheRepository.TypeCacheRow;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.BufferedReader;
import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.SQLException;
import java.util.ArrayList;
import java.util.List;

/**
 * Loads EVE Online Static Data Export (SDE) YAML files into the H2 database.
 * <p>
 * Uses a simple line-by-line parser tailored to the regular structure of the
 * SDE YAML files. No external YAML library is required.
 */
public class SdeLoader {

    private static final Logger LOG = LoggerFactory.getLogger(SdeLoader.class);
    private static final int BATCH_SIZE = 1000;

    private final TypeCacheRepository typeCacheRepo;
    private final MarketGroupRepository marketGroupRepo;
    private final DatabaseManager dbManager;

    public SdeLoader(TypeCacheRepository typeCacheRepo,
                     MarketGroupRepository marketGroupRepo,
                     DatabaseManager dbManager) {
        this.typeCacheRepo = typeCacheRepo;
        this.marketGroupRepo = marketGroupRepo;
        this.dbManager = dbManager;
    }

    /**
     * Loads all SDE data from the given directory. Expects types.yaml,
     * groups.yaml, categories.yaml, and marketGroups.yaml to be present.
     */
    public void loadAll(Path sdeDir) {
        LOG.info("Loading SDE data from {}", sdeDir);
        long start = System.currentTimeMillis();

        int categories = loadCategories(sdeDir.resolve("categories.yaml"));
        int groups = loadGroups(sdeDir.resolve("groups.yaml"));
        int marketGroups = loadMarketGroups(sdeDir.resolve("marketGroups.yaml"));
        int types = loadTypes(sdeDir.resolve("types.yaml"));

        long elapsed = System.currentTimeMillis() - start;
        LOG.info("SDE loading complete in {}ms: {} types, {} groups, {} categories, {} market groups",
                elapsed, types, groups, categories, marketGroups);
    }

    // -------------------------------------------------------------------------
    // Types
    // -------------------------------------------------------------------------

    private int loadTypes(Path file) {
        if (!Files.exists(file)) {
            LOG.warn("types.yaml not found at {}", file);
            return 0;
        }
        LOG.info("Loading types from {}", file);

        List<TypeCacheRow> batch = new ArrayList<>(BATCH_SIZE);
        int totalLoaded = 0;

        try (BufferedReader reader = Files.newBufferedReader(file, StandardCharsets.UTF_8)) {
            String line;
            // Current entry state
            Integer currentId = null;
            String name = null;
            Integer groupId = null;
            Integer categoryId = null;
            double volume = 0;
            boolean published = false;
            Integer marketGroupId = null;
            double mass = 0;
            boolean inName = false; // true when we're inside a "name:" block

            while ((line = reader.readLine()) != null) {
                if (line.isEmpty()) continue;

                // Top-level entry: "1234:"
                if (!line.startsWith(" ") && line.endsWith(":")) {
                    // Flush previous entry
                    if (currentId != null && published) {
                        batch.add(new TypeCacheRow(currentId, name != null ? name : "Type #" + currentId,
                                groupId, categoryId, volume, volume, published, marketGroupId));
                        if (batch.size() >= BATCH_SIZE) {
                            typeCacheRepo.bulkLoad(batch);
                            totalLoaded += batch.size();
                            batch.clear();
                            if (totalLoaded % 10000 == 0) {
                                LOG.info("  ... loaded {} types so far", totalLoaded);
                            }
                        }
                    }

                    // Parse new ID
                    String idStr = line.substring(0, line.length() - 1).trim();
                    try {
                        currentId = Integer.parseInt(idStr);
                    } catch (NumberFormatException e) {
                        currentId = null;
                    }

                    // Reset fields
                    name = null;
                    groupId = null;
                    categoryId = null;
                    volume = 0;
                    published = false;
                    marketGroupId = null;
                    mass = 0;
                    inName = false;
                    continue;
                }

                if (currentId == null) continue;

                String trimmed = line.stripLeading();

                // Inside "name:" block - look for "en: ..."
                if (inName) {
                    if (trimmed.startsWith("en:")) {
                        name = extractStringValue(trimmed, "en:");
                        inName = false;
                    } else if (!trimmed.isEmpty() && !line.startsWith("    ")) {
                        // Left the name block (less indented)
                        inName = false;
                        // Fall through to parse this line as a normal field
                    } else {
                        continue;
                    }
                }

                // Check for "name:" start
                if (trimmed.equals("name:")) {
                    inName = true;
                    continue;
                }

                // Parse fields at 2-space indent level
                if (trimmed.startsWith("groupID:")) {
                    groupId = parseIntValue(trimmed, "groupID:");
                } else if (trimmed.startsWith("published:")) {
                    published = "true".equals(extractRawValue(trimmed, "published:"));
                } else if (trimmed.startsWith("volume:")) {
                    volume = parseDoubleValue(trimmed, "volume:");
                } else if (trimmed.startsWith("mass:")) {
                    mass = parseDoubleValue(trimmed, "mass:");
                } else if (trimmed.startsWith("marketGroupID:")) {
                    marketGroupId = parseIntValue(trimmed, "marketGroupID:");
                }
            }

            // Flush last entry
            if (currentId != null && published) {
                batch.add(new TypeCacheRow(currentId, name != null ? name : "Type #" + currentId,
                        groupId, categoryId, volume, volume, published, marketGroupId));
            }
            if (!batch.isEmpty()) {
                typeCacheRepo.bulkLoad(batch);
                totalLoaded += batch.size();
            }

        } catch (IOException e) {
            LOG.error("Failed to load types.yaml", e);
            throw new RuntimeException("Failed to load types.yaml", e);
        }

        // Now update categoryId from groups table
        updateTypeCategoryIds();

        LOG.info("Loaded {} published types", totalLoaded);
        return totalLoaded;
    }

    /**
     * After types and groups are loaded, set each type's categoryId by joining
     * with the SdeGroups table.
     */
    private void updateTypeCategoryIds() {
        try (Connection conn = dbManager.getConnection();
             PreparedStatement ps = conn.prepareStatement("""
                     UPDATE TypeCache tc
                     SET CategoryId = (SELECT g.CategoryId FROM SdeGroups g WHERE g.GroupId = tc.GroupId)
                     WHERE tc.GroupId IS NOT NULL
                     """)) {
            int updated = ps.executeUpdate();
            LOG.info("Updated categoryId for {} types from SdeGroups", updated);
        } catch (SQLException e) {
            LOG.warn("Failed to update type category IDs from groups", e);
        }
    }

    // -------------------------------------------------------------------------
    // Groups
    // -------------------------------------------------------------------------

    private int loadGroups(Path file) {
        if (!Files.exists(file)) {
            LOG.warn("groups.yaml not found at {}", file);
            return 0;
        }
        LOG.info("Loading groups from {}", file);

        String sql = """
                MERGE INTO SdeGroups (GroupId, CategoryId, Name, Published)
                KEY (GroupId) VALUES (?, ?, ?, ?)
                """;
        int totalLoaded = 0;

        try (BufferedReader reader = Files.newBufferedReader(file, StandardCharsets.UTF_8)) {
            List<Object[]> batch = new ArrayList<>(BATCH_SIZE);
            String line;
            Integer currentId = null;
            String name = null;
            Integer categoryId = null;
            boolean published = false;
            boolean inName = false;

            while ((line = reader.readLine()) != null) {
                if (line.isEmpty()) continue;

                if (!line.startsWith(" ") && line.endsWith(":")) {
                    if (currentId != null) {
                        batch.add(new Object[]{currentId, categoryId,
                                name != null ? name : "Group #" + currentId, published});
                        if (batch.size() >= BATCH_SIZE) {
                            batchExecute(sql, batch);
                            totalLoaded += batch.size();
                            batch.clear();
                        }
                    }
                    String idStr = line.substring(0, line.length() - 1).trim();
                    try {
                        currentId = Integer.parseInt(idStr);
                    } catch (NumberFormatException e) {
                        currentId = null;
                    }
                    name = null;
                    categoryId = null;
                    published = false;
                    inName = false;
                    continue;
                }

                if (currentId == null) continue;
                String trimmed = line.stripLeading();

                if (inName) {
                    if (trimmed.startsWith("en:")) {
                        name = extractStringValue(trimmed, "en:");
                        inName = false;
                    } else if (!trimmed.isEmpty() && !line.startsWith("    ")) {
                        inName = false;
                    } else {
                        continue;
                    }
                }

                if (trimmed.equals("name:")) {
                    inName = true;
                } else if (trimmed.startsWith("categoryID:")) {
                    categoryId = parseIntValue(trimmed, "categoryID:");
                } else if (trimmed.startsWith("published:")) {
                    published = "true".equals(extractRawValue(trimmed, "published:"));
                }
            }

            // Flush last
            if (currentId != null) {
                batch.add(new Object[]{currentId, categoryId,
                        name != null ? name : "Group #" + currentId, published});
            }
            if (!batch.isEmpty()) {
                batchExecute(sql, batch);
                totalLoaded += batch.size();
            }
        } catch (IOException e) {
            LOG.error("Failed to load groups.yaml", e);
            throw new RuntimeException("Failed to load groups.yaml", e);
        }

        LOG.info("Loaded {} groups", totalLoaded);
        return totalLoaded;
    }

    // -------------------------------------------------------------------------
    // Categories
    // -------------------------------------------------------------------------

    private int loadCategories(Path file) {
        if (!Files.exists(file)) {
            LOG.warn("categories.yaml not found at {}", file);
            return 0;
        }
        LOG.info("Loading categories from {}", file);

        String sql = """
                MERGE INTO SdeCategories (CategoryId, Name, Published)
                KEY (CategoryId) VALUES (?, ?, ?)
                """;
        int totalLoaded = 0;

        try (BufferedReader reader = Files.newBufferedReader(file, StandardCharsets.UTF_8)) {
            List<Object[]> batch = new ArrayList<>(BATCH_SIZE);
            String line;
            Integer currentId = null;
            String name = null;
            boolean published = false;
            boolean inName = false;

            while ((line = reader.readLine()) != null) {
                if (line.isEmpty()) continue;

                if (!line.startsWith(" ") && line.endsWith(":")) {
                    if (currentId != null) {
                        batch.add(new Object[]{currentId,
                                name != null ? name : "Category #" + currentId, published});
                        if (batch.size() >= BATCH_SIZE) {
                            batchExecute(sql, batch);
                            totalLoaded += batch.size();
                            batch.clear();
                        }
                    }
                    String idStr = line.substring(0, line.length() - 1).trim();
                    try {
                        currentId = Integer.parseInt(idStr);
                    } catch (NumberFormatException e) {
                        currentId = null;
                    }
                    name = null;
                    published = false;
                    inName = false;
                    continue;
                }

                if (currentId == null) continue;
                String trimmed = line.stripLeading();

                if (inName) {
                    if (trimmed.startsWith("en:")) {
                        name = extractStringValue(trimmed, "en:");
                        inName = false;
                    } else if (!trimmed.isEmpty() && !line.startsWith("    ")) {
                        inName = false;
                    } else {
                        continue;
                    }
                }

                if (trimmed.equals("name:")) {
                    inName = true;
                } else if (trimmed.startsWith("published:")) {
                    published = "true".equals(extractRawValue(trimmed, "published:"));
                }
            }

            // Flush last
            if (currentId != null) {
                batch.add(new Object[]{currentId,
                        name != null ? name : "Category #" + currentId, published});
            }
            if (!batch.isEmpty()) {
                batchExecute(sql, batch);
                totalLoaded += batch.size();
            }
        } catch (IOException e) {
            LOG.error("Failed to load categories.yaml", e);
            throw new RuntimeException("Failed to load categories.yaml", e);
        }

        LOG.info("Loaded {} categories", totalLoaded);
        return totalLoaded;
    }

    // -------------------------------------------------------------------------
    // Market Groups
    // -------------------------------------------------------------------------

    private int loadMarketGroups(Path file) {
        if (!Files.exists(file)) {
            LOG.warn("marketGroups.yaml not found at {}", file);
            return 0;
        }
        LOG.info("Loading market groups from {}", file);

        List<MarketGroupRow> batch = new ArrayList<>(BATCH_SIZE);
        int totalLoaded = 0;

        try (BufferedReader reader = Files.newBufferedReader(file, StandardCharsets.UTF_8)) {
            String line;
            Integer currentId = null;
            String name = null;
            Integer parentGroupId = null;
            boolean hasTypes = false;
            Integer iconId = null;
            boolean inName = false;
            boolean inDescription = false;

            while ((line = reader.readLine()) != null) {
                if (line.isEmpty()) continue;

                if (!line.startsWith(" ") && line.endsWith(":")) {
                    // Flush previous
                    if (currentId != null) {
                        batch.add(new MarketGroupRow(currentId, parentGroupId,
                                name != null ? name : "Market Group #" + currentId, hasTypes, iconId));
                        if (batch.size() >= BATCH_SIZE) {
                            marketGroupRepo.bulkLoad(batch);
                            totalLoaded += batch.size();
                            batch.clear();
                        }
                    }
                    String idStr = line.substring(0, line.length() - 1).trim();
                    try {
                        currentId = Integer.parseInt(idStr);
                    } catch (NumberFormatException e) {
                        currentId = null;
                    }
                    name = null;
                    parentGroupId = null;
                    hasTypes = false;
                    iconId = null;
                    inName = false;
                    inDescription = false;
                    continue;
                }

                if (currentId == null) continue;
                String trimmed = line.stripLeading();

                // Skip description blocks (multi-line values)
                if (inDescription) {
                    if (!line.startsWith("    ") && !line.startsWith("  ")) {
                        inDescription = false;
                    } else if (line.startsWith("  ") && !line.startsWith("    ")) {
                        // Back to 2-space indent = new field
                        inDescription = false;
                    } else {
                        continue;
                    }
                }

                if (inName) {
                    if (trimmed.startsWith("en:")) {
                        name = extractStringValue(trimmed, "en:");
                        inName = false;
                    } else if (!trimmed.isEmpty() && !line.startsWith("    ")) {
                        inName = false;
                    } else {
                        continue;
                    }
                }

                if (trimmed.equals("name:")) {
                    inName = true;
                } else if (trimmed.equals("description:")) {
                    inDescription = true;
                } else if (trimmed.startsWith("parentGroupID:")) {
                    parentGroupId = parseIntValue(trimmed, "parentGroupID:");
                } else if (trimmed.startsWith("hasTypes:")) {
                    hasTypes = "true".equals(extractRawValue(trimmed, "hasTypes:"));
                } else if (trimmed.startsWith("iconID:")) {
                    iconId = parseIntValue(trimmed, "iconID:");
                }
            }

            // Flush last
            if (currentId != null) {
                batch.add(new MarketGroupRow(currentId, parentGroupId,
                        name != null ? name : "Market Group #" + currentId, hasTypes, iconId));
            }
            if (!batch.isEmpty()) {
                marketGroupRepo.bulkLoad(batch);
                totalLoaded += batch.size();
            }
        } catch (IOException e) {
            LOG.error("Failed to load marketGroups.yaml", e);
            throw new RuntimeException("Failed to load marketGroups.yaml", e);
        }

        LOG.info("Loaded {} market groups", totalLoaded);
        return totalLoaded;
    }

    // -------------------------------------------------------------------------
    // YAML value extraction helpers
    // -------------------------------------------------------------------------

    /**
     * Extracts a string value after a key prefix, e.g. "en: Rifter" -> "Rifter".
     * Handles both quoted and unquoted values.
     */
    private String extractStringValue(String line, String key) {
        String raw = line.substring(key.length()).trim();
        // Remove surrounding quotes if present
        if (raw.length() >= 2 &&
                ((raw.startsWith("'") && raw.endsWith("'")) ||
                 (raw.startsWith("\"") && raw.endsWith("\"")))) {
            raw = raw.substring(1, raw.length() - 1);
        }
        return raw.isEmpty() ? null : raw;
    }

    /**
     * Extracts the raw trimmed value after a key prefix.
     */
    private String extractRawValue(String line, String key) {
        return line.substring(key.length()).trim();
    }

    /**
     * Parses an integer value after a key prefix. Returns null for "null" or unparseable values.
     */
    private Integer parseIntValue(String line, String key) {
        String raw = extractRawValue(line, key);
        if (raw.isEmpty() || "null".equals(raw) || "~".equals(raw)) return null;
        try {
            // Handle values like "18.0" by truncating
            if (raw.contains(".")) {
                return (int) Double.parseDouble(raw);
            }
            return Integer.parseInt(raw);
        } catch (NumberFormatException e) {
            return null;
        }
    }

    /**
     * Parses a double value after a key prefix.
     */
    private double parseDoubleValue(String line, String key) {
        String raw = extractRawValue(line, key);
        if (raw.isEmpty() || "null".equals(raw) || "~".equals(raw)) return 0;
        try {
            return Double.parseDouble(raw);
        } catch (NumberFormatException e) {
            return 0;
        }
    }

    /**
     * Executes a batch of SQL statements directly via the DatabaseManager connection.
     */
    private void batchExecute(String sql, List<Object[]> paramSets) {
        if (paramSets.isEmpty()) return;
        try (Connection conn = dbManager.getConnection()) {
            conn.setAutoCommit(false);
            try (PreparedStatement ps = conn.prepareStatement(sql)) {
                int count = 0;
                for (Object[] params : paramSets) {
                    for (int i = 0; i < params.length; i++) {
                        if (params[i] == null) {
                            ps.setNull(i + 1, java.sql.Types.NULL);
                        } else {
                            ps.setObject(i + 1, params[i]);
                        }
                    }
                    ps.addBatch();
                    count++;
                    if (count % 1000 == 0) {
                        ps.executeBatch();
                    }
                }
                ps.executeBatch();
                conn.commit();
            } catch (SQLException e) {
                conn.rollback();
                throw e;
            }
        } catch (SQLException e) {
            throw new RuntimeException("Batch execute failed: " + sql, e);
        }
    }
}

