576	    private void loadItemOrders(TradeOpportunity item, String hubName) {
577	        detailItemLabel.setText("Loading orders for: " + item.typeName() + "...");
578	        buyOrdersTable.getItems().clear();
579	        sellOrdersTable.getItems().clear();
580	
581	        int regionId = hubToRegionIdFromFullName(hubName);
582	        Thread.ofVirtual().name("trader-load-orders").start(() ->
583	                dataService.getRegionOrders(item.typeId(), regionId)
584	                        .thenAccept(orders -> Platform.runLater(() -> {
585	                            detailItemLabel.setText("Orders for: " + item.typeName());
586	                            var buyOrders = orders.stream()
587	                                    .filter(MarketOrder::isBuyOrder)
588	                                    .sorted(Comparator.comparingDouble(MarketOrder::price).reversed())
589	                                    .toList();
590	                            var sellOrders = orders.stream()
591	                                    .filter(o -> !o.isBuyOrder())
592	                                    .sorted(Comparator.comparingDouble(MarketOrder::price))
593	                                    .toList();
594	                            buyOrdersTable.getItems().setAll(buyOrders);
595	                            sellOrdersTable.getItems().setAll(sellOrders);
596	                        }))
597	                        .exceptionally(ex -> {
598	                            Platform.runLater(() -> {
599	                                detailItemLabel.setText("Failed to load orders for: " + item.typeName());
600	                                log.error("Failed to load item orders", ex);
601	                            });
602	                            return null;
603	                        })
604	        );
605	    }
