607	    private static int hubToRegionIdFromFullName(String fullHubName) {
608	        if (fullHubName.startsWith("Jita")) return 10000002;
609	        if (fullHubName.startsWith("Amarr")) return 10000043;
610	        if (fullHubName.startsWith("Dodixie")) return 10000032;
611	        if (fullHubName.startsWith("Rens")) return 10000030;
612	        if (fullHubName.startsWith("Hek")) return 10000042;
613	        return 10000002;
614	    }
