870	        var shoppingRoot = new TreeItem<String>("Shopping List");
871	        shoppingRoot.setExpanded(true);
872	        shoppingTree.setRoot(shoppingRoot);
873	        shoppingTree.setShowRoot(true);
874	
875	        // --- Side TabPane for In Transit / Shopping List ---
876	        var sideTabPane = new TabPane();
