886	        summaryBox.setStyle("-fx-background-color: #252526;");
887	        totalInvestmentLabel = new Label("Total Investment: --");
888	        totalProfitLabel = new Label("Total Profit: --");
889	        roiLabel = new Label("ROI: --");
890	        cargoUsedLabel = new Label("Cargo Used: --");
