892	
893	        // --- Scan action ---
894	        scanBtn.setOnAction(e -> {
895	            scanBtn.setDisable(true);
896	            scanStatusLabel.setText("Scanning regional orders... (this may take a minute)");
897	            double minMargin;
898	            double maxCargo;
899	            double budget;
900	            try {
901	                minMargin = Double.parseDouble(minMarginField.getText()) / 100.0;
902	                maxCargo = Double.parseDouble(cargoField.getText().replace(",", ""));
903	                budget = Double.parseDouble(budgetField.getText().replace(",", ""));
904	            } catch (NumberFormatException ex) {
905	                scanBtn.setDisable(false);
906	                scanStatusLabel.setText("Invalid filter values");
907	                return;
908	            }
909	            int fromRegion = hubToRegionId(fromCombo.getValue());
910	            int toRegion = hubToRegionId(toCombo.getValue());
911	
912	            double shippingRate = 0;
913	            if (includeShippingCheck.isSelected()) {
914	                try {
915	                    shippingRate = Double.parseDouble(shippingRateField.getText().replace(",", ""));
916	                } catch (NumberFormatException ignored) {
917	                    // default to 0
918	                }
919	            }
920	            final double finalShippingRate = shippingRate;
921	
922	            Thread.ofVirtual().name("trader-regional-scan").start(() ->
923	                    dataService.scanRegionalTrades(fromRegion, toRegion, minMargin, maxCargo, budget)
924	                            .thenAccept(data -> Platform.runLater(() -> {
925	                                regionalOpportunities.setAll(data);
926	                                updateRegionalSummary(data, finalShippingRate);
927	                                updateShoppingTree(shoppingRoot, data, fromCombo.getValue());
928	                                scanStatusLabel.setText("Found " + data.size() + " opportunities");
929	                                scanBtn.setDisable(false);
