948	        centerSplit.setDividerPositions(0.7);
949	        centerSplit.getItems().addAll(tableContainer, sideTabPane);
950	        SplitPane.setResizableWithParent(sideTabPane, false);
951	
952	        var root = new VBox(routeBox, settingsBox, centerSplit, summaryBox);
