1004	
1005	    private void updateShoppingTree(TreeItem<String> root, List<TradeOpportunity> data, String sourceHub) {
1006	        root.getChildren().clear();
1007	
1008	        // Group all items under the source hub system
1009	        var systemNode = new TreeItem<>(sourceHub + " - Buy List");
1010	        systemNode.setExpanded(true);
1011	
1012	        for (var opp : data) {
1013	            long qty = opp.volume();
1014	            String label = String.format("%s x%d  -  %s",
1015	                    opp.typeName(), qty, IskFormatter.format(opp.buyPrice() * qty));
1016	            systemNode.getChildren().add(new TreeItem<>(label));
1017	        }
1018	
1019	        double totalCost = data.stream()
1020	                .mapToDouble(o -> o.buyPrice() * o.volume())
1021	                .sum();
1022	        var summaryNode = new TreeItem<>(String.format("Total: %s (%d items)",
1023	                IskFormatter.format(totalCost), data.size()));
1024	
1025	        root.getChildren().addAll(systemNode, summaryNode);
1026	    }
