1028	    // -----------------------------------------------------------------------
1029	    // Regional Summary
1030	    // -----------------------------------------------------------------------
1031	
1032	    private void updateRegionalSummary(List<TradeOpportunity> data, double shippingRate) {
1033	        double totalInvest = 0;
1034	        double totalProfit = 0;
1035	        double totalShipping = 0;
1036	        for (var opp : data) {
1037	            totalInvest += opp.buyPrice() * opp.volume();
1038	            double unitProfit = opp.sellPrice() - opp.buyPrice();
1039	            totalProfit += unitProfit * opp.volume();
1040	            // Shipping cost: rate * volume (assume 1 m3/unit)
1041	            totalShipping += shippingRate * opp.volume();
1042	        }
1043	        double netProfit = totalProfit - totalShipping;
1044	        totalInvestmentLabel.setText("Total Investment: " + IskFormatter.format(totalInvest));
1045	        totalProfitLabel.setText("Total Profit: " + IskFormatter.format(netProfit));
1046	        double roi = totalInvest > 0 ? (netProfit / totalInvest) * 100.0 : 0;
1047	        roiLabel.setText(String.format("ROI: %.1f%%", roi));
1048	        cargoUsedLabel.setText(String.format("Cargo Used: %,d m3",
1049	                data.stream().mapToLong(TradeOpportunity::volume).sum()));
1050	    }
