1056	    private static int hubToRegionId(String hub) {
1057	        return switch (hub) {
1058	            case "Jita" -> 10000002;
1059	            case "Amarr" -> 10000043;
1060	            case "Dodixie" -> 10000032;
1061	            case "Rens" -> 10000030;
1062	            case "Hek" -> 10000042;
1063	            default -> 10000002;
1064	        };
1065	    }
1066	
1067	    /**
1068	     * Comparator for ISK-formatted strings so table columns sort numerically.
1069	     */
1070	    private static int compareIskStrings(String a, String b) {
1071	        try {
1072	            double va = Double.parseDouble(a.replace(",", "").replace("%", "").replace("--", "0").trim());
1073	            double vb = Double.parseDouble(b.replace(",", "").replace("%", "").replace("--", "0").trim());
1074	            return Double.compare(va, vb);
1075	        } catch (NumberFormatException e) {
1076	            return a.compareTo(b);
1077	        }
1078	    }
1079	
1080	    @Override
1081	    public String getTitle() { return "Trader"; }
1082	
1083	    @Override
1084	    public void onActivated() { log.debug("Trader workspace activated"); }
1085	
1086	    @Override
1087	    public void onCharacterChanged(int characterId) {
1088	        log.debug("Trader: character changed to {}", characterId);
1089	        if (characterId <= 0) {
1090	            stationOpportunities.clear();
1091	            regionalOpportunities.clear();
1092	            inTransitItems.clear();
1093	        }
1094	    }
1095	}
