    private ContextMenu createTradeContextMenu(TableRow<TradeOpportunity> row,
                                                ObservableList<Integer> favorites,
                                                ObservableList<Integer> blacklist) {
        var contextMenu = new ContextMenu();

        var openInGameItem = new MenuItem("Open in Game");
        openInGameItem.setOnAction(e -> {
            var opp = row.getItem();
            if (opp != null) {
                // Copy showinfo link to clipboard for in-game use
                String showInfo = "showinfo:" + opp.typeId();
                var content = new ClipboardContent();
                content.putString(showInfo);
                Clipboard.getSystemClipboard().setContent(content);
                log.info("Copied showinfo link for {} to clipboard", opp.typeName());
            }
        });

        var addToFavoritesItem = new MenuItem("Add to Favorites");
        addToFavoritesItem.setOnAction(e -> {
            var opp = row.getItem();
            if (opp != null && !favorites.contains(opp.typeId())) {
                favorites.add(opp.typeId());
            }
        });

        var addToBlacklistItem = new MenuItem("Add to Blacklist");
        addToBlacklistItem.setOnAction(e -> {
            var opp = row.getItem();
            if (opp != null && !blacklist.contains(opp.typeId())) {
                blacklist.add(opp.typeId());
            }
        });

        contextMenu.getItems().addAll(openInGameItem, addToFavoritesItem, addToBlacklistItem);
        return contextMenu;
    }

    // -----------------------------------------------------------------------
    // Shopping Tree
    // -----------------------------------------------------------------------

    private void updateShoppingTree(TreeItem<String> root, List<TradeOpportunity> data, String sourceHub) {
        root.getChildren().clear();

        // Group all items under the source hub system
        var systemNode = new TreeItem<>(sourceHub + " - Buy List");
        systemNode.setExpanded(true);

        for (var opp : data) {
            long qty = opp.volume();
            String label = String.format("%s x%d  -  %s",
                    opp.typeName(), qty, IskFormatter.format(opp.buyPrice() * qty));
            systemNode.getChildren().add(new TreeItem<>(label));
        }

        double totalCost = data.stream()
                .mapToDouble(o -> o.buyPrice() * o.volume())
                .sum();
        var summaryNode = new TreeItem<>(String.format("Total: %s (%d items)",
                IskFormatter.format(totalCost), data.size()));

        root.getChildren().addAll(systemNode, summaryNode);
    }

    // -----------------------------------------------------------------------
    // Regional Summary
    // -----------------------------------------------------------------------

    private void updateRegionalSummary(List<TradeOpportunity> data, double shippingRate) {
        double totalInvest = 0;
        double totalProfit = 0;
        double totalShipping = 0;
        for (var opp : data) {
            totalInvest += opp.buyPrice() * opp.volume();
            double unitProfit = opp.sellPrice() - opp.buyPrice();
            totalProfit += unitProfit * opp.volume();
            // Shipping cost: rate * volume (assume 1 m3/unit)
            totalShipping += shippingRate * opp.volume();
        }
        double netProfit = totalProfit - totalShipping;
        totalInvestmentLabel.setText("Total Investment: " + IskFormatter.format(totalInvest));
        totalProfitLabel.setText("Total Profit: " + IskFormatter.format(netProfit));
        double roi = totalInvest > 0 ? (netProfit / totalInvest) * 100.0 : 0;
        roiLabel.setText(String.format("ROI: %.1f%%", roi));
        cargoUsedLabel.setText(String.format("Cargo Used: %,d m3",
                data.stream().mapToLong(TradeOpportunity::volume).sum()));
    }

    // -----------------------------------------------------------------------
    // Utility
    // -----------------------------------------------------------------------

    private static int hubToRegionId(String hub) {
        return switch (hub) {
            case "Jita" -> 10000002;
            case "Amarr" -> 10000043;
            case "Dodixie" -> 10000032;
            case "Rens" -> 10000030;
            case "Hek" -> 10000042;
            default -> 10000002;
        };
    }

    /**
     * Comparator for ISK-formatted strings so table columns sort numerically.
     */
    private static int compareIskStrings(String a, String b) {
        try {
            double va = Double.parseDouble(a.replace(",", "").replace("%", "").replace("--", "0").trim());
            double vb = Double.parseDouble(b.replace(",", "").replace("%", "").replace("--", "0").trim());
            return Double.compare(va, vb);
        } catch (NumberFormatException e) {
            return a.compareTo(b);
        }
    }

    @Override
    public String getTitle() { return "Trader"; }

    @Override
    public void onActivated() { log.debug("Trader workspace activated"); }

    @Override
    public void onCharacterChanged(int characterId) {
        log.debug("Trader: character changed to {}", characterId);
        if (characterId <= 0) {
            stationOpportunities.clear();
            regionalOpportunities.clear();
            inTransitItems.clear();
        }
    }
}

