package com.sampleapp.app;

import com.sampleapp.core.app.AppConfig;
import com.sampleapp.core.app.AppState;
import com.sampleapp.core.model.ItemType;
import com.sampleapp.data.DatabaseManager;
import com.sampleapp.data.StationStatsDatabase;
import com.sampleapp.data.cache.ItemTypeCache;
import com.sampleapp.data.repository.CharacterRepository;
import com.sampleapp.data.repository.MarketGroupRepository;
import com.sampleapp.data.repository.TypeCacheRepository;
import com.sampleapp.data.sde.SdeLoader;
import com.sampleapp.app.service.SyncService;
import com.sampleapp.app.service.StationTradeService;
import com.sampleapp.core.model.UserCharacter;
import com.google.inject.Guice;
import com.google.inject.Injector;
import javafx.application.Application;
import javafx.application.Platform;
import javafx.scene.Scene;
import javafx.stage.Stage;
import javafx.stage.StageStyle;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;

/**
 * Main entry point for the Sample App application.
 * Handles initialization sequence: splash -> config -> database -> UI.
 */
public class SampleApp extends Application {

    private static final Logger log = LoggerFactory.getLogger(SampleApp.class);
    private static final String APP_VERSION = "2.1.245";

    private AppState appState;
    private Injector injector;
    private Path dataDir;
    private boolean devMode;
    private boolean resetConfig;
    private boolean portableMode;

    // Service references for shutdown
    private DatabaseManager databaseManager;
    private StationStatsDatabase stationStatsDatabase;
    private SyncService syncService;
    private StationTradeService stationTradeService;

    @Override
    public void init() {
        parseArguments(getParameters().getRaw());
    }

    @Override
    public void start(Stage primaryStage) {
        log.info("Starting Sample App v{}", APP_VERSION);

        // Show splash screen
        var splashStage = new Stage(StageStyle.UNDECORATED);
        var splashScreen = new SplashScreen();
        var splashScene = new Scene(splashScreen, 470, 270);
        splashScene.getStylesheets().add(
                getClass().getResource("/css/dark-theme.css").toExternalForm());
        splashStage.setScene(splashScene);
        splashStage.setTitle("Sample App - Loading");
        splashStage.centerOnScreen();
        splashStage.show();

        // Run initialization on background thread
        Thread.ofVirtual().name("init").start(() -> {
            try {
                // Step 1: Resolve data directory
                splashScreen.updateStatus("Resolving data directory...", 0.05);
                resolveDataDir();

                // Step 2: Load configuration
                splashScreen.updateStatus("Loading configuration...", 0.15);
                var config = loadConfig();

                // Step 3: Initialize Guice
                splashScreen.updateStatus("Initializing dependency injection...", 0.25);
                var module = new AppModule(config, dataDir, devMode);
                injector = Guice.createInjector(module);
                appState = injector.getInstance(AppState.class);

                // Step 4: Initialize databases
                splashScreen.updateStatus("Initializing databases...", 0.40);
                initializeDatabases();

                // Step 4b: Load SDE if type cache is empty
                loadSdeIfNeeded(splashScreen);

                // Step 4c: Populate in-memory ItemTypeCache from DB
                splashScreen.updateStatus("Loading item type cache...", 0.52);
                populateItemTypeCache();

                // Step 5: Initialize feature gate and load characters
                splashScreen.updateStatus("Loading characters...", 0.55);
                initializeFeatureGate();
                loadCharacters();

                // Step 6: Create main window
                splashScreen.updateStatus("Building user interface...", 0.70);
                Platform.runLater(() -> {
                    try {
                        createMainWindow(primaryStage, splashStage, splashScreen);
                    } catch (Exception e) {
                        log.error("Failed to create main window", e);
                        showErrorAndExit(e);
                    }
                });
            } catch (Exception e) {
                log.error("Initialization failed", e);
                Platform.runLater(() -> showErrorAndExit(e));
            }
        });
    }

    private void createMainWindow(Stage primaryStage, Stage splashStage, SplashScreen splashScreen) {
        splashScreen.updateStatus("Preparing main window...", 0.85);

        var mainWindow = injector.getInstance(com.sampleapp.ui.MainWindow.class);
        var scene = new Scene(mainWindow, 1280, 800);
        scene.getStylesheets().add(
                getClass().getResource("/css/dark-theme.css").toExternalForm());

        primaryStage.setScene(scene);
        primaryStage.setTitle("Sample App v" + APP_VERSION);
        primaryStage.setMinWidth(960);
        primaryStage.setMinHeight(600);

        // Step 7: Start background services
        splashScreen.updateStatus("Starting background services...", 0.95);
        startBackgroundServices();

        splashScreen.updateStatus("Ready!", 1.0);

        // Close splash and show main window
        splashStage.close();
        primaryStage.show();

        log.info("Sample App started successfully");
    }

    @Override
    public void stop() {
        log.info("Shutting down Sample App...");

        // Save workspace layout on shutdown
        if (injector != null) {
            try {
                var mainWindow = injector.getInstance(com.sampleapp.ui.MainWindow.class);
                mainWindow.saveLayoutOnShutdown();
            } catch (Exception e) {
                log.debug("Failed to save layout on shutdown", e);
            }
        }

        // Stop background services
        if (syncService != null) {
            syncService.shutdown();
        }
        if (stationTradeService != null) {
            stationTradeService.shutdown();
        }

        // Close databases
        if (stationStatsDatabase != null) {
            stationStatsDatabase.close();
        }
        if (databaseManager != null) {
            databaseManager.close();
        }

        if (appState != null) {
            appState.shutdown();
        }

        log.info("Sample App shutdown complete");
    }

    private void parseArguments(List<String> args) {
        for (String arg : args) {
            if (arg.startsWith("--data-dir=")) {
                dataDir = Path.of(arg.substring("--data-dir=".length()));
            } else if ("--dev".equals(arg)) {
                devMode = true;
                log.info("Developer mode enabled");
            } else if ("--reset-config".equals(arg)) {
                resetConfig = true;
                log.info("Configuration reset requested");
            } else if ("--portable".equals(arg)) {
                portableMode = true;
                log.info("Portable mode enabled");
            }
        }
    }

    private void resolveDataDir() {
        if (dataDir == null) {
            if (portableMode) {
                dataDir = Path.of(System.getProperty("user.dir"), ".sampleapp");
            } else {
                dataDir = Path.of(System.getProperty("user.home"), ".sampleapp");
            }
        }
        try {
            Files.createDirectories(dataDir);
            Files.createDirectories(dataDir.resolve("logs"));
            Files.createDirectories(dataDir.resolve("cache"));
            Files.createDirectories(dataDir.resolve("db"));
            log.info("Data directory: {}", dataDir);
        } catch (Exception e) {
            throw new RuntimeException("Failed to create data directory: " + dataDir, e);
        }
    }

    private AppConfig loadConfig() {
        var configPath = dataDir.resolve("config.json");
        if (resetConfig) {
            try {
                Files.deleteIfExists(configPath);
                log.info("Configuration reset to defaults");
            } catch (Exception e) {
                log.warn("Failed to delete config file", e);
            }
        }
        return AppConfig.load(configPath);
    }

    private void initializeDatabases() {
        log.info("Initializing H2 databases in {}", dataDir.resolve("db"));

        databaseManager = injector.getInstance(DatabaseManager.class);
        databaseManager.initialize();

        stationStatsDatabase = injector.getInstance(StationStatsDatabase.class);
        stationStatsDatabase.initialize();

        log.info("Databases initialized successfully");
    }

    private void loadSdeIfNeeded(SplashScreen splashScreen) {
        try {
            var typeCacheRepo = injector.getInstance(TypeCacheRepository.class);
            if (typeCacheRepo.count() == 0) {
                splashScreen.updateStatus("Loading static data...", 0.50);
                Path sdeDir = resolveSdeDir();
                if (sdeDir != null && Files.exists(sdeDir)) {
                    var marketGroupRepo = injector.getInstance(MarketGroupRepository.class);
                    var dbManager = injector.getInstance(DatabaseManager.class);
                    var sdeLoader = new SdeLoader(typeCacheRepo, marketGroupRepo, dbManager);
                    sdeLoader.loadAll(sdeDir);
                    log.info("SDE data loaded successfully");
                } else {
                    log.warn("SDE directory not found - type names will be unavailable. " +
                            "Checked: {}/sde, D:\\Eve_data\\sde, {}/.sampleapp/sde",
                            dataDir, System.getProperty("user.home"));
                }
            } else {
                log.info("TypeCache already populated ({} entries), skipping SDE load",
                        typeCacheRepo.count());
            }
        } catch (Exception e) {
            log.error("Failed to load SDE data (non-fatal, continuing startup)", e);
        }
    }

    /**
     * Resolves the SDE directory by checking multiple candidate locations.
     */
    private Path resolveSdeDir() {
        // 1. dataDir/sde/
        Path candidate = dataDir.resolve("sde");
        if (Files.exists(candidate.resolve("types.yaml"))) {
            log.info("Using SDE directory: {}", candidate);
            return candidate;
        }

        // 2. D:\Eve_data\sde\ (shared C# data directory)
        candidate = Path.of("D:", "Eve_data", "sde");
        if (Files.exists(candidate.resolve("types.yaml"))) {
            log.info("Using SDE directory: {}", candidate);
            return candidate;
        }

        // 3. User home ~/.sampleapp/sde/
        candidate = Path.of(System.getProperty("user.home"), ".sampleapp", "sde");
        if (Files.exists(candidate.resolve("types.yaml"))) {
            log.info("Using SDE directory: {}", candidate);
            return candidate;
        }

        return null;
    }

    private void initializeFeatureGate() {
        log.info("Initializing feature gates (devMode={})", devMode);
        // UI FeatureGate is auto-configured by Guice injection (takes AppConfig + @DevMode)
        injector.getInstance(com.sampleapp.core.app.FeatureGate.class);

        // Subscription FeatureGate (used by StationTradeService) - enable all in dev mode
        var subscriptionGate = injector.getInstance(com.sampleapp.core.subscription.FeatureGate.class);
        if (devMode) {
            subscriptionGate.enableAll();
        }
    }

    private void populateItemTypeCache() {
        try {
            var typeCacheRepo = injector.getInstance(TypeCacheRepository.class);
            var itemTypeCache = injector.getInstance(ItemTypeCache.class);
            var rows = typeCacheRepo.findAll();
            var items = rows.stream()
                    .map(r -> new ItemType(
                            r.typeId(), r.name(),
                            r.groupId() != null ? r.groupId() : 0,
                            r.categoryId() != null ? r.categoryId() : 0,
                            r.volume(), r.packagedVolume(), r.published()))
                    .toList();
            itemTypeCache.putAll(items);
            log.info("Populated ItemTypeCache with {} entries", items.size());
        } catch (Exception e) {
            log.warn("Failed to populate ItemTypeCache (non-fatal)", e);
        }
    }

    private void loadCharacters() {
        log.info("Loading existing characters from database");
        try {
            var characterRepo = injector.getInstance(CharacterRepository.class);
            var characters = characterRepo.findAll();
            for (var row : characters) {
                var charInfo = new AppState.CharacterInfo(
                        row.characterId(),
                        row.name(),
                        "", // corporationName not stored in row, resolved later
                        ""  // allianceName not stored in row, resolved later
                );
                appState.getCharacters().add(charInfo);
                log.info("Loaded character: {} (ID: {})", row.name(), row.characterId());

                // Restore tokens from stored refresh tokens
                if (row.refreshToken() != null && !row.refreshToken().isBlank()) {
                    var tokenManager = injector.getInstance(com.sampleapp.esi.TokenManager.class);
                    // Store a placeholder token; it will be refreshed on first use
                    tokenManager.storeToken(new com.sampleapp.esi.TokenManager.TokenData(
                            "", // no access token yet
                            row.refreshToken(),
                            java.time.LocalDateTime.now().minusMinutes(1), // expired, will trigger refresh
                            row.characterId(),
                            row.name(),
                            row.ownerHash() != null ? row.ownerHash() : ""
                    ));
                }
            }
            log.info("Loaded {} characters from database", characters.size());
        } catch (Exception e) {
            log.warn("Failed to load characters from database", e);
        }
    }

    private void startBackgroundServices() {
        log.info("Starting background services");

        // Start ESI sync service
        syncService = injector.getInstance(SyncService.class);
        var config = injector.getInstance(AppConfig.class);
        syncService.start(config.getSyncIntervalMinutes());

        // Start station trade import schedule
        stationTradeService = injector.getInstance(StationTradeService.class);
        stationTradeService.startScheduledImport();

        log.info("Background services started");
    }

    private void showErrorAndExit(Exception e) {
        log.error("Fatal error during startup", e);
        var alert = new javafx.scene.control.Alert(
                javafx.scene.control.Alert.AlertType.ERROR,
                "Failed to start Sample App:\n" + e.getMessage()
        );
        alert.setTitle("Sample App - Startup Error");
        alert.showAndWait();
        Platform.exit();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

