3	import com.sampleapp.data.DatabaseManager;
4	
5	import java.sql.*;
6	import java.util.ArrayList;
7	import java.util.List;
8	import java.util.Optional;
9	
10	/**
11	 * Abstract base class providing common JDBC helper methods for all repositories.
12	 * Every method obtains and releases its own connection from the pool, so callers
13	 * never need to manage connections directly.
14	 */
15	public abstract class BaseRepository {
16	
17	    protected final DatabaseManager db;
18	
19	    protected BaseRepository(DatabaseManager db) {
20	        this.db = db;
21	    }
22	
23	    /**
24	     * Executes a SELECT and maps each row to a domain object.
25	     */
26	    protected <T> List<T> query(String sql, RowMapper<T> mapper, Object... params) {
27	        List<T> results = new ArrayList<>();
28	        try (Connection conn = db.getConnection();
29	             PreparedStatement ps = conn.prepareStatement(sql)) {
30	
31	            setParameters(ps, params);
32	
33	            try (ResultSet rs = ps.executeQuery()) {
34	                while (rs.next()) {
35	                    results.add(mapper.map(rs));
36	                }
37	            }
38	        } catch (SQLException e) {
39	            throw new RuntimeException("Query failed: " + sql, e);
40	        }
41	        return results;
42	    }
43	
44	    /**
45	     * Executes a SELECT expecting at most one result.
46	     */
47	    protected <T> Optional<T> queryOne(String sql, RowMapper<T> mapper, Object... params) {
48	        try (Connection conn = db.getConnection();
49	             PreparedStatement ps = conn.prepareStatement(sql)) {
50	
51	            setParameters(ps, params);
52	
53	            try (ResultSet rs = ps.executeQuery()) {
54	                if (rs.next()) {
55	                    return Optional.ofNullable(mapper.map(rs));
56	                }
57	            }
58	        } catch (SQLException e) {
59	            throw new RuntimeException("Query failed: " + sql, e);
60	        }
61	        return Optional.empty();
62	    }
63	
64	    /**
65	     * Executes an INSERT, UPDATE, or DELETE and returns the number of affected rows.
66	     */
67	    protected int update(String sql, Object... params) {
68	        try (Connection conn = db.getConnection();
69	             PreparedStatement ps = conn.prepareStatement(sql)) {
70	
71	            setParameters(ps, params);
72	            return ps.executeUpdate();
73	
74	        } catch (SQLException e) {
75	            throw new RuntimeException("Update failed: " + sql, e);
76	        }
77	    }
78	
79	    /**
80	     * Executes a batch insert/update. Each element in {@code paramSets} is an
81	     * array of parameter values for one row.
82	     */
83	    protected void batchInsert(String sql, List<Object[]> paramSets) {
84	        if (paramSets == null || paramSets.isEmpty()) {
85	            return;
86	        }
87	
88	        try (Connection conn = db.getConnection()) {
89	            conn.setAutoCommit(false);
90	
91	            try (PreparedStatement ps = conn.prepareStatement(sql)) {
92	                int count = 0;
93	                for (Object[] params : paramSets) {
94	                    setParameters(ps, params);
95	                    ps.addBatch();
96	                    count++;
97	
98	                    if (count % 1000 == 0) {
99	                        ps.executeBatch();
100	                    }
101	                }
102	                ps.executeBatch();
103	                conn.commit();
104	            } catch (SQLException e) {
105	                conn.rollback();
106	                throw e;
107	            }
108	        } catch (SQLException e) {
109	            throw new RuntimeException("Batch insert failed: " + sql, e);
110	        }
111	    }
