package com.sampleapp.data;

import com.zaxxer.hikari.HikariConfig;
import com.zaxxer.hikari.HikariDataSource;
import jakarta.inject.Inject;
import jakarta.inject.Named;
import jakarta.inject.Singleton;
import org.flywaydb.core.Flyway;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.sql.Connection;
import java.sql.SQLException;

/**
 * Manages the main H2 database connection pool and schema migrations.
 * This database stores all character-related data: transactions, orders,
 * contracts, industry jobs, assets, blueprints, wallet, and more.
 */
@Singleton
public class DatabaseManager {

    private static final Logger LOG = LoggerFactory.getLogger(DatabaseManager.class);
    private static final String DB_URL_TEMPLATE = "jdbc:h2:file:%s/sampleapp;AUTO_SERVER=TRUE";

    private final String dataFolder;
    private HikariDataSource dataSource;

    @Inject
    public DatabaseManager(@Named("dataFolder") String dataFolder) {
        this.dataFolder = dataFolder;
    }

    /**
     * Initialises the connection pool and runs Flyway migrations to bring
     * the schema up to date.
     */
    public void initialize() {
        String jdbcUrl = String.format(DB_URL_TEMPLATE, dataFolder.replace('\\', '/'));
        LOG.info("Initialising main database at {}", jdbcUrl);

        HikariConfig config = new HikariConfig();
        config.setJdbcUrl(jdbcUrl);
        config.setMaximumPoolSize(10);
        config.setMinimumIdle(2);
        config.setConnectionTimeout(30_000);
        config.setIdleTimeout(600_000);
        config.setMaxLifetime(1_800_000);
        config.setPoolName("sampleapp-main");

        dataSource = new HikariDataSource(config);

        Flyway flyway = Flyway.configure()
                .dataSource(dataSource)
                .locations("classpath:db/migration")
                .baselineOnMigrate(true)
                .load();

        flyway.migrate();
        LOG.info("Main database initialised successfully");
    }

    /**
     * Obtains a connection from the pool. Callers must close the connection
     * when finished (use try-with-resources).
     */
    public Connection getConnection() throws SQLException {
        if (dataSource == null || dataSource.isClosed()) {
            throw new IllegalStateException("Database has not been initialised or has been closed");
        }
        return dataSource.getConnection();
    }

    /**
     * Returns the underlying data source for advanced use cases.
     */
    public HikariDataSource getDataSource() {
        return dataSource;
    }

    /**
     * Shuts down the connection pool.
     */
    public void close() {
        if (dataSource != null && !dataSource.isClosed()) {
            LOG.info("Closing main database connection pool");
            dataSource.close();
        }
    }
}

