173	     * Automatically fetch all pages of a paginated endpoint and merge results.
174	     */
175	    public <T> CompletableFuture<List<T>> getAllPages(String path, TypeReference<List<T>> type, String token) {
176	        String separator = path.contains("?") ? "&" : "?";
177	        String firstPagePath = path + separator + "page=1";
178	
179	        return get(firstPagePath, type, token).thenCompose(firstResponse -> {
180	            if (!firstResponse.isSuccess()) {
181	                return CompletableFuture.completedFuture(
182	                        firstResponse.data() != null ? firstResponse.data() : List.of());
183	            }
184	
185	            int totalPages = firstResponse.pages();
186	            List<T> result = new ArrayList<>(firstResponse.data() != null ? firstResponse.data() : List.of());
187	
188	            if (totalPages <= 1) {
189	                return CompletableFuture.completedFuture(result);
190	            }
191	
192	            @SuppressWarnings("unchecked")
193	            CompletableFuture<EsiResponse<List<T>>>[] pageFutures = new CompletableFuture[totalPages - 1];
194	            for (int page = 2; page <= totalPages; page++) {
195	                String pagePath = path + separator + "page=" + page;
196	                pageFutures[page - 2] = get(pagePath, type, token);
197	            }
198	
199	            return CompletableFuture.allOf(pageFutures).thenApply(v2 -> {
200	                for (CompletableFuture<EsiResponse<List<T>>> pf : pageFutures) {
201	                    EsiResponse<List<T>> pr = pf.join();
202	                    if (pr.isSuccess() && pr.data() != null) {
203	                        result.addAll(pr.data());
204	                    }
205	                }
206	                return result;
207	            });
208	        });
209	    }
