    // -------------------------------------------------------------------------
    // Market Groups
    // -------------------------------------------------------------------------

    private int loadMarketGroups(Path file) {
        if (!Files.exists(file)) {
            LOG.warn("marketGroups.yaml not found at {}", file);
            return 0;
        }
        LOG.info("Loading market groups from {}", file);

        List<MarketGroupRow> batch = new ArrayList<>(BATCH_SIZE);
        int totalLoaded = 0;

        try (BufferedReader reader = Files.newBufferedReader(file, StandardCharsets.UTF_8)) {
            String line;
            Integer currentId = null;
            String name = null;
            Integer parentGroupId = null;
            boolean hasTypes = false;
            Integer iconId = null;
            boolean inName = false;
            boolean inDescription = false;

            while ((line = reader.readLine()) != null) {
                if (line.isEmpty()) continue;

                if (!line.startsWith(" ") && line.endsWith(":")) {
                    // Flush previous
                    if (currentId != null) {
                        batch.add(new MarketGroupRow(currentId, parentGroupId,
                                name != null ? name : "Market Group #" + currentId, hasTypes, iconId));
                        if (batch.size() >= BATCH_SIZE) {
                            marketGroupRepo.bulkLoad(batch);
                            totalLoaded += batch.size();
                            batch.clear();
                        }
                    }
                    String idStr = line.substring(0, line.length() - 1).trim();
                    try {
                        currentId = Integer.parseInt(idStr);
                    } catch (NumberFormatException e) {
                        currentId = null;
                    }
                    name = null;
                    parentGroupId = null;
                    hasTypes = false;
                    iconId = null;
                    inName = false;
                    inDescription = false;
                    continue;
                }

                if (currentId == null) continue;
                String trimmed = line.stripLeading();

                // Skip description blocks (multi-line values)
                if (inDescription) {
                    if (!line.startsWith("    ") && !line.startsWith("  ")) {
                        inDescription = false;
                    } else if (line.startsWith("  ") && !line.startsWith("    ")) {
                        // Back to 2-space indent = new field
                        inDescription = false;
                    } else {
                        continue;
                    }
                }

                if (inName) {
                    if (trimmed.startsWith("en:")) {
                        name = extractStringValue(trimmed, "en:");
                        inName = false;
                    } else if (!trimmed.isEmpty() && !line.startsWith("    ")) {
                        inName = false;
                    } else {
                        continue;
                    }
                }

                if (trimmed.equals("name:")) {
                    inName = true;
                } else if (trimmed.equals("description:")) {
                    inDescription = true;
                } else if (trimmed.startsWith("parentGroupID:")) {
                    parentGroupId = parseIntValue(trimmed, "parentGroupID:");
                } else if (trimmed.startsWith("hasTypes:")) {
                    hasTypes = "true".equals(extractRawValue(trimmed, "hasTypes:"));
                } else if (trimmed.startsWith("iconID:")) {
                    iconId = parseIntValue(trimmed, "iconID:");
                }
            }

            // Flush last
            if (currentId != null) {
                batch.add(new MarketGroupRow(currentId, parentGroupId,
                        name != null ? name : "Market Group #" + currentId, hasTypes, iconId));
            }
            if (!batch.isEmpty()) {
                marketGroupRepo.bulkLoad(batch);
                totalLoaded += batch.size();
            }
        } catch (IOException e) {
            LOG.error("Failed to load marketGroups.yaml", e);
            throw new RuntimeException("Failed to load marketGroups.yaml", e);
        }

        LOG.info("Loaded {} market groups", totalLoaded);
        return totalLoaded;
    }

    // -------------------------------------------------------------------------
    // Solar Systems
    // -------------------------------------------------------------------------

    private int loadSolarSystems(Path file) {
        if (!Files.exists(file)) {
            LOG.warn("mapSolarSystems.yaml not found at {}", file);
            return 0;
        }
        LOG.info("Loading solar systems from {}", file);

        String sql = """
                MERGE INTO SdeSolarSystems (SystemId, Name, ConstellationId, RegionId, SecurityStatus)
                KEY (SystemId) VALUES (?, ?, ?, ?, ?)
                """;
        int totalLoaded = 0;

        try (BufferedReader reader = Files.newBufferedReader(file, StandardCharsets.UTF_8)) {
            List<Object[]> batch = new ArrayList<>(BATCH_SIZE);
            String line;
            Integer currentId = null;
            String name = null;
            Integer constellationId = null;
            Integer regionId = null;
            double securityStatus = 0;
            boolean inName = false;

            while ((line = reader.readLine()) != null) {
                if (line.isEmpty()) continue;

                if (!line.startsWith(" ") && line.endsWith(":")) {
                    if (currentId != null) {
                        batch.add(new Object[]{currentId,
                                name != null ? name : "System #" + currentId,
                                constellationId, regionId, securityStatus});
                        if (batch.size() >= BATCH_SIZE) {
                            batchExecute(sql, batch);
                            totalLoaded += batch.size();
                            batch.clear();
                            if (totalLoaded % 5000 == 0) {
                                LOG.info("  ... loaded {} solar systems so far", totalLoaded);
                            }
                        }
                    }
                    String idStr = line.substring(0, line.length() - 1).trim();
                    try {
                        currentId = Integer.parseInt(idStr);
                    } catch (NumberFormatException e) {
                        currentId = null;
                    }
                    name = null;
                    constellationId = null;
                    regionId = null;
                    securityStatus = 0;
                    inName = false;
                    continue;
                }

                if (currentId == null) continue;
                String trimmed = line.stripLeading();

                if (inName) {
                    if (trimmed.startsWith("en:")) {
                        name = extractStringValue(trimmed, "en:");
                        inName = false;
                    } else if (!trimmed.isEmpty() && !line.startsWith("    ")) {
                        inName = false;
                    } else {
                        continue;
                    }
                }

                if (trimmed.equals("name:")) {
                    inName = true;
                } else if (trimmed.startsWith("constellationID:")) {
                    constellationId = parseIntValue(trimmed, "constellationID:");
                } else if (trimmed.startsWith("regionID:")) {
                    regionId = parseIntValue(trimmed, "regionID:");
                } else if (trimmed.startsWith("securityStatus:")) {
                    securityStatus = parseDoubleValue(trimmed, "securityStatus:");
                }
            }

            // Flush last
            if (currentId != null) {
                batch.add(new Object[]{currentId,
                        name != null ? name : "System #" + currentId,
                        constellationId, regionId, securityStatus});
            }
            if (!batch.isEmpty()) {
                batchExecute(sql, batch);
                totalLoaded += batch.size();
            }
        } catch (IOException e) {
            LOG.error("Failed to load mapSolarSystems.yaml", e);
            throw new RuntimeException("Failed to load mapSolarSystems.yaml", e);
        }

        LOG.info("Loaded {} solar systems", totalLoaded);
        return totalLoaded;
    }

    // -------------------------------------------------------------------------
    // Station Names (from npcStations + stationOperations + SdeSolarSystems)
    // -------------------------------------------------------------------------

    private int loadStationNames(Path npcStationsFile, Path operationsFile) {
        if (!Files.exists(npcStationsFile)) {
            LOG.warn("npcStations.yaml not found at {}", npcStationsFile);
            return 0;
        }
        LOG.info("Loading station names from {}", npcStationsFile);

        // Step 1: Load operation names from stationOperations.yaml
        Map<Integer, String> operationNames = loadOperationNames(operationsFile);

        // Step 2: Load solar system names from the DB (already loaded by loadSolarSystems)
        Map<Integer, String> systemNames = loadSystemNamesFromDb();

        // Step 3: Parse npcStations.yaml and build station names
        String sql = """
                MERGE INTO SdeStationNames (StationId, StationName, SolarSystemId)
                KEY (StationId) VALUES (?, ?, ?)
                """;
        int totalLoaded = 0;

        try (BufferedReader reader = Files.newBufferedReader(npcStationsFile, StandardCharsets.UTF_8)) {
            List<Object[]> batch = new ArrayList<>(BATCH_SIZE);
            String line;
            Long currentId = null;
            Integer operationId = null;
            Integer solarSystemId = null;

            while ((line = reader.readLine()) != null) {
                if (line.isEmpty()) continue;

                if (!line.startsWith(" ") && line.endsWith(":")) {
                    // Flush previous entry
                    if (currentId != null && solarSystemId != null) {
                        String sysName = systemNames.getOrDefault(solarSystemId, "System " + solarSystemId);
                        String opName = operationId != null
                                ? operationNames.getOrDefault(operationId, "Station")
                                : "Station";
                        String stationName = sysName + " - " + opName;
                        batch.add(new Object[]{currentId, stationName, solarSystemId});
                        if (batch.size() >= BATCH_SIZE) {
                            batchExecute(sql, batch);
                            totalLoaded += batch.size();
                            batch.clear();
                            if (totalLoaded % 5000 == 0) {
                                LOG.info("  ... loaded {} station names so far", totalLoaded);
                            }
                        }
                    }
                    String idStr = line.substring(0, line.length() - 1).trim();
                    try {
                        currentId = Long.parseLong(idStr);
                    } catch (NumberFormatException e) {
                        currentId = null;
                    }
                    operationId = null;
                    solarSystemId = null;
                    continue;
                }

                if (currentId == null) continue;
                String trimmed = line.stripLeading();

                if (trimmed.startsWith("operationID:")) {
                    operationId = parseIntValue(trimmed, "operationID:");
                } else if (trimmed.startsWith("solarSystemID:")) {
                    solarSystemId = parseIntValue(trimmed, "solarSystemID:");
                }
            }

            // Flush last
            if (currentId != null && solarSystemId != null) {
                String sysName = systemNames.getOrDefault(solarSystemId, "System " + solarSystemId);
                String opName = operationId != null
                        ? operationNames.getOrDefault(operationId, "Station")
                        : "Station";
                String stationName = sysName + " - " + opName;
                batch.add(new Object[]{currentId, stationName, solarSystemId});
            }
            if (!batch.isEmpty()) {
                batchExecute(sql, batch);
                totalLoaded += batch.size();
            }
        } catch (IOException e) {
            LOG.error("Failed to load npcStations.yaml", e);
            throw new RuntimeException("Failed to load npcStations.yaml", e);
        }

        LOG.info("Loaded {} station names", totalLoaded);
        return totalLoaded;
    }

    /**
     * Parses stationOperations.yaml to build a map of operationId -> English operation name.
     */
    private Map<Integer, String> loadOperationNames(Path file) {
        Map<Integer, String> result = new HashMap<>();
        if (!Files.exists(file)) {
            LOG.warn("stationOperations.yaml not found at {}", file);
            return result;
        }

        try (BufferedReader reader = Files.newBufferedReader(file, StandardCharsets.UTF_8)) {
            String line;
            Integer currentId = null;
            boolean inOperationName = false;

            while ((line = reader.readLine()) != null) {
                if (line.isEmpty()) continue;

                if (!line.startsWith(" ") && line.endsWith(":")) {
                    String idStr = line.substring(0, line.length() - 1).trim();
                    try {
                        currentId = Integer.parseInt(idStr);
                    } catch (NumberFormatException e) {
                        currentId = null;
                    }
                    inOperationName = false;
                    continue;
                }

                if (currentId == null) continue;
                String trimmed = line.stripLeading();

                if (inOperationName) {
                    if (trimmed.startsWith("en:")) {
                        String name = extractStringValue(trimmed, "en:");
                        if (name != null) {
                            result.put(currentId, name);
                        }
                        inOperationName = false;
                    } else if (!trimmed.isEmpty() && !line.startsWith("    ")) {
                        inOperationName = false;
                    }
                    continue;
                }

                if (trimmed.equals("operationName:")) {
                    inOperationName = true;
                }
            }
        } catch (IOException e) {
            LOG.warn("Failed to load stationOperations.yaml", e);
        }

        LOG.info("Loaded {} station operation names", result.size());
        return result;
    }

    /**
     * Reads solar system names from the SdeSolarSystems table (already loaded).
     */
    private Map<Integer, String> loadSystemNamesFromDb() {
        Map<Integer, String> result = new HashMap<>();
        try (Connection conn = dbManager.getConnection();
             PreparedStatement ps = conn.prepareStatement("SELECT SystemId, Name FROM SdeSolarSystems");
             ResultSet rs = ps.executeQuery()) {
            while (rs.next()) {
                result.put(rs.getInt(1), rs.getString(2));
            }
        } catch (SQLException e) {
            LOG.warn("Failed to read solar system names from DB", e);
        }
        return result;
    }

    // -------------------------------------------------------------------------
    // YAML value extraction helpers
    // -------------------------------------------------------------------------

    /**
     * Extracts a string value after a key prefix, e.g. "en: Rifter" -> "Rifter".
     * Handles both quoted and unquoted values.
     */
    private String extractStringValue(String line, String key) {
        String raw = line.substring(key.length()).trim();
        // Remove surrounding quotes if present
        if (raw.length() >= 2 &&
                ((raw.startsWith("'") && raw.endsWith("'")) ||
                 (raw.startsWith("\"") && raw.endsWith("\"")))) {
            raw = raw.substring(1, raw.length() - 1);
        }
        return raw.isEmpty() ? null : raw;
    }

    /**
     * Extracts the raw trimmed value after a key prefix.
     */
    private String extractRawValue(String line, String key) {
        return line.substring(key.length()).trim();
    }

    /**
     * Parses an integer value after a key prefix. Returns null for "null" or unparseable values.
     */
    private Integer parseIntValue(String line, String key) {
        String raw = extractRawValue(line, key);
        if (raw.isEmpty() || "null".equals(raw) || "~".equals(raw)) return null;
        try {
            // Handle values like "18.0" by truncating
            if (raw.contains(".")) {
                return (int) Double.parseDouble(raw);
            }
            return Integer.parseInt(raw);
        } catch (NumberFormatException e) {
            return null;
        }
    }

    /**
     * Parses a double value after a key prefix.
     */
    private double parseDoubleValue(String line, String key) {
        String raw = extractRawValue(line, key);
        if (raw.isEmpty() || "null".equals(raw) || "~".equals(raw)) return 0;
        try {
            return Double.parseDouble(raw);
        } catch (NumberFormatException e) {
            return 0;
        }
    }

    /**
     * Executes a batch of SQL statements directly via the DatabaseManager connection.
     */
    private void batchExecute(String sql, List<Object[]> paramSets) {
        if (paramSets.isEmpty()) return;
        try (Connection conn = dbManager.getConnection()) {
            conn.setAutoCommit(false);
            try (PreparedStatement ps = conn.prepareStatement(sql)) {
                int count = 0;
                for (Object[] params : paramSets) {
                    for (int i = 0; i < params.length; i++) {
                        if (params[i] == null) {
                            ps.setNull(i + 1, java.sql.Types.NULL);
                        } else {
                            ps.setObject(i + 1, params[i]);
                        }
                    }
                    ps.addBatch();
                    count++;
                    if (count % 1000 == 0) {
                        ps.executeBatch();
                    }
                }
                ps.executeBatch();
                conn.commit();
            } catch (SQLException e) {
                conn.rollback();
                throw e;
            }
        } catch (SQLException e) {
            throw new RuntimeException("Batch execute failed: " + sql, e);
        }
    }
}

