348	    public CompletableFuture<List<TradeOpportunity>> scanStationTrades(long stationId, double minProfit, int minVolume) {
349	        return CompletableFuture.supplyAsync(() -> {
350	            log.debug("scanStationTrades for station {} minProfit={} minVolume={}", stationId, minProfit, minVolume);
351	            try {
352	                int regionId = stationToRegion(stationId);
353	                log.info("Fetching region orders for region {} (station {})...", regionId, stationId);
354	
355	                // Fetch ALL orders in the region from ESI (paginated)
356	                List<RegionOrder> allOrders = esiClient.market.getRegionOrders(regionId).join();
357	                log.info("Fetched {} total region orders, filtering to station {}", allOrders.size(), stationId);
358	
359	                // Filter to orders at this station only
360	                List<RegionOrder> stationOrders = allOrders.stream()
361	                        .filter(o -> o.locationId() == stationId)
362	                        .toList();
363	
364	                // Group by typeId
365	                Map<Integer, List<RegionOrder>> byType = stationOrders.stream()
366	                        .collect(Collectors.groupingBy(RegionOrder::typeId));
367	
368	                List<TradeOpportunity> opportunities = new ArrayList<>();
369	                for (var entry : byType.entrySet()) {
370	                    int typeId = entry.getKey();
371	                    var orders = entry.getValue();
372	
373	                    // Find best buy (highest buy order) and best sell (lowest sell order)
374	                    OptionalDouble bestBuy = orders.stream()
375	                            .filter(RegionOrder::isBuyOrder)
376	                            .mapToDouble(RegionOrder::price)
377	                            .max();
378	                    OptionalDouble bestSell = orders.stream()
379	                            .filter(o -> !o.isBuyOrder())
380	                            .mapToDouble(RegionOrder::price)
381	                            .min();
382	
383	                    if (bestBuy.isEmpty() || bestSell.isEmpty()) continue;
384	
385	                    double buyPrice = bestBuy.getAsDouble();
386	                    double sellPrice = bestSell.getAsDouble();
387	                    double profit = sellPrice - buyPrice;
388	                    double margin = sellPrice > 0 ? profit / sellPrice : 0;
389	
390	                    // Count total sell volume for this type (calculate before filtering)
391	                    long sellVolume = orders.stream()
392	                            .filter(o -> !o.isBuyOrder())
393	                            .mapToLong(RegionOrder::volumeRemain)
394	                            .sum();
395	
396	                    if (profit < minProfit) continue;
397	                    if (margin <= 0) continue;
398	                    if (sellVolume < minVolume) continue;
399	
400	                    // Count number of sell orders (competition)
401	                    long orderCount = orders.stream()
402	                            .filter(o -> !o.isBuyOrder())
403	                            .count();
404	
405	                    String typeName = typeCacheRepo.findNameById(typeId).orElse("Type #" + typeId);
