@Override
public CompletableFuture<List<TradeOpportunity>> scanStationTrades(long stationId, double minProfit, int minVolume) {
    return CompletableFuture.supplyAsync(() -> {
        log.info("scanStationTrades for station {} minProfit={} minVolume={}", stationId, minProfit, minVolume);
        try {
            int regionId = stationToRegion(stationId);
            log.info("Fetching ALL region orders for region {} (station {})...", regionId, stationId);

            // Fetch ALL orders in the region from ESI (paginated)
            List<RegionOrder> allOrders = esiClient.market.getRegionOrders(regionId).join();
            log.info("Fetched {} total region orders for region {}", allOrders.size(), regionId);

            if (allOrders.isEmpty()) {
                log.warn("ESI returned 0 orders for region {} - API may be down or rate-limited", regionId);
                throw new RuntimeException("ESI returned no market orders for region " + regionId
                        + ". The market API may be temporarily unavailable.");
            }

            // Filter to orders at this station only
            List<RegionOrder> stationOrders = allOrders.stream()
                    .filter(o -> o.locationId() == stationId)
                    .toList();
            log.info("Filtered to {} orders at station {}", stationOrders.size(), stationId);

            // If no orders at the specific station, show top locations for debugging
            if (stationOrders.isEmpty()) {
                var topLocations = allOrders.stream()
                        .collect(Collectors.groupingBy(RegionOrder::locationId, Collectors.counting()))
                        .entrySet().stream()
                        .sorted(Map.Entry.<Long, Long>comparingByValue().reversed())
                        .limit(5)
                        .toList();
                log.warn("No orders found at station {}. Top locations in region: {}", stationId, topLocations);

                // Fall back: include all orders in the region's solar system for this station
                // Get the system ID for orders at the target station's system
                int targetSystemId = allOrders.stream()
                        .filter(o -> o.locationId() == stationId)
                        .map(RegionOrder::systemId)
                        .findFirst()
                        .orElse(stationToSystem(stationId));

                if (targetSystemId > 0) {
                    stationOrders = allOrders.stream()
                            .filter(o -> o.systemId() == targetSystemId)
                            .toList();
                    log.info("Expanded to {} orders in system {} (includes citadels)", stationOrders.size(), targetSystemId);
                }
            }

            // Group by typeId
            Map<Integer, List<RegionOrder>> byType = stationOrders.stream()
                    .collect(Collectors.groupingBy(RegionOrder::typeId));
            log.info("Found {} unique item types with orders", byType.size());

            List<TradeOpportunity> opportunities = new ArrayList<>();
            int typesWithBothSides = 0;
            for (var entry : byType.entrySet()) {
                int typeId = entry.getKey();
                var orders = entry.getValue();

                // Find best buy (highest buy order) and best sell (lowest sell order)
                OptionalDouble bestBuy = orders.stream()
                        .filter(RegionOrder::isBuyOrder)
                        .mapToDouble(RegionOrder::price)
                        .max();
                OptionalDouble bestSell = orders.stream()
                        .filter(o -> !o.isBuyOrder())
                        .mapToDouble(RegionOrder::price)
                        .min();

                if (bestBuy.isEmpty() || bestSell.isEmpty()) continue;
                typesWithBothSides++;

                double buyPrice = bestBuy.getAsDouble();
                double sellPrice = bestSell.getAsDouble();
                double profit = sellPrice - buyPrice;
                double margin = sellPrice > 0 ? profit / sellPrice : 0;

                // Count total sell volume for this type (calculate before filtering)
                long sellVolume = orders.stream()
                        .filter(o -> !o.isBuyOrder())
                        .mapToLong(RegionOrder::volumeRemain)
                        .sum();

                if (profit < minProfit) continue;
                if (margin <= 0) continue;
                if (sellVolume < minVolume) continue;

                // Count number of sell orders (competition)
                long orderCount = orders.stream()
                        .filter(o -> !o.isBuyOrder())
                        .count();

                String typeName = typeCacheRepo.findNameById(typeId).orElse("Type #" + typeId);

                opportunities.add(new TradeOpportunity(
                        typeId, typeName, buyPrice, sellPrice, margin,
                        orderCount, (double) sellVolume
                ));
            }

            // Cache the prices we found for future use
            for (var opp : opportunities) {
                stationPriceRepo.upsert(opp.typeId(), stationId, opp.buyPrice(), opp.sellPrice());
            }

            opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
            log.info("Station trade scan complete: {} types with both buy+sell, {} passed filters",
                    typesWithBothSides, opportunities.size());
            return opportunities;
        } catch (Exception e) {
            log.error("Failed to scan station trades for station {}", stationId, e);
            throw new RuntimeException("Station trade scan failed: " + e.getMessage(), e);
        }
    });
}

/**
 * Maps well-known trade hub station IDs to their solar system IDs.
 */
private static int stationToSystem(long stationId) {
    if (stationId == 60003760L) return 30000142; // Jita
    if (stationId == 60008494L) return 30002187; // Amarr
    if (stationId == 60011866L) return 30002659; // Dodixie
    if (stationId == 60004588L) return 30002510; // Rens
    if (stationId == 60005686L) return 30002053; // Hek
    return 0;
}

