239	                .thenCompose(response -> {
240	                    rateLimiter.updateFromResponse(response);
241	                    int status = response.statusCode();
242	
243	                    // Retry on gateway errors
244	                    if ((status == 502 || status == 503 || status == 504) && attempt < MAX_RETRIES) {
245	                        long delayMs = (long) Math.pow(2, attempt) * 1000;
246	                        LOG.warning("ESI returned " + status + " for " + request.uri() +
247	                                ", retry " + (attempt + 1) + "/" + MAX_RETRIES + " in " + delayMs + "ms");
248	                        CompletableFuture<EsiResponse<T>> delayed = new CompletableFuture<>();
249	                        CompletableFuture.delayedExecutor(delayMs, java.util.concurrent.TimeUnit.MILLISECONDS)
250	                                .execute(() ->
251	                                        executeWithRetry(request, type, attempt + 1)
252	                                                .thenAccept(delayed::complete)
253	                                                .exceptionally(ex -> {
