276	                .map(v -> {
277	                    try { return Integer.parseInt(v); } catch (NumberFormatException e) { return 1; }
278	                }).orElse(1);
279	
280	        String etag = response.headers().firstValue("ETag").orElse(null);
281	
282	        int errorRemain = response.headers().firstValue("X-Esi-Error-Limit-Remain")
283	                .map(v -> {
284	                    try { return Integer.parseInt(v); } catch (NumberFormatException e) { return 100; }
285	                }).orElse(100);
286	
287	        int errorReset = response.headers().firstValue("X-Esi-Error-Limit-Reset")
288	                .map(v -> {
289	                    try { return Integer.parseInt(v); } catch (NumberFormatException e) { return 60; }
290	                }).orElse(60);
