296	                    } catch (Exception e) {
297	                        return LocalDateTime.now();
298	                    }
299	                }).orElse(LocalDateTime.now());
300	
301	        return new EsiResponse<>(data, response.statusCode(), pages, etag, errorRemain, errorReset, expires);
