package com.sampleapp.data.repository;

import com.sampleapp.data.DatabaseManager;
import jakarta.inject.Inject;
import jakarta.inject.Singleton;

import java.sql.Timestamp;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Optional;

/**
 * Repository for the Characters table.
 */
@Singleton
public class CharacterRepository extends BaseRepository {

    public record CharacterRow(
            int characterId, String name, String ownerHash,
            Integer corporationId, Integer allianceId,
            String refreshToken, LocalDateTime lastSync
    ) {}

    private static final RowMapper<CharacterRow> MAPPER = rs -> new CharacterRow(
            rs.getInt("CharacterId"),
            rs.getString("Name"),
            rs.getString("OwnerHash"),
            rs.getObject("CorporationId") != null ? rs.getInt("CorporationId") : null,
            rs.getObject("AllianceId") != null ? rs.getInt("AllianceId") : null,
            rs.getString("RefreshToken"),
            rs.getTimestamp("LastSync") != null ? rs.getTimestamp("LastSync").toLocalDateTime() : null
    );

    @Inject
    public CharacterRepository(DatabaseManager db) {
        super(db);
    }

    public Optional<CharacterRow> findById(int characterId) {
        return queryOne("SELECT * FROM Characters WHERE CharacterId = ?",
                MAPPER, characterId);
    }

    public List<CharacterRow> findAll() {
        return query("SELECT * FROM Characters ORDER BY Name", MAPPER);
    }

    public Optional<CharacterRow> findByName(String name) {
        return queryOne("SELECT * FROM Characters WHERE Name = ?", MAPPER, name);
    }

    public void upsert(CharacterRow row) {
        update("""
                MERGE INTO Characters
                (CharacterId, Name, OwnerHash, CorporationId, AllianceId,
                 RefreshToken, LastSync)
                KEY (CharacterId)
                VALUES (?, ?, ?, ?, ?, ?, ?)
                """,
                row.characterId(), row.name(), row.ownerHash(),
                row.corporationId(), row.allianceId(), row.refreshToken(),
                row.lastSync() != null ? Timestamp.valueOf(row.lastSync()) : null);
    }

    public void updateRefreshToken(int characterId, String refreshToken) {
        update("UPDATE Characters SET RefreshToken = ? WHERE CharacterId = ?",
                refreshToken, characterId);
    }

    public void updateLastSync(int characterId, LocalDateTime lastSync) {
        update("UPDATE Characters SET LastSync = ? WHERE CharacterId = ?",
                Timestamp.valueOf(lastSync), characterId);
    }

    public void updateCorporationAndAlliance(int characterId, Integer corporationId,
                                              Integer allianceId) {
        update("""
                UPDATE Characters
                SET CorporationId = ?, AllianceId = ?
                WHERE CharacterId = ?
                """, corporationId, allianceId, characterId);
    }

    public int delete(int characterId) {
        return update("DELETE FROM Characters WHERE CharacterId = ?", characterId);
    }
}

