25	/**
26	 * Main facade for accessing the EVE Swagger Interface (ESI) API.
27	 * <p>
28	 * Provides typed sub-clients for each API area, automatic pagination,
29	 * rate limiting, retry with exponential backoff, and ETag-based caching support.
30	 */
31	@Singleton
32	public class EsiClient {
33	
34	    private static final Logger LOG = Logger.getLogger(EsiClient.class.getName());
35	
