37	    private static final String USER_AGENT = "SampleApp/2.1.245 (Redacted User)";
38	    private static final int MAX_RETRIES = 3;
39	    private static final Duration CONNECT_TIMEOUT = Duration.ofSeconds(10);
40	    private static final Duration REQUEST_TIMEOUT = Duration.ofSeconds(30);
