55	    public final IndustryApi industry;
56	    public final SkillsApi skills;
57	    public final LoyaltyApi loyalty;
58	    public final FleetsApi fleets;
59	    public final SearchApi search;
60	    public final RoutesApi routes;
61	    public final UserInterfaceApi ui;
62	    public final ImageApi images;
63	
64	    public EsiClient() {
65	        this(new TokenManager());
66	    }
67	
68	    public EsiClient(TokenManager tokenManager) {
69	        this.httpClient = HttpClient.newBuilder()
70	                .connectTimeout(CONNECT_TIMEOUT)
71	                .followRedirects(HttpClient.Redirect.NORMAL)
72	                .build();
73	
74	        this.objectMapper = new ObjectMapper()
75	                .registerModule(new JavaTimeModule())
76	                .configure(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES, false)
77	                .configure(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS, false);
78	
79	        this.rateLimiter = new RateLimiter();
80	        this.tokenManager = tokenManager;
81	
82	        this.characters = new CharacterApi(this);
83	        this.corporations = new CorporationApi(this);
84	        this.assets = new AssetsApi(this);
85	        this.market = new MarketApi(this);
86	        this.universe = new UniverseApi(this);
87	        this.wallet = new WalletApi(this);
88	        this.contracts = new ContractsApi(this);
