99	    // ---- Public HTTP methods ----
100	
101	    public <T> CompletableFuture<EsiResponse<T>> get(String path, TypeReference<T> type, String token) {
102	        return get(path, type, token, null);
103	    }
104	
105	    public <T> CompletableFuture<EsiResponse<T>> get(String path, TypeReference<T> type, String token, String etag) {
106	        return rateLimiter.acquire().thenCompose(v -> {
107	            HttpRequest.Builder builder = HttpRequest.newBuilder()
108	                    .uri(URI.create(BASE_URL + path))
109	                    .header("User-Agent", USER_AGENT)
110	                    .header("Accept", "application/json")
111	                    .timeout(REQUEST_TIMEOUT)
112	                    .GET();
113	
114	            if (token != null && !token.isBlank()) {
115	                builder.header("Authorization", "Bearer " + token);
116	            }
117	            if (etag != null && !etag.isBlank()) {
118	                builder.header("If-None-Match", etag);
119	            }
120	
121	            return executeWithRetry(builder.build(), type, 0);
122	        });
123	    }
124	
125	    public <T> CompletableFuture<EsiResponse<T>> post(String path, Object body, TypeReference<T> type, String token) {
126	        return rateLimiter.acquire().thenCompose(v -> {
127	            try {
128	                String jsonBody = objectMapper.writeValueAsString(body);
129	                HttpRequest.Builder builder = HttpRequest.newBuilder()
130	                        .uri(URI.create(BASE_URL + path))
131	                        .header("User-Agent", USER_AGENT)
132	                        .header("Accept", "application/json")
133	                        .header("Content-Type", "application/json")
134	                        .timeout(REQUEST_TIMEOUT)
135	                        .POST(HttpRequest.BodyPublishers.ofString(jsonBody));
136	
137	                if (token != null && !token.isBlank()) {
138	                    builder.header("Authorization", "Bearer " + token);
139	                }
140	
141	                return executeWithRetry(builder.build(), type, 0);
142	            } catch (Exception e) {
143	                return CompletableFuture.failedFuture(e);
144	            }
145	        });
146	    }
147	
148	    /**
149	     * POST with empty body (used by UI endpoints).
150	     */
151	    public CompletableFuture<EsiResponse<Void>> postEmpty(String path, String token) {
152	        return rateLimiter.acquire().thenCompose(v -> {
153	            HttpRequest.Builder builder = HttpRequest.newBuilder()
154	                    .uri(URI.create(BASE_URL + path))
155	                    .header("User-Agent", USER_AGENT)
156	                    .header("Accept", "application/json")
157	                    .timeout(REQUEST_TIMEOUT)
158	                    .POST(HttpRequest.BodyPublishers.noBody());
