347	    @Override
348	    public CompletableFuture<List<TradeOpportunity>> scanStationTrades(long stationId, double minProfit, int minVolume) {
349	        return CompletableFuture.supplyAsync(() -> {
350	            log.info("scanStationTrades for station {} minProfit={} minVolume={}", stationId, minProfit, minVolume);
351	            try {
352	                int regionId = stationToRegion(stationId);
353	                log.info("Fetching ALL region orders for region {} (station {})...", regionId, stationId);
354	
355	                // Fetch ALL orders in the region from ESI (paginated)
356	                List<RegionOrder> allOrders = esiClient.market.getRegionOrders(regionId).join();
357	                log.info("Fetched {} total region orders for region {}", allOrders.size(), regionId);
358	
359	                if (allOrders.isEmpty()) {
360	                    log.warn("ESI returned 0 orders for region {} - API may be down or rate-limited", regionId);
361	                    throw new RuntimeException("ESI returned no market orders for region " + regionId
362	                            + ". The market API may be temporarily unavailable.");
363	                }
364	
365	                // Filter to orders at this station only
366	                List<RegionOrder> stationOrders = allOrders.stream()
367	                        .filter(o -> o.locationId() == stationId)
368	                        .toList();
369	                log.info("Filtered to {} orders at station {}", stationOrders.size(), stationId);
370	
371	                // If no orders at the specific station, show top locations for debugging
372	                if (stationOrders.isEmpty()) {
373	                    var topLocations = allOrders.stream()
374	                            .collect(Collectors.groupingBy(RegionOrder::locationId, Collectors.counting()))
375	                            .entrySet().stream()
376	                            .sorted(Map.Entry.<Long, Long>comparingByValue().reversed())
377	                            .limit(5)
378	                            .toList();
379	                    log.warn("No orders found at station {}. Top locations in region: {}", stationId, topLocations);
380	
381	                    // Fall back: include all orders in the region's solar system for this station
382	                    // Get the system ID for orders at the target station's system
383	                    int targetSystemId = allOrders.stream()
384	                            .filter(o -> o.locationId() == stationId)
385	                            .map(RegionOrder::systemId)
386	                            .findFirst()
387	                            .orElse(stationToSystem(stationId));
388	
389	                    if (targetSystemId > 0) {
390	                        stationOrders = allOrders.stream()
391	                                .filter(o -> o.systemId() == targetSystemId)
392	                                .toList();
393	                        log.info("Expanded to {} orders in system {} (includes citadels)", stationOrders.size(), targetSystemId);
394	                    }
395	                }
396	
397	                // Group by typeId
398	                Map<Integer, List<RegionOrder>> byType = stationOrders.stream()
399	                        .collect(Collectors.groupingBy(RegionOrder::typeId));
400	                log.info("Found {} unique item types with orders", byType.size());
401	
402	                List<TradeOpportunity> opportunities = new ArrayList<>();
403	                int typesWithBothSides = 0;
404	                for (var entry : byType.entrySet()) {
405	                    int typeId = entry.getKey();
406	                    var orders = entry.getValue();
407	
408	                    // Find best buy (highest buy order) and best sell (lowest sell order)
409	                    OptionalDouble bestBuy = orders.stream()
410	                            .filter(RegionOrder::isBuyOrder)
411	                            .mapToDouble(RegionOrder::price)
412	                            .max();
413	                    OptionalDouble bestSell = orders.stream()
414	                            .filter(o -> !o.isBuyOrder())
415	                            .mapToDouble(RegionOrder::price)
416	                            .min();
417	
418	                    if (bestBuy.isEmpty() || bestSell.isEmpty()) continue;
419	                    typesWithBothSides++;
420	
421	                    double buyPrice = bestBuy.getAsDouble();
422	                    double sellPrice = bestSell.getAsDouble();
423	                    double profit = sellPrice - buyPrice;
424	                    double margin = sellPrice > 0 ? profit / sellPrice : 0;
425	
426	                    // Count total sell volume for this type (calculate before filtering)
427	                    long sellVolume = orders.stream()
428	                            .filter(o -> !o.isBuyOrder())
429	                            .mapToLong(RegionOrder::volumeRemain)
430	                            .sum();
431	
432	                    if (profit < minProfit) continue;
433	                    if (margin <= 0) continue;
434	                    if (sellVolume < minVolume) continue;
435	
436	                    // Count number of sell orders (competition)
437	                    long orderCount = orders.stream()
438	                            .filter(o -> !o.isBuyOrder())
439	                            .count();
440	
441	                    String typeName = typeCacheRepo.findNameById(typeId).orElse("Type #" + typeId);
442	
443	                    opportunities.add(new TradeOpportunity(
444	                            typeId, typeName, buyPrice, sellPrice, margin,
445	                            orderCount, (double) sellVolume
446	                    ));
447	                }
448	
449	                // Cache the prices we found for future use
450	                for (var opp : opportunities) {
451	                    stationPriceRepo.upsert(opp.typeId(), stationId, opp.buyPrice(), opp.sellPrice());
452	                }
453	
454	                opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
455	                log.info("Station trade scan complete: {} types with both buy+sell, {} passed filters",
456	                        typesWithBothSides, opportunities.size());
457	                return opportunities;
458	            } catch (Exception e) {
459	                log.error("Failed to scan station trades for station {}", stationId, e);
460	                throw new RuntimeException("Station trade scan failed: " + e.getMessage(), e);
461	            }
462	        });
463	    }
