477	    @Override
478	    public CompletableFuture<List<TradeOpportunity>> scanRegionalTrades(int fromRegionId, int toRegionId,
479	                                                                        double minMargin, double maxCargo, double budget) {
480	        return CompletableFuture.supplyAsync(() -> {
481	            log.debug("scanRegionalTrades from {} to {} minMargin={} maxCargo={} budget={}",
482	                    fromRegionId, toRegionId, minMargin, maxCargo, budget);
483	            try {
484	                log.info("Fetching region orders for regions {} and {}...", fromRegionId, toRegionId);
485	
486	                // Fetch orders from both regions in parallel
487	                var fromOrdersFuture = esiClient.market.getRegionOrders(fromRegionId);
488	                var toOrdersFuture = esiClient.market.getRegionOrders(toRegionId);
489	
490	                List<RegionOrder> fromOrders = fromOrdersFuture.join();
491	                List<RegionOrder> toOrders = toOrdersFuture.join();
492	                log.info("Fetched {} orders from source region, {} from destination region",
493	                        fromOrders.size(), toOrders.size());
494	
495	                // Build price maps: for source, find lowest sell price per type
496	                Map<Integer, Double> sourceSellPrices = new HashMap<>();
497	                Map<Integer, Long> sourceVolumes = new HashMap<>();
498	                for (var order : fromOrders) {
499	                    if (order.isBuyOrder()) continue; // skip buy orders
500	                    sourceSellPrices.merge(order.typeId(), order.price(), Math::min);
501	                    sourceVolumes.merge(order.typeId(), (long) order.volumeRemain(), Long::sum);
502	                }
503	
504	                // For destination, find lowest sell price (what we undercut)
505	                Map<Integer, Double> destSellPrices = new HashMap<>();
506	                for (var order : toOrders) {
507	                    if (order.isBuyOrder()) continue;
508	                    destSellPrices.merge(order.typeId(), order.price(), Math::min);
509	                }
510	
511	                List<TradeOpportunity> opportunities = new ArrayList<>();
512	                for (var entry : sourceSellPrices.entrySet()) {
513	                    int typeId = entry.getKey();
514	                    double buyCost = entry.getValue();
515	                    Double sellRevenue = destSellPrices.get(typeId);
516	
517	                    if (sellRevenue == null || buyCost <= 0 || sellRevenue <= 0) continue;
518	
519	                    double margin = (sellRevenue - buyCost) / sellRevenue;
520	                    if (margin < minMargin) continue;
521	
522	                    // Check cargo volume constraint
523	                    var typeInfo = typeCacheRepo.findById(typeId);
524	                    if (typeInfo.isPresent() && maxCargo > 0) {
525	                        double vol = typeInfo.get().packagedVolume() > 0
526	                                ? typeInfo.get().packagedVolume()
527	                                : typeInfo.get().volume();
528	                        if (vol > maxCargo) continue;
529	                    }
530	
531	                    // Check budget constraint
532	                    if (budget > 0 && buyCost > budget) continue;
533	
534	                    long volume = sourceVolumes.getOrDefault(typeId, 0L);
535	                    String typeName = typeCacheRepo.findNameById(typeId).orElse("Type #" + typeId);
536	
537	                    opportunities.add(new TradeOpportunity(
538	                            typeId, typeName, buyCost, sellRevenue, margin,
539	                            volume, (double) volume
540	                    ));
541	                }
542	
543	                opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
544	                log.info("Found {} regional trade opportunities", opportunities.size());
545	                return opportunities;
546	            } catch (Exception e) {
547	                log.error("Failed to scan regional trades from {} to {}", fromRegionId, toRegionId, e);
548	                return List.of();
549	            }
550	        });
551	    }
