553	    /**
554	     * Maps well-known trade hub station IDs to their region IDs.
555	     */
556	    private static int stationToRegion(long stationId) {
557	        if (stationId == 60003760L) return 10000002; // Jita -> The Forge
558	        if (stationId == 60008494L) return 10000043; // Amarr -> Domain
559	        if (stationId == 60011866L) return 10000032; // Dodixie -> Sinq Laison
560	        if (stationId == 60004588L) return 10000030; // Rens -> Heimatar
561	        if (stationId == 60005686L) return 10000042; // Hek -> Metropolis
562	        return 10000002; // default to The Forge
563	    }
