726	    @Override
727	    public CompletableFuture<List<FleetMemberInfo>> getFleetMembers(int characterId) {
728	        return CompletableFuture.supplyAsync(() -> {
729	            log.debug("getFleetMembers for character {}", characterId);
730	            try {
731	                String token = tokenManager.getValidToken(characterId).join();
732	                // First get the character's fleet ID
733	                var fleetInfoResp = esiClient.fleets.getCharacterFleet(characterId, token).join();
734	                if (!fleetInfoResp.isSuccess() || fleetInfoResp.data() == null) {
735	                    return List.<FleetMemberInfo>of();
736	                }
737	                long fleetId = fleetInfoResp.data().fleetId();
738	
739	                // Get fleet members
740	                var membersResp = esiClient.fleets.getFleetMembers(fleetId, token).join();
741	                if (!membersResp.isSuccess() || membersResp.data() == null) {
742	                    return List.<FleetMemberInfo>of();
743	                }
744	
745	                // Get fleet wings for wing/squad names
746	                var wingsResp = esiClient.fleets.getFleetWings(fleetId, token).join();
747	                Map<Long, String> wingNames = new HashMap<>();
748	                Map<Long, String> squadNames = new HashMap<>();
749	                if (wingsResp.isSuccess() && wingsResp.data() != null) {
750	                    for (var wing : wingsResp.data()) {
751	                        wingNames.put(wing.id(), wing.name());
752	                        if (wing.squads() != null) {
753	                            for (var squad : wing.squads()) {
754	                                squadNames.put(squad.id(), squad.name());
755	                            }
756	                        }
757	                    }
758	                }
759	
760	                // Resolve character names via universe names
761	                List<Integer> charIds = membersResp.data().stream()
762	                        .map(com.sampleapp.esi.dto.FleetMember::characterId)
763	                        .toList();
764	                Map<Integer, String> charNames = new HashMap<>();
765	                if (!charIds.isEmpty()) {
766	                    try {
767	                        var namesResp = esiClient.universe.getNames(charIds).join();
768	                        if (namesResp.isSuccess() && namesResp.data() != null) {
769	                            for (var name : namesResp.data()) {
770	                                charNames.put(name.id(), name.name());
771	                            }
772	                        }
773	                    } catch (Exception e) {
774	                        log.warn("Failed to resolve fleet member names", e);
775	                    }
