905	    public CompletableFuture<String> resolveLocationName(long locationId) {
906	        // Check cache first
907	        String cached = locationNameCache.get(locationId);
908	        if (cached != null) return CompletableFuture.completedFuture(cached);
909	
910	        return CompletableFuture.supplyAsync(() -> {
911	            String name = resolveLocationNameSync(locationId);
912	            locationNameCache.put(locationId, name);
913	            return name;
914	        });
