917	    private String resolveLocationNameSync(long locationId) {
918	        if (locationId <= 0) return "Unknown Location";
919	
920	        // Solar system IDs: 30,000,000 - 33,000,000
921	        if (locationId >= 30_000_000 && locationId < 33_000_000) {
922	            // Try SDE first (fast, no network)
923	            try (var conn = dbManager.getConnection();
924	                 var ps = conn.prepareStatement("SELECT Name FROM SdeSolarSystems WHERE SystemId = ?")) {
925	                ps.setInt(1, (int) locationId);
926	                var rs = ps.executeQuery();
927	                if (rs.next()) {
928	                    String name = rs.getString(1);
929	                    if (name != null) return name;
930	                }
931	            } catch (Exception e) {
932	                log.debug("SDE solar system lookup failed for {}, falling back to ESI", locationId);
933	            }
934	            // Fall back to ESI
935	            try {
936	                var resp = esiClient.universe.getSystem((int) locationId).join();
937	                if (resp.isSuccess() && resp.data() != null) {
938	                    return resp.data().name();
939	                }
940	            } catch (Exception e) {
941	                log.debug("Failed to resolve system name for {}", locationId, e);
942	            }
943	        }
944	
945	        // NPC station IDs: 60,000,000 - 64,000,000
946	        if (locationId >= 60_000_000 && locationId < 64_000_000) {
947	            // Try SDE first (fast, no network)
948	            try (var conn = dbManager.getConnection();
949	                 var ps = conn.prepareStatement("SELECT StationName FROM SdeStationNames WHERE StationId = ?")) {
950	                ps.setLong(1, locationId);
951	                var rs = ps.executeQuery();
952	                if (rs.next()) {
953	                    String name = rs.getString(1);
954	                    if (name != null) return name;
955	                }
956	            } catch (Exception e) {
957	                log.debug("SDE station name lookup failed for {}, falling back to ESI", locationId);
958	            }
959	            // Fall back to ESI
960	            try {
961	                var resp = esiClient.universe.getStation((int) locationId).join();
962	                if (resp.isSuccess() && resp.data() != null) {
963	                    return resp.data().name();
964	                }
965	            } catch (Exception e) {
966	                log.debug("Failed to resolve station name for {}", locationId, e);
967	            }
968	        }
969	
970	        // Structures: >= 64,000,000 (Upwell structures, requires auth)
971	        if (locationId >= 64_000_000) {
972	            // Try to resolve via any available character token
973	            try {
974	                var characters = characterRepo.findAll();
975	                for (var character : characters) {
976	                    try {
977	                        String token = tokenManager.getValidToken(character.characterId()).join();
978	                        var resp = esiClient.universe.getStructure(locationId, token).join();
979	                        if (resp.isSuccess() && resp.data() != null) {
980	                            return resp.data().name();
981	                        }
982	                    } catch (Exception e) {
983	                        // This character may not have access, try next
984	                        continue;
985	                    }
986	                }
987	            } catch (Exception e) {
988	                log.debug("Failed to resolve structure name for {}", locationId, e);
989	            }
990	            // Fall back: try to find the solar system from assets and show "Structure in <system>"
991	            return "Structure " + locationId;
992	        }
993	
994	        // Try universe names API as a fallback for other ID ranges
995	        if (locationId > 0 && locationId <= Integer.MAX_VALUE) {
996	            try {
997	                var resp = esiClient.universe.getNames(List.of((int) locationId)).join();
998	                if (resp.isSuccess() && resp.data() != null && !resp.data().isEmpty()) {
999	                    return resp.data().get(0).name();
1000	                }
1001	            } catch (Exception e) {
1002	                log.debug("Failed to resolve name via universe names for {}", locationId, e);
1003	            }
1004	        }
1005	
1006	        return "Location " + locationId;
1007	    }
