37	    @SuppressWarnings("unchecked")
38	    private Tab createPublicContractsTab() {
39	        var tab = new Tab("Public Contracts");
40	
41	        var vbox = new VBox(10);
42	        vbox.setPadding(new Insets(10));
43	
44	        // Search/filter controls
45	        var filterBox = new HBox(10);
46	        var regionCombo = new ComboBox<String>();
47	        regionCombo.getItems().addAll("All Regions", "The Forge", "Domain",
48	                "Sinq Laison", "Metropolis", "Heimatar");
49	        regionCombo.setValue("The Forge");
50	        var typeFilter = new ComboBox<String>();
51	        typeFilter.getItems().addAll("All", "Item Exchange", "Auction", "Courier");
52	        typeFilter.setValue("All");
53	        var searchField = new TextField();
54	        searchField.setPromptText("Search contracts...");
55	        searchField.setPrefWidth(200);
56	        var searchBtn = new Button("Search");
57	        var statusLabel = new Label("");
58	        statusLabel.setStyle("-fx-text-fill: #AAAAAA;");
59	        filterBox.getChildren().addAll(
60	                new Label("Region:"), regionCombo,
61	                new Label("Type:"), typeFilter,
62	                searchField, searchBtn, statusLabel
63	        );
64	
65	        // Contracts table
66	        var table = new TableView<ContractModel>();
67	        var typeCol = new TableColumn<ContractModel, String>("Type");
68	        typeCol.setPrefWidth(100);
69	        typeCol.setCellValueFactory(c -> new SimpleStringProperty(
70	                c.getValue().type() != null ? c.getValue().type() : "--"));
71	        var titleCol = new TableColumn<ContractModel, String>("Status");
72	        titleCol.setPrefWidth(100);
73	        titleCol.setCellValueFactory(c -> new SimpleStringProperty(
74	                c.getValue().status() != null ? c.getValue().status() : "--"));
