89	        var availCol = new TableColumn<ContractModel, String>("Availability");
90	        availCol.setPrefWidth(120);
91	        availCol.setCellValueFactory(c -> new SimpleStringProperty(
92	                c.getValue().availability() != null ? c.getValue().availability() : "--"));
93	        var issuerCol = new TableColumn<ContractModel, String>("Issuer");
94	        issuerCol.setPrefWidth(150);
95	        issuerCol.setCellValueFactory(c -> {
96	            var contract = c.getValue();
97	            if (contract.forCorporation()) {
98	                int corpId = contract.issuerCorporationId();
99	                var prop = new SimpleStringProperty("Corp #" + corpId);
100	                dataService.resolveCorporationName(corpId)
101	                        .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
102	                return prop;
103	            } else {
104	                int issuerId = contract.issuerId();
105	                var prop = new SimpleStringProperty("Pilot #" + issuerId);
