package com.sampleapp.ui.workspace;

import com.sampleapp.core.app.AppState;
import com.sampleapp.core.model.ContractModel;
import javafx.application.Platform;
import javafx.beans.property.SimpleDoubleProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.geometry.Orientation;
import javafx.scene.control.*;
import javafx.scene.layout.*;

import com.sampleapp.common.IskFormatter;

import java.time.format.DateTimeFormatter;

/**
 * Public Contracts workspace with a single tab for browsing public contracts.
 */
public class PublicContractsWorkspace extends Workspace {

    private static final DateTimeFormatter DT_FMT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");

    private final WorkspaceDataService dataService;

    private final ObservableList<ContractModel> contractsList = FXCollections.observableArrayList();

    public PublicContractsWorkspace(AppState appState, WorkspaceDataService dataService) {
        super(appState);
        this.dataService = dataService;

        tabPane.getTabs().add(createPublicContractsTab());
    }

    @SuppressWarnings("unchecked")
    private Tab createPublicContractsTab() {
        var tab = new Tab("Public Contracts");

        var vbox = new VBox(10);
        vbox.setPadding(new Insets(10));

        // Search/filter controls
        var filterBox = new HBox(10);
        var regionCombo = new ComboBox<String>();
        regionCombo.getItems().addAll("All Regions", "The Forge", "Domain",
                "Sinq Laison", "Metropolis", "Heimatar");
        regionCombo.setValue("The Forge");
        var typeFilter = new ComboBox<String>();
        typeFilter.getItems().addAll("All", "Item Exchange", "Auction", "Courier");
        typeFilter.setValue("All");
        var searchField = new TextField();
        searchField.setPromptText("Search contracts...");
        searchField.setPrefWidth(200);
        var searchBtn = new Button("Search");
        var statusLabel = new Label("");
        statusLabel.setStyle("-fx-text-fill: #AAAAAA;");
        filterBox.getChildren().addAll(
                new Label("Region:"), regionCombo,
                new Label("Type:"), typeFilter,
                searchField, searchBtn, statusLabel
        );

        // Contracts table
        var table = new TableView<ContractModel>();
        var typeCol = new TableColumn<ContractModel, String>("Type");
        typeCol.setPrefWidth(100);
        typeCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().type() != null ? c.getValue().type() : "--"));
        var titleCol = new TableColumn<ContractModel, String>("Status");
        titleCol.setPrefWidth(100);
        titleCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().status() != null ? c.getValue().status() : "--"));
        var priceCol = new TableColumn<ContractModel, Number>("Price");
        priceCol.setPrefWidth(120);
        priceCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().price()));
        priceCol.setCellFactory(col -> new TableCell<>() {
            @Override
            protected void updateItem(Number item, boolean empty) {
                super.updateItem(item, empty);
                if (empty || item == null) setText(null);
                else setText(IskFormatter.formatRaw(item.doubleValue()));
            }
        });
        var volumeCol = new TableColumn<ContractModel, Number>("Volume");
        volumeCol.setPrefWidth(80);
        volumeCol.setCellValueFactory(c -> new SimpleDoubleProperty(c.getValue().volume()));
        var availCol = new TableColumn<ContractModel, String>("Availability");
        availCol.setPrefWidth(120);
        availCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().availability() != null ? c.getValue().availability() : "--"));
        var issuerCol = new TableColumn<ContractModel, String>("Issuer");
        issuerCol.setPrefWidth(150);
        issuerCol.setCellValueFactory(c -> {
            var contract = c.getValue();
            if (contract.forCorporation()) {
                int corpId = contract.issuerCorporationId();
                var prop = new SimpleStringProperty("Corp #" + corpId);
                dataService.resolveCorporationName(corpId)
                        .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
                return prop;
            } else {
                int issuerId = contract.issuerId();
                var prop = new SimpleStringProperty("Pilot #" + issuerId);
                dataService.resolveCharacterName(issuerId)
                        .thenAccept(name -> Platform.runLater(() -> prop.set(name)));
                return prop;
            }
        });
        var expiresCol = new TableColumn<ContractModel, String>("Expires");
        expiresCol.setPrefWidth(130);
        expiresCol.setCellValueFactory(c -> new SimpleStringProperty(
                c.getValue().dateExpired() != null ? c.getValue().dateExpired().format(DT_FMT) : "--"));

        table.getColumns().addAll(typeCol, titleCol, priceCol, volumeCol,
                availCol, issuerCol, expiresCol);
        table.setItems(contractsList);
        table.setPlaceholder(new Label("Search for public contracts"));

        // Contract detail pane
        var detailPane = new VBox(5);
        detailPane.setPadding(new Insets(5));
        var detailLabel = new Label("Select a contract to view items");
        detailLabel.setStyle("-fx-font-weight: bold; -fx-text-fill: #CCCCCC;");

        var itemsTable = new TableView<WorkspaceDataService.ContractItemInfo>();
        var ciNameCol = new TableColumn<WorkspaceDataService.ContractItemInfo, String>("Item");
        ciNameCol.setPrefWidth(250);
        ciNameCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().typeName()));
        var ciQtyCol = new TableColumn<WorkspaceDataService.ContractItemInfo, Number>("Quantity");
        ciQtyCol.setPrefWidth(80);
        ciQtyCol.setCellValueFactory(c -> new javafx.beans.property.SimpleIntegerProperty(c.getValue().quantity()));
        var ciIncludedCol = new TableColumn<WorkspaceDataService.ContractItemInfo, String>("Included");
        ciIncludedCol.setPrefWidth(80);
        ciIncludedCol.setCellValueFactory(c -> new SimpleStringProperty(c.getValue().isIncluded() ? "Yes" : "No"));
        var ciJitaBuyCol = new TableColumn<WorkspaceDataService.ContractItemInfo, String>("Jita Buy");
        ciJitaBuyCol.setPrefWidth(120);
        ciJitaBuyCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().jitaBuyPrice())));
        var ciJitaSellCol = new TableColumn<WorkspaceDataService.ContractItemInfo, String>("Jita Sell");
        ciJitaSellCol.setPrefWidth(120);
        ciJitaSellCol.setCellValueFactory(c -> new SimpleStringProperty(
                IskFormatter.formatRaw(c.getValue().jitaSellPrice())));
        itemsTable.getColumns().addAll(ciNameCol, ciQtyCol, ciIncludedCol, ciJitaBuyCol, ciJitaSellCol);
        itemsTable.setPlaceholder(new Label("No items"));

        detailPane.getChildren().addAll(detailLabel, itemsTable);
        VBox.setVgrow(itemsTable, Priority.ALWAYS);

        // Wire selection to load contract items
        table.getSelectionModel().selectedItemProperty().addListener((obs, old, sel) -> {
            if (sel == null) {
                detailLabel.setText("Select a contract to view items");
                itemsTable.getItems().clear();
                return;
            }
            long contractId = sel.contractId();
            detailLabel.setText("Loading items for contract #" + contractId + "...");
            itemsTable.getItems().clear();
            dataService.getPublicContractItems(contractId)
                    .thenAccept(items -> Platform.runLater(() -> {
                        detailLabel.setText("Items in contract #" + contractId + " (" + items.size() + " items)");
                        itemsTable.getItems().setAll(items);
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> detailLabel.setText("Failed to load items"));
                        return null;
                    });
        });

        searchBtn.setOnAction(e -> {
            searchBtn.setDisable(true);
            statusLabel.setText("Searching...");
            String region = regionCombo.getValue();
            String type = typeFilter.getValue();

            int regionId = regionNameToId(region);
            String typeQuery = "All".equals(type) ? null : type;

            dataService.getPublicContracts(regionId, typeQuery)
                    .thenAccept(data -> Platform.runLater(() -> {
                        contractsList.setAll(data);
                        statusLabel.setText(data.size() + " contracts found");
                        searchBtn.setDisable(false);
                    }))
                    .exceptionally(ex -> {
                        Platform.runLater(() -> {
                            log.error("Failed to load public contracts", ex);
                            statusLabel.setText("Error loading contracts");
                            searchBtn.setDisable(false);
                        });
                        return null;
                    });
        });

        // Layout with SplitPane
        var splitPane = new SplitPane();
        splitPane.setOrientation(Orientation.VERTICAL);
        splitPane.setDividerPositions(0.6);
        VBox.setVgrow(table, Priority.ALWAYS);
        var topBox = new VBox(filterBox, table);
        VBox.setVgrow(table, Priority.ALWAYS);
        splitPane.getItems().addAll(topBox, detailPane);
        VBox.setVgrow(splitPane, Priority.ALWAYS);

        vbox.getChildren().addAll(splitPane);
        tab.setContent(vbox);
        return tab;
    }

    private static int regionNameToId(String name) {
        return switch (name) {
            case "The Forge" -> 10000002;
            case "Domain" -> 10000043;
            case "Sinq Laison" -> 10000032;
            case "Metropolis" -> 10000042;
            case "Heimatar" -> 10000030;
            case "All Regions" -> 0;
            default -> 10000002;
        };
    }

    @Override
    public String getTitle() { return "Public Contracts"; }

    @Override
    public void onActivated() { log.debug("Public Contracts workspace activated"); }

    @Override
    public void onCharacterChanged(int characterId) {
        // Public contracts are not character-specific
    }
}

