                "/v1/corporations/" + corporationId + "/contracts/" + contractId + "/bids/",
                new TypeReference<>() {},
                token
        );
    }

    /** GET /v1/corporations/{corporationId}/contracts/{contractId}/items/ */
    public CompletableFuture<EsiResponse<List<ContractItem>>> getCorporationContractItems(
            int corporationId, long contractId, String token) {
        return client.get(
                "/v1/corporations/" + corporationId + "/contracts/" + contractId + "/items/",
                new TypeReference<>() {},
                token
        );
    }

    /** GET /v1/contracts/public/{regionId}/ — paginated */
    public CompletableFuture<List<Contract>> getPublicContracts(int regionId) {
        return client.getAllPages(
                "/v1/contracts/public/" + regionId + "/",
                new TypeReference<>() {},
                null
        );
    }

    /** GET /v1/contracts/public/bids/{contractId}/ — paginated */
    public CompletableFuture<List<ContractBid>> getPublicContractBids(long contractId) {
        return client.getAllPages(
