    /** GET /v1/contracts/public/items/{contractId}/ — paginated */
    public CompletableFuture<List<ContractItem>> getPublicContractItems(long contractId) {
        return client.getAllPages(
                "/v1/contracts/public/items/" + contractId + "/",
                new TypeReference<>() {},
