337	        injector.getInstance(com.sampleapp.core.app.FeatureGate.class);
338	
339	        // Subscription FeatureGate (used by StationTradeService) - enable all in dev mode
340	        var subscriptionGate = injector.getInstance(com.sampleapp.core.subscription.FeatureGate.class);
341	        if (devMode) {
342	            subscriptionGate.enableAll();
343	        }
344	    }
