346	    private void populateItemTypeCache() {
347	        try {
348	            var typeCacheRepo = injector.getInstance(TypeCacheRepository.class);
349	            var itemTypeCache = injector.getInstance(ItemTypeCache.class);
350	            var rows = typeCacheRepo.findAll();
351	            var items = rows.stream()
352	                    .map(r -> new ItemType(
353	                            r.typeId(), r.name(),
354	                            r.groupId() != null ? r.groupId() : 0,
355	                            r.categoryId() != null ? r.categoryId() : 0,
356	                            r.volume(), r.packagedVolume(), r.published()))
357	                    .toList();
358	            itemTypeCache.putAll(items);
359	            log.info("Populated ItemTypeCache with {} entries", items.size());
360	        } catch (Exception e) {
361	            log.warn("Failed to populate ItemTypeCache (non-fatal)", e);
362	        }
363	    }
364	
365	    private void loadCharacters() {
366	        log.info("Loading existing characters from database");
367	        try {
368	            var characterRepo = injector.getInstance(CharacterRepository.class);
369	            var characters = characterRepo.findAll();
370	            for (var row : characters) {
371	                var charInfo = new AppState.CharacterInfo(
372	                        row.characterId(),
373	                        row.name(),
374	                        "", // corporationName not stored in row, resolved later
375	                        ""  // allianceName not stored in row, resolved later
376	                );
377	                appState.getCharacters().add(charInfo);
378	                log.info("Loaded character: {} (ID: {})", row.name(), row.characterId());
379	
380	                // Restore tokens from stored refresh tokens
381	                if (row.refreshToken() != null && !row.refreshToken().isBlank()) {
382	                    var tokenManager = injector.getInstance(com.sampleapp.esi.TokenManager.class);
383	                    // Store a placeholder token; it will be refreshed on first use
384	                    tokenManager.storeToken(new com.sampleapp.esi.TokenManager.TokenData(
385	                            "", // no access token yet
386	                            row.refreshToken(),
387	                            java.time.LocalDateTime.now().minusMinutes(1), // expired, will trigger refresh
388	                            row.characterId(),
389	                            row.name(),
390	                            row.ownerHash() != null ? row.ownerHash() : ""
391	                    ));
392	                }
393	            }
394	            log.info("Loaded {} characters from database", characters.size());
395	        } catch (Exception e) {
396	            log.warn("Failed to load characters from database", e);
397	        }
398	    }
399	
400	    private void startBackgroundServices() {
401	        log.info("Starting background services");
402	
403	        // Start ESI sync service
404	        syncService = injector.getInstance(SyncService.class);
405	        var config = injector.getInstance(AppConfig.class);
406	        syncService.start(config.getSyncIntervalMinutes());
407	
408	        // Start station trade import schedule
409	        stationTradeService = injector.getInstance(StationTradeService.class);
410	        stationTradeService.startScheduledImport();
411	
412	        log.info("Background services started");
413	    }
414	
415	    private void showErrorAndExit(Exception e) {
416	        log.error("Fatal error during startup", e);
417	        var alert = new javafx.scene.control.Alert(
418	                javafx.scene.control.Alert.AlertType.ERROR,
419	                "Failed to start Sample App:\n" + e.getMessage()
420	        );
421	        alert.setTitle("Sample App - Startup Error");
422	        alert.showAndWait();
423	        Platform.exit();
424	    }
425	
426	    public static void main(String[] args) {
427	        launch(args);
428	    }
429	}
