package com.sampleapp.esi;

import jakarta.inject.Singleton;

import java.time.LocalDateTime;
import java.util.Collection;
import java.util.Optional;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ConcurrentHashMap;
import java.util.function.Function;
import java.util.logging.Logger;

/**
 * Thread-safe in-memory store for per-character EVE SSO tokens.
 * Automatically refreshes expired tokens via a pluggable refresh callback.
 */
@Singleton
public class TokenManager {

    private static final Logger LOG = Logger.getLogger(TokenManager.class.getName());

    /** Buffer before actual expiry to trigger a refresh (seconds). */
    private static final long REFRESH_BUFFER_SECONDS = 120;

    private final ConcurrentHashMap<Integer, TokenData> tokens = new ConcurrentHashMap<>();

    /** Callback set by {@link EveSsoAuth} to perform the actual refresh. */
    private volatile Function<String, CompletableFuture<TokenData>> refreshCallback;

    /** Optional callback to persist refresh tokens to durable storage (e.g. database). */
    private volatile java.util.function.BiConsumer<Integer, String> persistCallback;

    /**
     * Immutable snapshot of a character's OAuth tokens.
     */
    public record TokenData(
            String accessToken,
            String refreshToken,
            LocalDateTime expiresAt,
            int characterId,
            String characterName,
            String ownerHash
    ) { }

    /**
     * Returns a valid (non-expired) access token for the given character, refreshing
     * automatically if necessary.
     */
    public CompletableFuture<String> getValidToken(int characterId) {
        TokenData data = tokens.get(characterId);
        if (data == null) {
            return CompletableFuture.failedFuture(
                    new IllegalStateException("No token stored for character " + characterId));
        }

        if (data.expiresAt().isAfter(LocalDateTime.now().plusSeconds(REFRESH_BUFFER_SECONDS))) {
            return CompletableFuture.completedFuture(data.accessToken());
        }

        if (refreshCallback == null) {
            return CompletableFuture.failedFuture(
                    new IllegalStateException("Token expired and no refresh callback configured"));
        }

        LOG.info("Refreshing token for character " + characterId);
        return refreshCallback.apply(data.refreshToken())
                .thenApply(refreshed -> {
                    storeToken(refreshed);
                    // Persist new refresh token to database so it survives restarts
                    if (persistCallback != null) {
                        try {
                            persistCallback.accept(refreshed.characterId(), refreshed.refreshToken());
                        } catch (Exception e) {
                            LOG.warning("Failed to persist refresh token for character " + refreshed.characterId());
                        }
                    }
                    return refreshed.accessToken();
                });
    }

    public void storeToken(TokenData token) {
        tokens.put(token.characterId(), token);
        LOG.fine("Stored token for character " + token.characterId() + " (" + token.characterName() + ")");
    }

    public void removeToken(int characterId) {
        tokens.remove(characterId);
    }

    public Optional<TokenData> getToken(int characterId) {
        return Optional.ofNullable(tokens.get(characterId));
    }

    public Collection<TokenData> getAllTokens() {
        return tokens.values();
    }

    /**
     * Register the callback that performs the actual token refresh against the SSO.
     */
    public void setRefreshCallback(Function<String, CompletableFuture<TokenData>> callback) {
        this.refreshCallback = callback;
    }

    /**
     * Register a callback to persist refresh tokens to durable storage (database).
     * Called with (characterId, refreshToken) after every successful token refresh.
     */
    public void setPersistCallback(java.util.function.BiConsumer<Integer, String> callback) {
        this.persistCallback = callback;
    }
}

