package com.sampleapp.esi;

import java.net.http.HttpResponse;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.locks.ReentrantLock;
import java.util.logging.Logger;

/**
 * Tracks ESI error limits from response headers and pauses requests when the
 * remaining error budget is low.
 */
public class RateLimiter {

    private static final Logger LOG = Logger.getLogger(RateLimiter.class.getName());

    /** When remaining errors drop to this threshold we start delaying requests. */
    private static final int THROTTLE_THRESHOLD = 20;

    /** Hard-pause threshold — block until window resets. */
    private static final int BLOCK_THRESHOLD = 5;

    private final AtomicInteger errorLimitRemain = new AtomicInteger(100);
    private final AtomicInteger errorLimitReset = new AtomicInteger(60);
    private final ReentrantLock pauseLock = new ReentrantLock();

    private final ScheduledExecutorService scheduler =
            Executors.newSingleThreadScheduledExecutor(r -> {
                Thread t = new Thread(r, "esi-rate-limiter");
                t.setDaemon(true);
                return t;
            });

    /**
     * Update internal counters from the latest ESI response headers.
     */
    public void updateFromResponse(HttpResponse<?> response) {
        response.headers().firstValue("X-Esi-Error-Limit-Remain")
                .ifPresent(v -> {
                    try {
                        errorLimitRemain.set(Integer.parseInt(v));
                    } catch (NumberFormatException ignored) { }
                });
        response.headers().firstValue("X-Esi-Error-Limit-Reset")
                .ifPresent(v -> {
                    try {
                        errorLimitReset.set(Integer.parseInt(v));
                    } catch (NumberFormatException ignored) { }
                });
    }

    /**
     * Returns a future that completes when it is safe to send the next request.
     * Under normal conditions this completes immediately.
     */
    public CompletableFuture<Void> acquire() {
        int remain = errorLimitRemain.get();
        int reset = errorLimitReset.get();

        if (remain <= BLOCK_THRESHOLD) {
            LOG.warning("ESI error limit nearly exhausted (" + remain +
                    " remain). Blocking for " + reset + "s until window resets.");
            CompletableFuture<Void> future = new CompletableFuture<>();
            scheduler.schedule(() -> future.complete(null), reset, TimeUnit.SECONDS);
            return future;
        }

        if (remain <= THROTTLE_THRESHOLD) {
            long delayMs = Math.max(100, (long) reset * 1000 / Math.max(remain, 1));
            LOG.info("ESI error limit low (" + remain + " remain). Delaying " + delayMs + "ms.");
            CompletableFuture<Void> future = new CompletableFuture<>();
            scheduler.schedule(() -> future.complete(null), delayMs, TimeUnit.MILLISECONDS);
            return future;
        }

        return CompletableFuture.completedFuture(null);
    }

    public int getErrorLimitRemain() {
        return errorLimitRemain.get();
    }

    public int getErrorLimitReset() {
        return errorLimitReset.get();
    }

    public void shutdown() {
        scheduler.shutdownNow();
    }
}

