    // Verify the write actually persisted
    var verify = findById(row.characterId());
    if (verify.isPresent()) {
        log.info("Character persistence VERIFIED: {} (ID: {}, hasRefreshToken: {})",
                verify.get().name(), verify.get().characterId(),
