package com.sampleapp.data.repository;

import com.sampleapp.data.DatabaseManager;

import java.sql.*;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;

/**
 * Abstract base class providing common JDBC helper methods for all repositories.
 * Every method obtains and releases its own connection from the pool, so callers
 * never need to manage connections directly.
 */
public abstract class BaseRepository {

    protected final DatabaseManager db;

    protected BaseRepository(DatabaseManager db) {
        this.db = db;
    }

    /**
     * Executes a SELECT and maps each row to a domain object.
     */
    protected <T> List<T> query(String sql, RowMapper<T> mapper, Object... params) {
        List<T> results = new ArrayList<>();
        try (Connection conn = db.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {

            setParameters(ps, params);

            try (ResultSet rs = ps.executeQuery()) {
                while (rs.next()) {
                    results.add(mapper.map(rs));
                }
            }
        } catch (SQLException e) {
            throw new RuntimeException("Query failed: " + sql, e);
        }
        return results;
    }

    /**
     * Executes a SELECT expecting at most one result.
     */
    protected <T> Optional<T> queryOne(String sql, RowMapper<T> mapper, Object... params) {
        try (Connection conn = db.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {

            setParameters(ps, params);

            try (ResultSet rs = ps.executeQuery()) {
                if (rs.next()) {
                    return Optional.ofNullable(mapper.map(rs));
                }
            }
        } catch (SQLException e) {
            throw new RuntimeException("Query failed: " + sql, e);
        }
        return Optional.empty();
    }

    /**
     * Executes an INSERT, UPDATE, or DELETE and returns the number of affected rows.
     */
    protected int update(String sql, Object... params) {
        try (Connection conn = db.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {

            setParameters(ps, params);
            return ps.executeUpdate();

        } catch (SQLException e) {
            throw new RuntimeException("Update failed: " + sql, e);
        }
    }

    /**
     * Executes a batch insert/update. Each element in {@code paramSets} is an
     * array of parameter values for one row.
     */
    protected void batchInsert(String sql, List<Object[]> paramSets) {
        if (paramSets == null || paramSets.isEmpty()) {
            return;
        }

        try (Connection conn = db.getConnection()) {
            conn.setAutoCommit(false);

            try (PreparedStatement ps = conn.prepareStatement(sql)) {
                int count = 0;
                for (Object[] params : paramSets) {
                    setParameters(ps, params);
                    ps.addBatch();
                    count++;

                    if (count % 1000 == 0) {
                        ps.executeBatch();
                    }
                }
                ps.executeBatch();
                conn.commit();
            } catch (SQLException e) {
                conn.rollback();
                throw e;
            } finally {
                conn.setAutoCommit(true);
            }
        } catch (SQLException e) {
            throw new RuntimeException("Batch insert failed: " + sql, e);
        }
    }

    /**
     * Sets parameters on a {@link PreparedStatement}, handling null values
     * and standard Java types.
     */
    private void setParameters(PreparedStatement ps, Object... params) throws SQLException {
        if (params == null) return;
        for (int i = 0; i < params.length; i++) {
            if (params[i] == null) {
                ps.setNull(i + 1, Types.NULL);
            } else {
                ps.setObject(i + 1, params[i]);
            }
        }
    }
}

