package com.sampleapp.esi;

import java.time.LocalDateTime;

/**
 * Generic wrapper for ESI API responses, including metadata from response headers.
 *
 * @param <T>              the response body type
 * @param data             deserialized response body
 * @param statusCode       HTTP status code
 * @param pages            total pages from X-Pages header (1 if not paginated)
 * @param etag             ETag value for conditional requests
 * @param errorLimitRemain remaining errors before throttle (X-Esi-Error-Limit-Remain)
 * @param errorLimitReset  seconds until error window resets (X-Esi-Error-Limit-Reset)
 * @param expires          cache expiry from Expires header
 */
public record EsiResponse<T>(
        T data,
        int statusCode,
        int pages,
        String etag,
        int errorLimitRemain,
        int errorLimitReset,
        LocalDateTime expires
) {
    public boolean isSuccess() {
        return statusCode >= 200 && statusCode < 300;
    }

    public boolean isNotModified() {
        return statusCode == 304;
    }
}

