577	    private void loadItemOrders(TradeOpportunity item, String hubName) {
578	        detailItemLabel.setText("Loading orders for: " + item.typeName() + "...");
579	        buyOrdersTable.getItems().clear();
580	        sellOrdersTable.getItems().clear();
581	
582	        int regionId = hubToRegionIdFromFullName(hubName);
583	        Thread.ofVirtual().name("trader-load-orders").start(() ->
584	                dataService.getRegionOrders(item.typeId(), regionId)
585	                        .thenAccept(orders -> Platform.runLater(() -> {
586	                            detailItemLabel.setText("Orders for: " + item.typeName());
587	                            var buyOrders = orders.stream()
588	                                    .filter(MarketOrder::isBuyOrder)
589	                                    .sorted(Comparator.comparingDouble(MarketOrder::price).reversed())
590	                                    .toList();
591	                            var sellOrders = orders.stream()
592	                                    .filter(o -> !o.isBuyOrder())
593	                                    .sorted(Comparator.comparingDouble(MarketOrder::price))
594	                                    .toList();
595	                            buyOrdersTable.getItems().setAll(buyOrders);
596	                            sellOrdersTable.getItems().setAll(sellOrders);
597	                        }))
598	                        .exceptionally(ex -> {
599	                            Platform.runLater(() -> {
600	                                detailItemLabel.setText("Failed to load orders for: " + item.typeName());
601	                                log.error("Failed to load item orders", ex);
602	                            });
603	                            return null;
604	                        })
605	        );
606	    }
