608	    private static int hubToRegionIdFromFullName(String fullHubName) {
609	        if (fullHubName.startsWith("Jita")) return 10000002;
610	        if (fullHubName.startsWith("Amarr")) return 10000043;
611	        if (fullHubName.startsWith("Dodixie")) return 10000032;
612	        if (fullHubName.startsWith("Rens")) return 10000030;
613	        if (fullHubName.startsWith("Hek")) return 10000042;
614	        return 10000002;
615	    }
