1006	    private void updateShoppingTree(TreeItem<String> root, List<TradeOpportunity> data, String sourceHub) {
1007	        root.getChildren().clear();
1008	
1009	        // Group all items under the source hub system
1010	        var systemNode = new TreeItem<>(sourceHub + " - Buy List");
1011	        systemNode.setExpanded(true);
1012	
1013	        for (var opp : data) {
1014	            long qty = opp.volume();
1015	            String label = String.format("%s x%d  -  %s",
1016	                    opp.typeName(), qty, IskFormatter.format(opp.buyPrice() * qty));
1017	            systemNode.getChildren().add(new TreeItem<>(label));
1018	        }
1019	
1020	        double totalCost = data.stream()
1021	                .mapToDouble(o -> o.buyPrice() * o.volume())
1022	                .sum();
1023	        var summaryNode = new TreeItem<>(String.format("Total: %s (%d items)",
1024	                IskFormatter.format(totalCost), data.size()));
