1033	    private void updateRegionalSummary(List<TradeOpportunity> data, double shippingRate) {
1034	        double totalInvest = 0;
1035	        double totalProfit = 0;
1036	        double totalShipping = 0;
1037	        for (var opp : data) {
1038	            totalInvest += opp.buyPrice() * opp.volume();
1039	            double unitProfit = opp.sellPrice() - opp.buyPrice();
1040	            totalProfit += unitProfit * opp.volume();
1041	            // Shipping cost: rate * volume (assume 1 m3/unit)
1042	            totalShipping += shippingRate * opp.volume();
1043	        }
1044	        double netProfit = totalProfit - totalShipping;
1045	        totalInvestmentLabel.setText("Total Investment: " + IskFormatter.format(totalInvest));
1046	        totalProfitLabel.setText("Total Profit: " + IskFormatter.format(netProfit));
1047	        double roi = totalInvest > 0 ? (netProfit / totalInvest) * 100.0 : 0;
1048	        roiLabel.setText(String.format("ROI: %.1f%%", roi));
1049	        cargoUsedLabel.setText(String.format("Cargo Used: %,d m3",
1050	                data.stream().mapToLong(TradeOpportunity::volume).sum()));
