1073	            double va = Double.parseDouble(a.replace(",", "").replace("%", "").replace("--", "0").trim());
1074	            double vb = Double.parseDouble(b.replace(",", "").replace("%", "").replace("--", "0").trim());
1075	            return Double.compare(va, vb);
1076	        } catch (NumberFormatException e) {
