    // ================================================================
    // Accounting / Wallet
    // ================================================================

    @Override
    public CompletableFuture<List<JournalEntry>> getJournalEntries(int characterId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getJournalEntries for character {}", characterId);
            List<WalletRepository.WalletJournalRow> rows = walletRepo.findJournalByCharacter(characterId);
            return rows.stream()
                    .map(r -> new JournalEntry(
                            r.journalId(),
                            r.date(),
                            r.transactionType(),
                            r.amount(),
                            r.balance(),
                            r.description(),
                            r.firstPartyId() != null ? r.firstPartyId() : 0L,
                            r.secondPartyId() != null ? r.secondPartyId() : 0L
                    ))
                    .toList();
        });
