    @Override
    public CompletableFuture<List<MarketOrder>> getRegionOrders(int typeId, int regionId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getRegionOrders for type {} in region {}", typeId, regionId);
            try {
                var esiOrders = esiClient.market.getRegionOrdersForType(regionId, "all", typeId).join();
                return esiOrders.stream()
                        .map(o -> new MarketOrder(
                                o.orderId(),
                                o.typeId(),
                                o.price(),
                                o.volumeRemain(),
                                o.volumeTotal(),
                                o.isBuyOrder(),
                                o.duration(),
                                o.issued().toLocalDateTime(),
                                o.locationId(),
                                "active",
                                regionId
                        ))
                        .toList();
            } catch (Exception e) {
                log.error("Failed to fetch region orders for type {} in region {}", typeId, regionId, e);
                return List.of();
            }
        });
    }

    @Override
    public CompletableFuture<List<HubPrices>> appraiseItems(List<Integer> typeIds) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("appraiseItems for {} types", typeIds.size());
            List<HubPrices> results = new ArrayList<>();
            for (int typeId : typeIds) {
                double jitaBuy = 0, jitaSell = 0;
                double amarrBuy = 0, amarrSell = 0;
                double dodixieBuy = 0, dodixieSell = 0;
                double hekBuy = 0, hekSell = 0;
                double rensBuy = 0, rensSell = 0;

                var jita = stationPriceRepo.findById(typeId, Constants.JITA);
                if (jita.isPresent()) {
                    jitaBuy = jita.get().buyPrice();
                    jitaSell = jita.get().sellPrice();
                }

                var amarr = stationPriceRepo.findById(typeId, Constants.AMARR);
                if (amarr.isPresent()) {
                    amarrBuy = amarr.get().buyPrice();
                    amarrSell = amarr.get().sellPrice();
                }

                var dodixie = stationPriceRepo.findById(typeId, Constants.DODIXIE);
                if (dodixie.isPresent()) {
                    dodixieBuy = dodixie.get().buyPrice();
                    dodixieSell = dodixie.get().sellPrice();
                }

                var hek = stationPriceRepo.findById(typeId, Constants.HEK);
                if (hek.isPresent()) {
                    hekBuy = hek.get().buyPrice();
                    hekSell = hek.get().sellPrice();
                }

                var rens = stationPriceRepo.findById(typeId, Constants.RENS);
                if (rens.isPresent()) {
                    rensBuy = rens.get().buyPrice();
                    rensSell = rens.get().sellPrice();
                }

                results.add(new HubPrices(
                        typeId,
                        jitaBuy, jitaSell,
                        amarrBuy, amarrSell,
                        dodixieBuy, dodixieSell,
                        hekBuy, hekSell,
                        rensBuy, rensSell
                ));
            }
            return results;
        });
    }

    // ================================================================
    // Trader
    // ================================================================

    @Override
    public CompletableFuture<List<TradeOpportunity>> scanStationTrades(long stationId, double minProfit, int minVolume) {
        return CompletableFuture.supplyAsync(() -> {
            log.info("scanStationTrades for station {} minProfit={} minVolume={}", stationId, minProfit, minVolume);
            try {
                int regionId = stationToRegion(stationId);
                log.info("Fetching ALL region orders for region {} (station {})...", regionId, stationId);

                // Fetch ALL orders in the region from ESI (paginated)
                List<RegionOrder> allOrders = esiClient.market.getRegionOrders(regionId).join();
                log.info("Fetched {} total region orders for region {}", allOrders.size(), regionId);

                if (allOrders.isEmpty()) {
                    log.warn("ESI returned 0 orders for region {} - API may be down or rate-limited", regionId);
                    throw new RuntimeException("ESI returned no market orders for region " + regionId
                            + ". The market API may be temporarily unavailable.");
                }

                // Filter to orders at this station only
                List<RegionOrder> stationOrders = allOrders.stream()
                        .filter(o -> o.locationId() == stationId)
                        .toList();
                log.info("Filtered to {} orders at station {}", stationOrders.size(), stationId);

                // If no orders at the specific station, show top locations for debugging
                if (stationOrders.isEmpty()) {
                    var topLocations = allOrders.stream()
                            .collect(Collectors.groupingBy(RegionOrder::locationId, Collectors.counting()))
                            .entrySet().stream()
                            .sorted(Map.Entry.<Long, Long>comparingByValue().reversed())
                            .limit(5)
                            .toList();
                    log.warn("No orders found at station {}. Top locations in region: {}", stationId, topLocations);

                    // Fall back: include all orders in the region's solar system for this station
                    // Get the system ID for orders at the target station's system
                    int targetSystemId = allOrders.stream()
                            .filter(o -> o.locationId() == stationId)
                            .map(RegionOrder::systemId)
                            .findFirst()
                            .orElse(stationToSystem(stationId));

                    if (targetSystemId > 0) {
                        stationOrders = allOrders.stream()
                                .filter(o -> o.systemId() == targetSystemId)
                                .toList();
                        log.info("Expanded to {} orders in system {} (includes citadels)", stationOrders.size(), targetSystemId);
                    }
                }

                // Group by typeId
                Map<Integer, List<RegionOrder>> byType = stationOrders.stream()
                        .collect(Collectors.groupingBy(RegionOrder::typeId));
                log.info("Found {} unique item types with orders", byType.size());

                List<TradeOpportunity> opportunities = new ArrayList<>();
                int typesWithBothSides = 0;
                for (var entry : byType.entrySet()) {
                    int typeId = entry.getKey();
                    var orders = entry.getValue();

                    // Find best buy (highest buy order) and best sell (lowest sell order)
                    OptionalDouble bestBuy = orders.stream()
                            .filter(RegionOrder::isBuyOrder)
                            .mapToDouble(RegionOrder::price)
                            .max();
                    OptionalDouble bestSell = orders.stream()
                            .filter(o -> !o.isBuyOrder())
                            .mapToDouble(RegionOrder::price)
                            .min();

                    if (bestBuy.isEmpty() || bestSell.isEmpty()) continue;
                    typesWithBothSides++;

                    double buyPrice = bestBuy.getAsDouble();
                    double sellPrice = bestSell.getAsDouble();
                    double profit = sellPrice - buyPrice;
                    double margin = sellPrice > 0 ? profit / sellPrice : 0;

                    // Count total sell volume for this type (calculate before filtering)
                    long sellVolume = orders.stream()
                            .filter(o -> !o.isBuyOrder())
                            .mapToLong(RegionOrder::volumeRemain)
                            .sum();

                    if (profit < minProfit) continue;
                    if (margin <= 0) continue;
                    if (sellVolume < minVolume) continue;

                    // Count number of sell orders (competition)
                    long orderCount = orders.stream()
                            .filter(o -> !o.isBuyOrder())
                            .count();

                    String typeName = typeCacheRepo.findNameById(typeId).orElse("Type #" + typeId);

                    opportunities.add(new TradeOpportunity(
                            typeId, typeName, buyPrice, sellPrice, margin,
                            orderCount, (double) sellVolume
                    ));
                }

                // Cache the prices we found for future use
                for (var opp : opportunities) {
                    stationPriceRepo.upsert(opp.typeId(), stationId, opp.buyPrice(), opp.sellPrice());
                }

                opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
                log.info("Station trade scan complete: {} types with both buy+sell, {} passed filters",
                        typesWithBothSides, opportunities.size());
                return opportunities;
            } catch (Exception e) {
                log.error("Failed to scan station trades for station {}", stationId, e);
                throw new RuntimeException("Station trade scan failed: " + e.getMessage(), e);
            }
        });
    }

    /**
     * Maps well-known trade hub station IDs to their solar system IDs.
     */
    private static int stationToSystem(long stationId) {
        if (stationId == 60003760L) return 30000142; // Jita
        if (stationId == 60008494L) return 30002187; // Amarr
        if (stationId == 60011866L) return 30002659; // Dodixie
        if (stationId == 60004588L) return 30002510; // Rens
        if (stationId == 60005686L) return 30002053; // Hek
        return 0;
    }

    @Override
    public CompletableFuture<List<TradeOpportunity>> scanRegionalTrades(int fromRegionId, int toRegionId,
                                                                        double minMargin, double maxCargo, double budget) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("scanRegionalTrades from {} to {} minMargin={} maxCargo={} budget={}",
                    fromRegionId, toRegionId, minMargin, maxCargo, budget);
            try {
                log.info("Fetching region orders for regions {} and {}...", fromRegionId, toRegionId);

                // Fetch orders from both regions in parallel
                var fromOrdersFuture = esiClient.market.getRegionOrders(fromRegionId);
                var toOrdersFuture = esiClient.market.getRegionOrders(toRegionId);

                List<RegionOrder> fromOrders = fromOrdersFuture.join();
                List<RegionOrder> toOrders = toOrdersFuture.join();
                log.info("Fetched {} orders from source region, {} from destination region",
                        fromOrders.size(), toOrders.size());

                // Build price maps: for source, find lowest sell price per type
                Map<Integer, Double> sourceSellPrices = new HashMap<>();
                Map<Integer, Long> sourceVolumes = new HashMap<>();
                for (var order : fromOrders) {
                    if (order.isBuyOrder()) continue; // skip buy orders
                    sourceSellPrices.merge(order.typeId(), order.price(), Math::min);
                    sourceVolumes.merge(order.typeId(), (long) order.volumeRemain(), Long::sum);
                }

                // For destination, find lowest sell price (what we undercut)
                Map<Integer, Double> destSellPrices = new HashMap<>();
                for (var order : toOrders) {
                    if (order.isBuyOrder()) continue;
                    destSellPrices.merge(order.typeId(), order.price(), Math::min);
                }

                List<TradeOpportunity> opportunities = new ArrayList<>();
                for (var entry : sourceSellPrices.entrySet()) {
                    int typeId = entry.getKey();
                    double buyCost = entry.getValue();
                    Double sellRevenue = destSellPrices.get(typeId);

                    if (sellRevenue == null || buyCost <= 0 || sellRevenue <= 0) continue;

                    double margin = (sellRevenue - buyCost) / sellRevenue;
                    if (margin < minMargin) continue;

                    // Check cargo volume constraint
                    var typeInfo = typeCacheRepo.findById(typeId);
                    if (typeInfo.isPresent() && maxCargo > 0) {
                        double vol = typeInfo.get().packagedVolume() > 0
                                ? typeInfo.get().packagedVolume()
                                : typeInfo.get().volume();
                        if (vol > maxCargo) continue;
                    }

                    // Check budget constraint
                    if (budget > 0 && buyCost > budget) continue;

                    long volume = sourceVolumes.getOrDefault(typeId, 0L);
                    String typeName = typeCacheRepo.findNameById(typeId).orElse("Type #" + typeId);

                    opportunities.add(new TradeOpportunity(
                            typeId, typeName, buyCost, sellRevenue, margin,
                            volume, (double) volume
                    ));
                }

                opportunities.sort((a, b) -> Double.compare(b.margin(), a.margin()));
                log.info("Found {} regional trade opportunities", opportunities.size());
                return opportunities;
            } catch (Exception e) {
                log.error("Failed to scan regional trades from {} to {}", fromRegionId, toRegionId, e);
                return List.of();
            }
        });
    }

    /**
     * Maps well-known trade hub station IDs to their region IDs.
     */
    private static int stationToRegion(long stationId) {
        if (stationId == 60003760L) return 10000002; // Jita -> The Forge
        if (stationId == 60008494L) return 10000043; // Amarr -> Domain
        if (stationId == 60011866L) return 10000032; // Dodixie -> Sinq Laison
        if (stationId == 60004588L) return 10000030; // Rens -> Heimatar
        if (stationId == 60005686L) return 10000042; // Hek -> Metropolis
        return 10000002; // default to The Forge
    }

    // ================================================================
    // LP Store
    // ================================================================

    @Override
    public CompletableFuture<List<LoyaltyOffer>> getLpStoreOffers(int corporationId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getLpStoreOffers for corporation {}", corporationId);
            try {
                var response = esiClient.loyalty.getStoreOffers(corporationId).join();
                if (response.isSuccess() && response.data() != null) {
                    return response.data().stream()
                            .map(o -> new LoyaltyOffer(
                                    o.offerId(),
                                    o.typeId(),
                                    o.quantity(),
                                    o.lpCost(),
                                    (double) o.iskCost(),
                                    o.requiredItems() != null
                                            ? o.requiredItems().stream()
                                            .map(ri -> new LoyaltyOfferRequirement(ri.typeId(), ri.quantity()))
                                            .toList()
                                            : List.of()
                            ))
                            .toList();
                }
                return List.<LoyaltyOffer>of();
            } catch (Exception e) {
                log.error("Failed to fetch LP store offers for corporation {}", corporationId, e);
                return List.of();
            }
        });
    }

    @Override
    public CompletableFuture<List<LoyaltyPoints>> getLoyaltyPoints(int characterId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getLoyaltyPoints for character {}", characterId);
            List<LoyaltyRepository.LoyaltyPointsRow> rows = loyaltyRepo.findByCharacter(characterId);
            return rows.stream()
                    .map(r -> new LoyaltyPoints(
                            r.corporationId(),
                            r.points()
                    ))
                    .toList();
        });
    }

    // ================================================================
    // Public Contracts
    // ================================================================

    @Override
    public CompletableFuture<List<ContractModel>> getPublicContracts(int regionId, String typeFilter) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getPublicContracts for region {} typeFilter={}", regionId, typeFilter);
            try {
                if (regionId <= 0) {
                    log.warn("Invalid region ID for public contracts: {}", regionId);
                    return List.<ContractModel>of();
                }
                List<com.sampleapp.esi.dto.Contract> contracts = esiClient.contracts.getPublicContracts(regionId).join();
                log.info("Fetched {} public contracts from region {}", contracts.size(), regionId);

                return contracts.stream()
                        .filter(c -> typeFilter == null || typeFilter.isEmpty()
                                || (c.type() != null && c.type().replace("_", " ").equalsIgnoreCase(typeFilter)))
                        .limit(500) // Limit to prevent UI overload
                        .map(c -> new ContractModel(
                                c.contractId(),
                                c.type() != null ? c.type().replace("_", " ") : "--",
                                c.status() != null ? c.status() : "--",
                                c.price() != null ? c.price() : 0.0,
                                c.buyout() != null ? c.buyout() : 0.0,
                                c.collateral() != null ? c.collateral() : 0.0,
                                c.reward() != null ? c.reward() : 0.0,
                                c.volume() != null ? c.volume() : 0.0,
                                c.availability() != null ? c.availability() : "--",
                                c.forCorporation(),
                                c.issuerCorporationId(),
                                c.issuerId(),
                                c.dateIssued() != null ? c.dateIssued().toLocalDateTime() : null,
                                c.dateExpired() != null ? c.dateExpired().toLocalDateTime() : null
                        ))
                        .toList();
            } catch (Exception e) {
                log.error("Failed to fetch public contracts for region {}", regionId, e);
                return List.of();
            }
        });
    }

    @Override
    public CompletableFuture<String> resolveCharacterName(int characterId) {
        return CompletableFuture.supplyAsync(() -> {
            try {
                var resp = esiClient.universe.getNames(java.util.List.of(characterId)).join();
                if (resp.isSuccess() && resp.data() != null && !resp.data().isEmpty()) {
                    return resp.data().get(0).name();
                }
                log.warn("Universe names returned no results for character ID {}, status={}", characterId,
                        resp != null ? resp.statusCode() : "null");
            } catch (Exception e) {
                Throwable cause = e.getCause() != null ? e.getCause() : e;
                log.warn("Failed to resolve character name for {}: {}", characterId, cause.getMessage());
            }
            return "Pilot #" + characterId;
        });
    }

    @Override
    public CompletableFuture<List<ContractItemInfo>> getPublicContractItems(long contractId) {
        return CompletableFuture.supplyAsync(() -> {
            try {
                log.info("Fetching items for public contract {}", contractId);
                var items = esiClient.contracts.getPublicContractItems(contractId).join();
                log.info("Got {} items for contract {}", items.size(), contractId);
                return items.stream()
                        .map(item -> {
                            String typeName = typeCacheRepo.findNameById(item.typeId()).orElse("Type #" + item.typeId());
                            double jitaBuy = 0, jitaSell = 0;

                            // Try cached prices first
                            var jitaPrice = stationPriceRepo.findById(item.typeId(), Constants.JITA);
                            if (jitaPrice.isPresent()) {
                                jitaBuy = jitaPrice.get().buyPrice();
                                jitaSell = jitaPrice.get().sellPrice();
                            } else {
                                // Fallback: fetch live from ESI for this type at Jita (The Forge)
                                try {
                                    var orders = esiClient.market.getRegionOrdersForType(
                                            10000002, "all", item.typeId()).join();
                                    var jitaOrders = orders.stream()
                                            .filter(o -> o.locationId() == Constants.JITA)
                                            .toList();
                                    jitaBuy = jitaOrders.stream()
                                            .filter(RegionOrder::isBuyOrder)
                                            .mapToDouble(RegionOrder::price)
                                            .max().orElse(0);
                                    jitaSell = jitaOrders.stream()
                                            .filter(o -> !o.isBuyOrder())
                                            .mapToDouble(RegionOrder::price)
                                            .min().orElse(0);
                                    // Cache for future use
                                    if (jitaBuy > 0 || jitaSell > 0) {
                                        stationPriceRepo.upsert(item.typeId(), Constants.JITA, jitaBuy, jitaSell);
                                    }
                                } catch (Exception e) {
                                    log.debug("Failed to fetch Jita prices for type {}", item.typeId(), e);
                                }
                            }
                            return new ContractItemInfo(item.typeId(), typeName, item.quantity(), item.isIncluded(),
                                    jitaBuy, jitaSell);
                        })
                        .toList();
            } catch (Exception e) {
                Throwable cause = e.getCause() != null ? e.getCause() : e;
                log.error("Failed to fetch contract items for contract {}: {}", contractId, cause.getMessage(), e);
                return java.util.List.of();
            }
        });
    }

    // ================================================================
    // Fleet
    // ================================================================

    @Override
    public CompletableFuture<List<FleetMemberInfo>> getFleetMembers(int characterId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getFleetMembers for character {}", characterId);
            try {
                String token = tokenManager.getValidToken(characterId).join();
                // First get the character's fleet ID
                var fleetInfoResp = esiClient.fleets.getCharacterFleet(characterId, token).join();
                if (!fleetInfoResp.isSuccess() || fleetInfoResp.data() == null) {
                    return List.<FleetMemberInfo>of();
                }
                long fleetId = fleetInfoResp.data().fleetId();

                // Get fleet members
                var membersResp = esiClient.fleets.getFleetMembers(fleetId, token).join();
                if (!membersResp.isSuccess() || membersResp.data() == null) {
                    return List.<FleetMemberInfo>of();
                }

                // Get fleet wings for wing/squad names
                var wingsResp = esiClient.fleets.getFleetWings(fleetId, token).join();
                Map<Long, String> wingNames = new HashMap<>();
                Map<Long, String> squadNames = new HashMap<>();
                if (wingsResp.isSuccess() && wingsResp.data() != null) {
                    for (var wing : wingsResp.data()) {
                        wingNames.put(wing.id(), wing.name());
                        if (wing.squads() != null) {
                            for (var squad : wing.squads()) {
                                squadNames.put(squad.id(), squad.name());
                            }
                        }
                    }
                }

                // Resolve character names via universe names
                List<Integer> charIds = membersResp.data().stream()
                        .map(com.sampleapp.esi.dto.FleetMember::characterId)
                        .toList();
                Map<Integer, String> charNames = new HashMap<>();
                if (!charIds.isEmpty()) {
                    try {
                        var namesResp = esiClient.universe.getNames(charIds).join();
                        if (namesResp.isSuccess() && namesResp.data() != null) {
                            for (var name : namesResp.data()) {
                                charNames.put(name.id(), name.name());
                            }
                        }
                    } catch (Exception e) {
                        log.warn("Failed to resolve fleet member names", e);
                    }
                }

                return membersResp.data().stream()
                        .map(m -> new FleetMemberInfo(
                                m.characterId(),
                                charNames.getOrDefault(m.characterId(), "Character #" + m.characterId()),
                                "", // ship name not available from ESI fleet members
                                "Ship Type #" + m.shipTypeId(),
                                "System #" + m.solarSystemId(),
                                m.role() != null ? m.role() : "--",
                                squadNames.getOrDefault(m.squadId(), "Squad #" + m.squadId()),
                                wingNames.getOrDefault(m.wingId(), "Wing #" + m.wingId())
                        ))
                        .toList();
            } catch (Exception e) {
                log.error("Failed to load fleet members for character {}", characterId, e);
                return List.of();
            }
        });
    }

    // ================================================================
    // Universe
    // ================================================================

    @Override
    public CompletableFuture<List<SystemSecurity>> getSystemsInRegion(String regionName) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getSystemsInRegion for region '{}'", regionName);
            try {
                // Map region name to ID
                int regionId = switch (regionName) {
                    case "The Forge" -> 10000002;
                    case "Domain" -> 10000043;
                    case "Sinq Laison" -> 10000032;
                    case "Metropolis" -> 10000042;
                    case "Heimatar" -> 10000030;
                    case "Essence" -> 10000064;
                    case "The Citadel" -> 10000033;
                    case "Lonetrek" -> 10000016;
                    case "Black Rise" -> 10000069;
                    case "Placid" -> 10000048;
                    case "Devoid" -> 10000036;
                    case "Tash-Murkon" -> 10000020;
                    default -> 0;
                };
                if (regionId == 0) return List.<SystemSecurity>of();

                return getWellKnownSystemsForRegion(regionId);
            } catch (Exception e) {
                log.error("Failed to get systems for region '{}'", regionName, e);
                return List.of();
            }
        });
    }

    private List<SystemSecurity> getWellKnownSystemsForRegion(int regionId) {
        // Well-known trade hub systems per region
        return switch (regionId) {
            case 10000002 -> List.of( // The Forge
                    new SystemSecurity(30000142, 0.9, "B"), // Jita
                    new SystemSecurity(30000144, 0.9, "B"), // Perimeter
                    new SystemSecurity(30000139, 0.8, "B"), // Maurasi
                    new SystemSecurity(30000143, 1.0, "A"), // Niyabainen
                    new SystemSecurity(30000148, 0.7, "B")  // Sobaseki
            );
            case 10000043 -> List.of( // Domain
                    new SystemSecurity(30002187, 1.0, "A"), // Amarr
                    new SystemSecurity(30002053, 0.7, "B"), // Sarum Prime
                    new SystemSecurity(30002068, 0.8, "B")  // Halaima
            );
            case 10000032 -> List.of( // Sinq Laison
                    new SystemSecurity(30002659, 0.9, "B"), // Dodixie
                    new SystemSecurity(30002661, 0.8, "B")  // Botane
            );
            case 10000042 -> List.of( // Metropolis
                    new SystemSecurity(30002510, 0.9, "B")  // Hek
            );
            case 10000030 -> List.of( // Heimatar
                    new SystemSecurity(30002510, 0.9, "B"), // Rens
                    new SystemSecurity(30002526, 1.0, "A")  // Frarn
            );
            default -> List.of();
        };
    }

    // ================================================================
    // Market Group Tree
    // ================================================================

    @Override
    public CompletableFuture<List<MarketGroupInfo>> getRootMarketGroups() {
        return CompletableFuture.supplyAsync(() -> {
            return marketGroupRepo.findByParent(null).stream()
                    .map(r -> new MarketGroupInfo(r.marketGroupId(), r.name(), r.hasTypes()))
