    // ================================================================
    // Name Resolution
    // ================================================================

    @Override
    public CompletableFuture<String> resolveTypeName(int typeId) {
        return CompletableFuture.supplyAsync(() -> {
            return typeCacheRepo.findNameById(typeId).orElse("Unknown Type");
        });
    }

    @Override
    public CompletableFuture<String> resolveLocationName(long locationId) {
        // Check cache first
        String cached = locationNameCache.get(locationId);
        if (cached != null) return CompletableFuture.completedFuture(cached);

        return CompletableFuture.supplyAsync(() -> {
            String name = resolveLocationNameSync(locationId);
            locationNameCache.put(locationId, name);
            return name;
        });
    }

    private String resolveLocationNameSync(long locationId) {
        if (locationId <= 0) return "Unknown Location";

        // Solar system IDs: 30,000,000 - 33,000,000
        if (locationId >= 30_000_000 && locationId < 33_000_000) {
            // Try SDE first (fast, no network)
            try (var conn = dbManager.getConnection();
                 var ps = conn.prepareStatement("SELECT Name FROM SdeSolarSystems WHERE SystemId = ?")) {
                ps.setInt(1, (int) locationId);
                var rs = ps.executeQuery();
                if (rs.next()) {
                    String name = rs.getString(1);
                    if (name != null) return name;
                }
            } catch (Exception e) {
                log.debug("SDE solar system lookup failed for {}, falling back to ESI", locationId);
            }
            // Fall back to ESI
            try {
                var resp = esiClient.universe.getSystem((int) locationId).join();
                if (resp.isSuccess() && resp.data() != null) {
                    return resp.data().name();
                }
            } catch (Exception e) {
                log.debug("Failed to resolve system name for {}", locationId, e);
            }
        }

        // NPC station IDs: 60,000,000 - 64,000,000
        if (locationId >= 60_000_000 && locationId < 64_000_000) {
            // Try SDE first (fast, no network)
            try (var conn = dbManager.getConnection();
                 var ps = conn.prepareStatement("SELECT StationName FROM SdeStationNames WHERE StationId = ?")) {
                ps.setLong(1, locationId);
                var rs = ps.executeQuery();
                if (rs.next()) {
                    String name = rs.getString(1);
                    if (name != null) return name;
                }
            } catch (Exception e) {
                log.debug("SDE station name lookup failed for {}, falling back to ESI", locationId);
            }
            // Fall back to ESI
            try {
                var resp = esiClient.universe.getStation((int) locationId).join();
                if (resp.isSuccess() && resp.data() != null) {
                    return resp.data().name();
                }
            } catch (Exception e) {
                log.debug("Failed to resolve station name for {}", locationId, e);
            }
        }

        // Structures: >= 64,000,000 (Upwell structures, requires auth)
        if (locationId >= 64_000_000) {
            // Try to resolve via any available character token
            try {
                var characters = characterRepo.findAll();
                for (var character : characters) {
                    try {
                        String token = tokenManager.getValidToken(character.characterId()).join();
                        var resp = esiClient.universe.getStructure(locationId, token).join();
                        if (resp.isSuccess() && resp.data() != null) {
                            return resp.data().name();
                        }
                    } catch (Exception e) {
                        // This character may not have access, try next
                        continue;
                    }
                }
            } catch (Exception e) {
                log.debug("Failed to resolve structure name for {}", locationId, e);
            }
            // Fall back: try to find the solar system from assets and show "Structure in <system>"
            return "Structure " + locationId;
        }

        // Try universe names API as a fallback for other ID ranges
        if (locationId > 0 && locationId <= Integer.MAX_VALUE) {
            try {
                var resp = esiClient.universe.getNames(List.of((int) locationId)).join();
                if (resp.isSuccess() && resp.data() != null && !resp.data().isEmpty()) {
                    return resp.data().get(0).name();
                }
            } catch (Exception e) {
                log.debug("Failed to resolve name via universe names for {}", locationId, e);
            }
        }

        return "Location " + locationId;
    }

    @Override
    public CompletableFuture<String> resolveSystemName(int systemId) {
        return CompletableFuture.supplyAsync(() -> {
            // Try SDE first (fast, no network)
            try (var conn = dbManager.getConnection();
                 var ps = conn.prepareStatement("SELECT Name FROM SdeSolarSystems WHERE SystemId = ?")) {
                ps.setInt(1, systemId);
                var rs = ps.executeQuery();
                if (rs.next()) {
                    String name = rs.getString(1);
                    if (name != null) return name;
                }
            } catch (Exception e) {
                log.debug("SDE solar system lookup failed for {}, falling back to ESI", systemId);
            }
            // Fall back to ESI
            try {
                var resp = esiClient.universe.getSystem(systemId).join();
                if (resp.isSuccess() && resp.data() != null) {
                    return resp.data().name();
                }
            } catch (Exception e) {
                log.warn("Failed to resolve system name for {}", systemId, e);
            }
            return "System " + systemId;
        });
    }

    @Override
    public CompletableFuture<String> resolveCorporationName(int corporationId) {
        return CompletableFuture.supplyAsync(() -> {
            try {
                var resp = esiClient.corporations.getCorporation(corporationId).join();
                if (resp.isSuccess() && resp.data() != null) {
                    return resp.data().name();
                }
            } catch (Exception e) {
                log.warn("Failed to resolve corporation name for {}", corporationId, e);
            }
            return "Corporation #" + corporationId;
        });
    }
}

