    @Override
    public CompletableFuture<List<ContractItemInfo>> getPublicContractItems(long contractId) {
        return CompletableFuture.supplyAsync(() -> {
            try {
                log.info("Fetching items for public contract {}", contractId);
                var items = esiClient.contracts.getPublicContractItems(contractId).join();
                log.info("Got {} items for contract {}", items.size(), contractId);
                return items.stream()
                        .map(item -> {
                            String typeName = typeCacheRepo.findNameById(item.typeId()).orElse("Type #" + item.typeId());
                            double jitaBuy = 0, jitaSell = 0;

                            // Try cached prices first
                            var jitaPrice = stationPriceRepo.findById(item.typeId(), Constants.JITA);
                            if (jitaPrice.isPresent()) {
                                jitaBuy = jitaPrice.get().buyPrice();
                                jitaSell = jitaPrice.get().sellPrice();
                            } else {
                                // Fallback: fetch live from ESI for this type at Jita (The Forge)
                                try {
                                    var orders = esiClient.market.getRegionOrdersForType(
                                            10000002, "all", item.typeId()).join();
                                    var jitaOrders = orders.stream()
                                            .filter(o -> o.locationId() == Constants.JITA)
                                            .toList();
                                    jitaBuy = jitaOrders.stream()
                                            .filter(RegionOrder::isBuyOrder)
                                            .mapToDouble(RegionOrder::price)
                                            .max().orElse(0);
                                    jitaSell = jitaOrders.stream()
                                            .filter(o -> !o.isBuyOrder())
                                            .mapToDouble(RegionOrder::price)
                                            .min().orElse(0);
                                    // Cache for future use
                                    if (jitaBuy > 0 || jitaSell > 0) {
                                        stationPriceRepo.upsert(item.typeId(), Constants.JITA, jitaBuy, jitaSell);
                                    }
                                } catch (Exception e) {
                                    log.debug("Failed to fetch Jita prices for type {}", item.typeId(), e);
                                }
                            }
                            return new ContractItemInfo(item.typeId(), typeName, item.quantity(), item.isIncluded(),
                                    jitaBuy, jitaSell);
                        })
                        .toList();
            } catch (Exception e) {
                Throwable cause = e.getCause() != null ? e.getCause() : e;
                log.error("Failed to fetch contract items for contract {}: {}", contractId, cause.getMessage(), e);
                return java.util.List.of();
            }
        });
    }

