    @Override
    public CompletableFuture<List<FleetMemberInfo>> getFleetMembers(int characterId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getFleetMembers for character {}", characterId);
            try {
                String token = tokenManager.getValidToken(characterId).join();
                // First get the character's fleet ID
                var fleetInfoResp = esiClient.fleets.getCharacterFleet(characterId, token).join();
                if (!fleetInfoResp.isSuccess() || fleetInfoResp.data() == null) {
                    return List.<FleetMemberInfo>of();
                }
                long fleetId = fleetInfoResp.data().fleetId();

                // Get fleet members
                var membersResp = esiClient.fleets.getFleetMembers(fleetId, token).join();
                if (!membersResp.isSuccess() || membersResp.data() == null) {
                    return List.<FleetMemberInfo>of();
                }

                // Get fleet wings for wing/squad names
                var wingsResp = esiClient.fleets.getFleetWings(fleetId, token).join();
                Map<Long, String> wingNames = new HashMap<>();
                Map<Long, String> squadNames = new HashMap<>();
                if (wingsResp.isSuccess() && wingsResp.data() != null) {
                    for (var wing : wingsResp.data()) {
                        wingNames.put(wing.id(), wing.name());
                        if (wing.squads() != null) {
                            for (var squad : wing.squads()) {
                                squadNames.put(squad.id(), squad.name());
                            }
                        }
                    }
                }

                // Resolve character names via universe names
                List<Integer> charIds = membersResp.data().stream()
                        .map(com.sampleapp.esi.dto.FleetMember::characterId)
                        .toList();
                Map<Integer, String> charNames = new HashMap<>();
                if (!charIds.isEmpty()) {
                    try {
                        var namesResp = esiClient.universe.getNames(charIds).join();
                        if (namesResp.isSuccess() && namesResp.data() != null) {
                            for (var name : namesResp.data()) {
                                charNames.put(name.id(), name.name());
                            }
                        }
                    } catch (Exception e) {
                        log.warn("Failed to resolve fleet member names", e);
                    }
                }

                return membersResp.data().stream()
                        .map(m -> new FleetMemberInfo(
                                m.characterId(),
                                charNames.getOrDefault(m.characterId(), "Character #" + m.characterId()),
                                "", // ship name not available from ESI fleet members
                                "Ship Type #" + m.shipTypeId(),
                                "System #" + m.solarSystemId(),
                                m.role() != null ? m.role() : "--",
                                squadNames.getOrDefault(m.squadId(), "Squad #" + m.squadId()),
                                wingNames.getOrDefault(m.wingId(), "Wing #" + m.wingId())
                        ))
                        .toList();
            } catch (Exception e) {
                log.error("Failed to load fleet members for character {}", characterId, e);
                return List.of();
            }
        });
    }

