    // ================================================================

    @Override
    public CompletableFuture<List<FleetMemberInfo>> getFleetMembers(int characterId) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getFleetMembers for character {}", characterId);
            try {
                String token = tokenManager.getValidToken(characterId).join();
                // First get the character's fleet ID
                var fleetInfoResp = esiClient.fleets.getCharacterFleet(characterId, token).join();
                if (!fleetInfoResp.isSuccess() || fleetInfoResp.data() == null) {
                    return List.<FleetMemberInfo>of();
                }
                long fleetId = fleetInfoResp.data().fleetId();

                // Get fleet members
                var membersResp = esiClient.fleets.getFleetMembers(fleetId, token).join();
                if (!membersResp.isSuccess() || membersResp.data() == null) {
                    return List.<FleetMemberInfo>of();
                }

                // Get fleet wings for wing/squad names
                var wingsResp = esiClient.fleets.getFleetWings(fleetId, token).join();
                Map<Long, String> wingNames = new HashMap<>();
                Map<Long, String> squadNames = new HashMap<>();
                if (wingsResp.isSuccess() && wingsResp.data() != null) {
                    for (var wing : wingsResp.data()) {
                        wingNames.put(wing.id(), wing.name());
                        if (wing.squads() != null) {
                            for (var squad : wing.squads()) {
                                squadNames.put(squad.id(), squad.name());
                            }
                        }
                    }
                }

                // Resolve character names via universe names
                List<Integer> charIds = membersResp.data().stream()
                        .map(com.sampleapp.esi.dto.FleetMember::characterId)
                        .toList();
                Map<Integer, String> charNames = new HashMap<>();
                if (!charIds.isEmpty()) {
                    try {
                        var namesResp = esiClient.universe.getNames(charIds).join();
                        if (namesResp.isSuccess() && namesResp.data() != null) {
                            for (var name : namesResp.data()) {
                                charNames.put(name.id(), name.name());
                            }
                        }
                    } catch (Exception e) {
                        log.warn("Failed to resolve fleet member names", e);
                    }
                }

                return membersResp.data().stream()
                        .map(m -> new FleetMemberInfo(
                                m.characterId(),
                                charNames.getOrDefault(m.characterId(), "Character #" + m.characterId()),
                                "", // ship name not available from ESI fleet members
                                "Ship Type #" + m.shipTypeId(),
                                "System #" + m.solarSystemId(),
                                m.role() != null ? m.role() : "--",
                                squadNames.getOrDefault(m.squadId(), "Squad #" + m.squadId()),
                                wingNames.getOrDefault(m.wingId(), "Wing #" + m.wingId())
                        ))
                        .toList();
            } catch (Exception e) {
                log.error("Failed to load fleet members for character {}", characterId, e);
                return List.of();
            }
        });
    }

    // ================================================================
    // Universe
    // ================================================================

    @Override
    public CompletableFuture<List<SystemSecurity>> getSystemsInRegion(String regionName) {
        return CompletableFuture.supplyAsync(() -> {
            log.debug("getSystemsInRegion for region '{}'", regionName);
            try {
                // Map region name to ID
                int regionId = switch (regionName) {
                    case "The Forge" -> 10000002;
                    case "Domain" -> 10000043;
                    case "Sinq Laison" -> 10000032;
                    case "Metropolis" -> 10000042;
                    case "Heimatar" -> 10000030;
                    case "Essence" -> 10000064;
                    case "The Citadel" -> 10000033;
                    case "Lonetrek" -> 10000016;
                    case "Black Rise" -> 10000069;
                    case "Placid" -> 10000048;
                    case "Devoid" -> 10000036;
                    case "Tash-Murkon" -> 10000020;
                    default -> 0;
                };
                if (regionId == 0) return List.<SystemSecurity>of();

                return getWellKnownSystemsForRegion(regionId);
            } catch (Exception e) {
                log.error("Failed to get systems for region '{}'", regionName, e);
                return List.of();
            }
        });
    }

    private List<SystemSecurity> getWellKnownSystemsForRegion(int regionId) {
        // Well-known trade hub systems per region
        return switch (regionId) {
            case 10000002 -> List.of( // The Forge
                    new SystemSecurity(30000142, 0.9, "B"), // Jita
                    new SystemSecurity(30000144, 0.9, "B"), // Perimeter
                    new SystemSecurity(30000139, 0.8, "B"), // Maurasi
                    new SystemSecurity(30000143, 1.0, "A"), // Niyabainen
                    new SystemSecurity(30000148, 0.7, "B")  // Sobaseki
            );
            case 10000043 -> List.of( // Domain
                    new SystemSecurity(30002187, 1.0, "A"), // Amarr
                    new SystemSecurity(30002053, 0.7, "B"), // Sarum Prime
                    new SystemSecurity(30002068, 0.8, "B")  // Halaima
            );
            case 10000032 -> List.of( // Sinq Laison
                    new SystemSecurity(30002659, 0.9, "B"), // Dodixie
                    new SystemSecurity(30002661, 0.8, "B")  // Botane
            );
            case 10000042 -> List.of( // Metropolis
                    new SystemSecurity(30002510, 0.9, "B")  // Hek
            );
            case 10000030 -> List.of( // Heimatar
                    new SystemSecurity(30002510, 0.9, "B"), // Rens
                    new SystemSecurity(30002526, 1.0, "A")  // Frarn
            );
            default -> List.of();
        };
    }

    // ================================================================
    // Market Group Tree
    // ================================================================

    @Override
    public CompletableFuture<List<MarketGroupInfo>> getRootMarketGroups() {
        return CompletableFuture.supplyAsync(() -> {
            return marketGroupRepo.findByParent(null).stream()
                    .map(r -> new MarketGroupInfo(r.marketGroupId(), r.name(), r.hasTypes()))
                    .toList();
        });
    }

    @Override
    public CompletableFuture<List<MarketGroupInfo>> getChildMarketGroups(int parentGroupId) {
        return CompletableFuture.supplyAsync(() -> {
            return marketGroupRepo.findByParent(parentGroupId).stream()
                    .map(r -> new MarketGroupInfo(r.marketGroupId(), r.name(), r.hasTypes()))
                    .toList();
        });
    }

    @Override
    public CompletableFuture<List<MarketGroupItem>> getMarketGroupItems(int marketGroupId) {
        return CompletableFuture.supplyAsync(() -> {
            return typeCacheRepo.findByMarketGroupId(marketGroupId).stream()
                    .map(r -> new MarketGroupItem(r.typeId(), r.name()))
                    .toList();
        });
    }

    // ================================================================
    // Name Resolution
    // ================================================================

    @Override
    public CompletableFuture<String> resolveTypeName(int typeId) {
        return CompletableFuture.supplyAsync(() -> {
            return typeCacheRepo.findNameById(typeId).orElse("Unknown Type");
        });
    }

    @Override
    public CompletableFuture<String> resolveLocationName(long locationId) {
        // Check cache first
        String cached = locationNameCache.get(locationId);
        if (cached != null) return CompletableFuture.completedFuture(cached);

        return CompletableFuture.supplyAsync(() -> {
            String name = resolveLocationNameSync(locationId);
            locationNameCache.put(locationId, name);
            return name;
        });
    }

    private String resolveLocationNameSync(long locationId) {
        if (locationId <= 0) return "Unknown Location";

        // Solar system IDs: 30,000,000 - 33,000,000
        if (locationId >= 30_000_000 && locationId < 33_000_000) {
            // Try SDE first (fast, no network)
            try (var conn = dbManager.getConnection();
                 var ps = conn.prepareStatement("SELECT Name FROM SdeSolarSystems WHERE SystemId = ?")) {
                ps.setInt(1, (int) locationId);
                var rs = ps.executeQuery();
                if (rs.next()) {
                    String name = rs.getString(1);
                    if (name != null) return name;
                }
            } catch (Exception e) {
                log.debug("SDE solar system lookup failed for {}, falling back to ESI", locationId);
            }
            // Fall back to ESI
            try {
                var resp = esiClient.universe.getSystem((int) locationId).join();
                if (resp.isSuccess() && resp.data() != null) {
                    return resp.data().name();
                }
            } catch (Exception e) {
                log.debug("Failed to resolve system name for {}", locationId, e);
            }
        }

        // NPC station IDs: 60,000,000 - 64,000,000
        if (locationId >= 60_000_000 && locationId < 64_000_000) {
            // Try SDE first (fast, no network)
            try (var conn = dbManager.getConnection();
                 var ps = conn.prepareStatement("SELECT StationName FROM SdeStationNames WHERE StationId = ?")) {
                ps.setLong(1, locationId);
                var rs = ps.executeQuery();
                if (rs.next()) {
                    String name = rs.getString(1);
                    if (name != null) return name;
                }
            } catch (Exception e) {
                log.debug("SDE station name lookup failed for {}, falling back to ESI", locationId);
            }
            // Fall back to ESI
            try {
                var resp = esiClient.universe.getStation((int) locationId).join();
                if (resp.isSuccess() && resp.data() != null) {
                    return resp.data().name();
                }
            } catch (Exception e) {
                log.debug("Failed to resolve station name for {}", locationId, e);
            }
        }

        // Structures: >= 64,000,000 (Upwell structures, requires auth)
        if (locationId >= 64_000_000) {
            // Try to resolve via any available character token
            try {
                var characters = characterRepo.findAll();
                for (var character : characters) {
                    try {
                        String token = tokenManager.getValidToken(character.characterId()).join();
                        var resp = esiClient.universe.getStructure(locationId, token).join();
                        if (resp.isSuccess() && resp.data() != null) {
                            return resp.data().name();
                        }
                    } catch (Exception e) {
                        // This character may not have access, try next
                        continue;
                    }
                }
            } catch (Exception e) {
                log.debug("Failed to resolve structure name for {}", locationId, e);
            }
            // Fall back: try to find the solar system from assets and show "Structure in <system>"
            return "Structure " + locationId;
        }

        // Try universe names API as a fallback for other ID ranges
        if (locationId > 0 && locationId <= Integer.MAX_VALUE) {
            try {
                var resp = esiClient.universe.getNames(List.of((int) locationId)).join();
                if (resp.isSuccess() && resp.data() != null && !resp.data().isEmpty()) {
                    return resp.data().get(0).name();
                }
            } catch (Exception e) {
                log.debug("Failed to resolve name via universe names for {}", locationId, e);
            }
        }

        return "Location " + locationId;
    }

    @Override
    public CompletableFuture<String> resolveSystemName(int systemId) {
        return CompletableFuture.supplyAsync(() -> {
            // Try SDE first (fast, no network)
            try (var conn = dbManager.getConnection();
                 var ps = conn.prepareStatement("SELECT Name FROM SdeSolarSystems WHERE SystemId = ?")) {
                ps.setInt(1, systemId);
                var rs = ps.executeQuery();
                if (rs.next()) {
                    String name = rs.getString(1);
                    if (name != null) return name;
                }
            } catch (Exception e) {
                log.debug("SDE solar system lookup failed for {}, falling back to ESI", systemId);
            }
            // Fall back to ESI
            try {
                var resp = esiClient.universe.getSystem(systemId).join();
                if (resp.isSuccess() && resp.data() != null) {
                    return resp.data().name();
                }
            } catch (Exception e) {
                log.warn("Failed to resolve system name for {}", systemId, e);
            }
            return "System " + systemId;
        });
    }

    @Override
    public CompletableFuture<String> resolveCorporationName(int corporationId) {
        return CompletableFuture.supplyAsync(() -> {
            try {
                var resp = esiClient.corporations.getCorporation(corporationId).join();
                if (resp.isSuccess() && resp.data() != null) {
                    return resp.data().name();
                }
            } catch (Exception e) {
                log.warn("Failed to resolve corporation name for {}", corporationId, e);
            }
            return "Corporation #" + corporationId;
        });
    }
}

