/**
 * Automatically fetch all pages of a paginated endpoint and merge results.
 * Uses a semaphore to limit concurrent requests and avoid HTTP/2 stream exhaustion.
 */
public <T> CompletableFuture<List<T>> getAllPages(String path, TypeReference<List<T>> type, String token) {
    return getAllPages(path, type, token, null);
}

/**
 * Automatically fetch all pages with a progress callback.
 * The callback receives (completedPages, totalPages) after each page completes.
 */
public <T> CompletableFuture<List<T>> getAllPages(String path, TypeReference<List<T>> type, String token,
                                                  BiConsumer<Integer, Integer> progressCallback) {
    String separator = path.contains("?") ? "&" : "?";
    String firstPagePath = path + separator + "page=1";

    return get(firstPagePath, type, token).thenCompose(firstResponse -> {
        if (!firstResponse.isSuccess()) {
            return CompletableFuture.completedFuture(
                    firstResponse.data() != null ? firstResponse.data() : List.of());
        }

        int totalPages = firstResponse.pages();
        List<T> result = new ArrayList<>(firstResponse.data() != null ? firstResponse.data() : List.of());

        if (totalPages <= 1) {
            if (progressCallback != null) progressCallback.accept(1, 1);
            return CompletableFuture.completedFuture(result);
        }

        if (progressCallback != null) progressCallback.accept(1, totalPages);

        LOG.info("Fetching " + (totalPages - 1) + " additional pages for " + path +
                " (max " + MAX_CONCURRENT_REQUESTS + " concurrent)");

        // Fetch remaining pages with concurrency limiting via semaphore
        final AtomicInteger completedPages = new AtomicInteger(1);
        return CompletableFuture.supplyAsync(() -> {
            @SuppressWarnings("unchecked")
            CompletableFuture<EsiResponse<List<T>>>[] pageFutures = new CompletableFuture[totalPages - 1];

            for (int page = 2; page <= totalPages; page++) {
                String pagePath = path + separator + "page=" + page;
                pageFutures[page - 2] = CompletableFuture.supplyAsync(() -> {
                    try {
                        concurrencyLimiter.acquire();
                    } catch (InterruptedException e) {
                        Thread.currentThread().interrupt();
                        throw new RuntimeException("Interrupted waiting for concurrency slot", e);
                    }
                    return pagePath;
                }).thenCompose(p -> get(p, type, token)
                        .whenComplete((resp, ex) -> {
                            concurrencyLimiter.release();
                            if (progressCallback != null) {
                                progressCallback.accept(completedPages.incrementAndGet(), totalPages);
                            }
                        }));
            }

            CompletableFuture.allOf(pageFutures).join();

            for (CompletableFuture<EsiResponse<List<T>>> pf : pageFutures) {
                EsiResponse<List<T>> pr = pf.join();
                if (pr.isSuccess() && pr.data() != null) {
                    result.addAll(pr.data());
                }
            }
            return result;
        });
    });

