                        try {
                            concurrencyLimiter.acquire();
                        } catch (InterruptedException e) {
                            Thread.currentThread().interrupt();
                            throw new RuntimeException("Interrupted waiting for concurrency slot", e);
                        }
                        return pagePath;
                    }).thenCompose(p -> get(p, type, token)
                            .whenComplete((resp, ex) -> {
                                concurrencyLimiter.release();
                                if (progressCallback != null) {
                                    progressCallback.accept(completedPages.incrementAndGet(), totalPages);
                                }
                            }));
