                    } catch (Exception e) {
                        LOG.log(Level.WARNING, "Failed to parse ESI response for " + request.uri(), e);
                        return CompletableFuture.failedFuture(e);
                    }
                });
    }

    private <T> EsiResponse<T> buildEsiResponse(HttpResponse<String> response, T data) {
        int pages = response.headers().firstValue("X-Pages")
                .map(v -> {
