package com.sampleapp.esi;

import com.sampleapp.esi.api.*;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.DeserializationFeature;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.SerializationFeature;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import jakarta.inject.Singleton;

import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.time.LocalDateTime;
import java.time.ZonedDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.CompletableFuture;
import java.util.function.BiConsumer;
import java.util.logging.Level;
import java.util.logging.Logger;

/**
 * Main facade for accessing the EVE Swagger Interface (ESI) API.
 * <p>
 * Provides typed sub-clients for each API area, automatic pagination,
 * rate limiting, retry with exponential backoff, and ETag-based caching support.
 */
@Singleton
public class EsiClient {

    private static final Logger LOG = Logger.getLogger(EsiClient.class.getName());

    public static final String BASE_URL = "https://esi.evetech.net";
    private static final String USER_AGENT = "SampleApp/2.1.245 (Redacted User)";
    private static final int MAX_RETRIES = 3;
    private static final Duration CONNECT_TIMEOUT = Duration.ofSeconds(10);
    private static final Duration REQUEST_TIMEOUT = Duration.ofSeconds(30);
    /** Max concurrent HTTP requests to prevent "too many concurrent streams" on HTTP/2. */
    private static final int MAX_CONCURRENT_REQUESTS = 20;

    private final HttpClient httpClient;
    private final ObjectMapper objectMapper;
    private final RateLimiter rateLimiter;
    private final TokenManager tokenManager;
    private final Semaphore concurrencyLimiter = new Semaphore(MAX_CONCURRENT_REQUESTS);

    // API sub-clients
    public final CharacterApi characters;
    public final CorporationApi corporations;
    public final AssetsApi assets;
    public final MarketApi market;
    public final UniverseApi universe;
    public final WalletApi wallet;
    public final ContractsApi contracts;
    public final IndustryApi industry;
    public final SkillsApi skills;
    public final LoyaltyApi loyalty;
    public final FleetsApi fleets;
    public final SearchApi search;
    public final RoutesApi routes;
    public final UserInterfaceApi ui;
    public final ImageApi images;

    public EsiClient() {
        this(new TokenManager());
    }

    public EsiClient(TokenManager tokenManager) {
        this.httpClient = HttpClient.newBuilder()
                .connectTimeout(CONNECT_TIMEOUT)
                .followRedirects(HttpClient.Redirect.NORMAL)
                .build();

        this.objectMapper = new ObjectMapper()
                .registerModule(new JavaTimeModule())
                .configure(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES, false)
                .configure(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS, false);

        this.rateLimiter = new RateLimiter();
        this.tokenManager = tokenManager;

        this.characters = new CharacterApi(this);
        this.corporations = new CorporationApi(this);
        this.assets = new AssetsApi(this);
        this.market = new MarketApi(this);
        this.universe = new UniverseApi(this);
        this.wallet = new WalletApi(this);
        this.contracts = new ContractsApi(this);
        this.industry = new IndustryApi(this);
        this.skills = new SkillsApi(this);
        this.loyalty = new LoyaltyApi(this);
        this.fleets = new FleetsApi(this);
        this.search = new SearchApi(this);
        this.routes = new RoutesApi(this);
        this.ui = new UserInterfaceApi(this);
        this.images = new ImageApi();
    }

    // ---- Public HTTP methods ----

    public <T> CompletableFuture<EsiResponse<T>> get(String path, TypeReference<T> type, String token) {
        return get(path, type, token, null);
    }

    public <T> CompletableFuture<EsiResponse<T>> get(String path, TypeReference<T> type, String token, String etag) {
        return rateLimiter.acquire().thenCompose(v -> {
            HttpRequest.Builder builder = HttpRequest.newBuilder()
                    .uri(URI.create(BASE_URL + path))
                    .header("User-Agent", USER_AGENT)
                    .header("Accept", "application/json")
                    .timeout(REQUEST_TIMEOUT)
                    .GET();

            if (token != null && !token.isBlank()) {
                builder.header("Authorization", "Bearer " + token);
            }
            if (etag != null && !etag.isBlank()) {
                builder.header("If-None-Match", etag);
            }

            return executeWithRetry(builder.build(), type, 0);
        });
    }

    public <T> CompletableFuture<EsiResponse<T>> post(String path, Object body, TypeReference<T> type, String token) {
        return rateLimiter.acquire().thenCompose(v -> {
            try {
                String jsonBody = objectMapper.writeValueAsString(body);
                HttpRequest.Builder builder = HttpRequest.newBuilder()
                        .uri(URI.create(BASE_URL + path))
                        .header("User-Agent", USER_AGENT)
                        .header("Accept", "application/json")
                        .header("Content-Type", "application/json")
                        .timeout(REQUEST_TIMEOUT)
                        .POST(HttpRequest.BodyPublishers.ofString(jsonBody));

                if (token != null && !token.isBlank()) {
                    builder.header("Authorization", "Bearer " + token);
                }

                return executeWithRetry(builder.build(), type, 0);
            } catch (Exception e) {
                return CompletableFuture.failedFuture(e);
            }
        });
    }

    /**
     * POST with empty body (used by UI endpoints).
     */
    public CompletableFuture<EsiResponse<Void>> postEmpty(String path, String token) {
        return rateLimiter.acquire().thenCompose(v -> {
            HttpRequest.Builder builder = HttpRequest.newBuilder()
                    .uri(URI.create(BASE_URL + path))
                    .header("User-Agent", USER_AGENT)
                    .header("Accept", "application/json")
                    .timeout(REQUEST_TIMEOUT)
                    .POST(HttpRequest.BodyPublishers.noBody());

            if (token != null && !token.isBlank()) {
                builder.header("Authorization", "Bearer " + token);
            }

            return httpClient.sendAsync(builder.build(), HttpResponse.BodyHandlers.ofString())
                    .thenApply(response -> {
                        rateLimiter.updateFromResponse(response);
                        return buildEsiResponse(response, null);
                    });
        });
    }

    /**
     * Automatically fetch all pages of a paginated endpoint and merge results.
     * Uses a semaphore to limit concurrent requests and avoid HTTP/2 stream exhaustion.
     */
    public <T> CompletableFuture<List<T>> getAllPages(String path, TypeReference<List<T>> type, String token) {
        return getAllPages(path, type, token, null);
    }

    /**
     * Automatically fetch all pages with a progress callback.
     * The callback receives (completedPages, totalPages) after each page completes.
     * <p>
     * Uses batched fetching: fires up to {@link #MAX_CONCURRENT_REQUESTS} pages at a time,
     * waits for the batch to complete, then fires the next batch. This avoids both
     * HTTP/2 stream exhaustion and ForkJoinPool thread starvation.
     */
    public <T> CompletableFuture<List<T>> getAllPages(String path, TypeReference<List<T>> type, String token,
                                                      BiConsumer<Integer, Integer> progressCallback) {
        String separator = path.contains("?") ? "&" : "?";
        String firstPagePath = path + separator + "page=1";

        return get(firstPagePath, type, token).thenCompose(firstResponse -> {
            if (!firstResponse.isSuccess()) {
                return CompletableFuture.completedFuture(
                        firstResponse.data() != null ? firstResponse.data() : List.of());
            }

            int totalPages = firstResponse.pages();
            List<T> result = new ArrayList<>(firstResponse.data() != null ? firstResponse.data() : List.of());

            if (totalPages <= 1) {
                if (progressCallback != null) progressCallback.accept(1, 1);
                return CompletableFuture.completedFuture(result);
            }

            if (progressCallback != null) progressCallback.accept(1, totalPages);

            LOG.info("Fetching " + (totalPages - 1) + " additional pages for " + path +
                    " in batches of " + MAX_CONCURRENT_REQUESTS);

            // Use a virtual thread to run the batched fetch loop without blocking the caller
            CompletableFuture<List<T>> batchedResult = new CompletableFuture<>();
            Thread.ofVirtual().name("esi-paged-fetch").start(() -> {
                try {
                    int completed = 1;
                    for (int batchStart = 2; batchStart <= totalPages; batchStart += MAX_CONCURRENT_REQUESTS) {
                        int batchEnd = Math.min(batchStart + MAX_CONCURRENT_REQUESTS - 1, totalPages);
                        int batchSize = batchEnd - batchStart + 1;

                        @SuppressWarnings("unchecked")
                        CompletableFuture<EsiResponse<List<T>>>[] batch = new CompletableFuture[batchSize];
                        for (int page = batchStart; page <= batchEnd; page++) {
                            String pagePath = path + separator + "page=" + page;
                            batch[page - batchStart] = get(pagePath, type, token);
                        }

                        // Wait for entire batch to complete before starting next
                        CompletableFuture.allOf(batch).join();

                        for (CompletableFuture<EsiResponse<List<T>>> pf : batch) {
                            EsiResponse<List<T>> pr = pf.join();
                            if (pr.isSuccess() && pr.data() != null) {
                                result.addAll(pr.data());
                            }
                            completed++;
                            if (progressCallback != null) {
                                progressCallback.accept(completed, totalPages);
                            }
                        }
                    }
                    batchedResult.complete(result);
                } catch (Exception e) {
                    batchedResult.completeExceptionally(e);
                }
            });
            return batchedResult;
        });
    }

    // ---- Accessors ----

    public ObjectMapper getObjectMapper() {
        return objectMapper;
    }

    public TokenManager getTokenManager() {
        return tokenManager;
    }

    public RateLimiter getRateLimiter() {
        return rateLimiter;
    }

    public HttpClient getHttpClient() {
        return httpClient;
    }

    public EveSsoAuth createSsoAuth() {
        return new EveSsoAuth(httpClient, objectMapper, tokenManager);
    }

    // ---- Private helpers ----

    private <T> CompletableFuture<EsiResponse<T>> executeWithRetry(
            HttpRequest request, TypeReference<T> type, int attempt) {

        return httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
                .thenCompose(response -> {
                    rateLimiter.updateFromResponse(response);
                    int status = response.statusCode();

                    // Retry on gateway errors
                    if ((status == 502 || status == 503 || status == 504) && attempt < MAX_RETRIES) {
                        long delayMs = (long) Math.pow(2, attempt) * 1000;
                        LOG.warning("ESI returned " + status + " for " + request.uri() +
                                ", retry " + (attempt + 1) + "/" + MAX_RETRIES + " in " + delayMs + "ms");
                        CompletableFuture<EsiResponse<T>> delayed = new CompletableFuture<>();
                        CompletableFuture.delayedExecutor(delayMs, java.util.concurrent.TimeUnit.MILLISECONDS)
                                .execute(() ->
                                        executeWithRetry(request, type, attempt + 1)
                                                .thenAccept(delayed::complete)
                                                .exceptionally(ex -> {
                                                    delayed.completeExceptionally(ex);
                                                    return null;
                                                })
                                );
                        return delayed;
                    }

                    try {
                        T data = null;
                        if (status != 304 && response.body() != null && !response.body().isBlank()) {
                            data = objectMapper.readValue(response.body(), type);
                        }
                        return CompletableFuture.completedFuture(buildEsiResponse(response, data));
                    } catch (Exception e) {
                        LOG.log(Level.WARNING, "Failed to parse ESI response for " + request.uri(), e);
                        return CompletableFuture.failedFuture(e);
                    }
                });
    }

    private <T> EsiResponse<T> buildEsiResponse(HttpResponse<String> response, T data) {
        int pages = response.headers().firstValue("X-Pages")
                .map(v -> {
                    try { return Integer.parseInt(v); } catch (NumberFormatException e) { return 1; }
                }).orElse(1);

        String etag = response.headers().firstValue("ETag").orElse(null);

        int errorRemain = response.headers().firstValue("X-Esi-Error-Limit-Remain")
                .map(v -> {
                    try { return Integer.parseInt(v); } catch (NumberFormatException e) { return 100; }
                }).orElse(100);

        int errorReset = response.headers().firstValue("X-Esi-Error-Limit-Reset")
                .map(v -> {
                    try { return Integer.parseInt(v); } catch (NumberFormatException e) { return 60; }
                }).orElse(60);

        LocalDateTime expires = response.headers().firstValue("Expires")
                .map(v -> {
                    try {
                        return ZonedDateTime.parse(v, DateTimeFormatter.RFC_1123_DATE_TIME).toLocalDateTime();
                    } catch (Exception e) {
                        return LocalDateTime.now();
                    }
                }).orElse(LocalDateTime.now());

        return new EsiResponse<>(data, response.statusCode(), pages, etag, errorRemain, errorReset, expires);
    }
}
